-- Poems batch 481
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-5','送僧入五泄','貫休','唐','御定全唐诗','yuding','','[]','五泄江山寺，禪林境最奇。九年吃菜粥，此事少人知。',48,'御定全唐詩/json/833.json','["五泄江山寺，禪林境最奇。九年吃菜粥，此事少人知。", "山響僧擔谷，林香豹乳兒。伊余頭已白，不去更何之。"]'),
('yuding-6','題令宣和尚院','貫休','唐','御定全唐诗','yuding','','[]','軒窗領嵐翠，師得世情忘。惟愛談諸祖，曾經宿大荒。',48,'御定全唐詩/json/833.json','["軒窗領嵐翠，師得世情忘。惟愛談諸祖，曾經宿大荒。", "泉聲淹臥榻，雲片犯爐香。寄語題門者，看經在上方。"]'),
('yuding-7','寄四明閭丘道士二首','貫休','唐','御定全唐诗','yuding','','[]','淮海兵荒日，分飛直至今。知擔諸子出，卻入四明深。',96,'御定全唐詩/json/833.json','["淮海兵荒日，分飛直至今。知擔諸子出，卻入四明深。", "衣必編仙草，僧應共栗林。秋風溪上路，應得一相尋。", "三千功未了，大道本無程。好共禪師好，常將藥犬行。", "石門紅蘚剝，柘塢白雲生。莫認無名是，無名已是名。"]'),
('yuding-8','經士馬中作','貫休','唐','御定全唐诗','yuding','','[]','偷兒成大寇，處處起煙塵。黃葉滿空宅，青山見俗人。',48,'御定全唐詩/json/833.json','["偷兒成大寇，處處起煙塵。黃葉滿空宅，青山見俗人。", "妖星芒刺越，鬼哭勢連秦。惆悵還惆悵，茫茫江海濱。"]'),
('yuding-9','士馬後見赤松舒道士','貫休','唐','御定全唐诗','yuding','','[]','滿眼盡瘡痍，相逢相對悲。亂階猶未已，一柱若為支。',48,'御定全唐詩/json/833.json','["滿眼盡瘡痍，相逢相對悲。亂階猶未已，一柱若為支。", "堰茗蒸紅棗，看花似好時。不知今日後，吾道竟何之。"]'),
('yuding-10','題方公院寄夏侯明府','貫休','唐','御定全唐诗','yuding','','[]','銀地有餘光，方公道益芳。誰分修藏力，頂有剃頭霜。',48,'御定全唐詩/json/833.json','["銀地有餘光，方公道益芳。誰分修藏力，頂有剃頭霜。", "經勘松風燥，簷垂塢茗香。終須結西社，此縣似柴桑。"]'),
('yuding-11','與劉象正字','貫休','唐','御定全唐诗','yuding','','[]','獨居三島上，花竹映柴關。道廣群仙惜，名成萬事閑。',48,'御定全唐詩/json/833.json','["獨居三島上，花竹映柴關。道廣群仙惜，名成萬事閑。", "病多唯縱酒，靜極不思山。唯有逍遙子，時時自往還。"]'),
('yuding-12','懷智體道人','貫休','唐','御定全唐诗','yuding','','[]','棲碧思吾友，庭鶯百囀時。唯應一處住，方得不相思。',48,'御定全唐詩/json/833.json','["棲碧思吾友，庭鶯百囀時。唯應一處住，方得不相思。", "雲水淹門閫，春雷在樹枝。平生無限事，不獨白雲知。"]'),
('yuding-13','贈晦公禪人','貫休','唐','御定全唐诗','yuding','','[]','流陽為役者，相訪葉紛紛。有句雖如我，無心未似君。',48,'御定全唐詩/json/833.json','["流陽為役者，相訪葉紛紛。有句雖如我，無心未似君。", "構林青及竹，茆屋暖於雲。何日相將去，千山麋鹿群。"]'),
('yuding-14','寄靜林別墅胡進士兄弟','貫休','唐','御定全唐诗','yuding','','[]','見說山居好，書樓被翠侵。燒熛汀島境，月色弟兄吟。',48,'御定全唐詩/json/833.json','["見說山居好，書樓被翠侵。燒熛汀島境，月色弟兄吟。", "犬吠黃椑落，牛歸紅樹深。仍聞多白菌，應許一相尋。"]'),
('yuding-15','懷赤松故舒道士','貫休','唐','御定全唐诗','yuding','','[]','可惜複可惜，如今何所之。信來堪大慟，餘複用生為。',48,'御定全唐詩/json/833.json','["可惜複可惜，如今何所之。信來堪大慟，餘複用生為。", "亂世今交鬥，玄宮玉柱隳。春風五陵道，回首不勝悲。"]'),
('yuding-16','偶作','貫休','唐','御定全唐诗','yuding','','[]','無端為五字，字字鬢星星。只覺人情薄，空餘鶴眼青。',48,'御定全唐詩/json/833.json','["無端為五字，字字鬢星星。只覺人情薄，空餘鶴眼青。", "砌莎藏墜果，窗雪浸殘經。只有歸山計，茫茫何所營。"]'),
('yuding-17','春日許征君見訪','貫休','唐','御定全唐诗','yuding','','[]','龍鍾多病後，日望遇升平。遠念穿嵩雪，前林囀早鶯。',48,'御定全唐詩/json/833.json','["龍鍾多病後，日望遇升平。遠念穿嵩雪，前林囀早鶯。", "廚香烹瓠葉，道友扣門聲。還似青溪上，微吟踏葉行。"]'),
('yuding-18','經先主廟作','貫休','唐','御定全唐诗','yuding','','[]','古廟積煙蘿，威靈及物多。因知曹孟德，爭奈此公何。',48,'御定全唐詩/json/833.json','["古廟積煙蘿，威靈及物多。因知曹孟德，爭奈此公何。", "樹古雷痕剝，碑荒篆畫訛。今朝冥禱祝，只望息干戈。"]'),
('yuding-19','寄中條道者','貫休','唐','御定全唐诗','yuding','','[]','柏梯杉影裏，頭白藥山孫。今古管不得，是非爭肯論。',48,'御定全唐詩/json/833.json','["柏梯杉影裏，頭白藥山孫。今古管不得，是非爭肯論。", "虎須懸瀑滴，禪衲帶苔痕。常恨龍鍾也，無因接話言。"]'),
('yuding-20','夏日晚望','貫休','唐','御定全唐诗','yuding','','[]','登臨聊一望，不覺意恞然。陶侃寒溪寺，如今何處邊。',48,'御定全唐詩/json/833.json','["登臨聊一望，不覺意恞然。陶侃寒溪寺，如今何處邊。", "汀沙生旱霧，山火照平川。終事東歸去，干戈滿許田。"]'),
('yuding-21','送僧歸山','貫休','唐','御定全唐诗','yuding','','[]','眼青禪帔赤，氣岸出塵埃。霞外終須去，人間作麼來。',48,'御定全唐詩/json/833.json','["眼青禪帔赤，氣岸出塵埃。霞外終須去，人間作麼來。", "崖香泉吐乳，塢燥燒□雷。他日終相覓，山門何處開。"]'),
('yuding-22','《覽皎然渠南鄉集》','貫休','唐','御定全唐诗','yuding','','[]','學力不相敵，清還仿佛同。高於寶月月，誰得射雕弓。',48,'御定全唐詩/json/833.json','["學力不相敵，清還仿佛同。高於寶月月，誰得射雕弓。", "至鑒封姚監，良工遇魯公。如斯深可羨，千古共清風。"]'),
('yuding-23','《覽姚合極玄集》','貫休','唐','御定全唐诗','yuding','','[]','至覽如日月，今時即古時。發如邊草白，誰念射聲□。',48,'御定全唐詩/json/833.json','["至覽如日月，今時即古時。發如邊草白，誰念射聲□。", "好鳥挨花落，清風出院遲。知音郭有道，始為一吟之。"]'),
('yuding-24','大駕西幸秋日聞雷','貫休','唐','御定全唐诗','yuding','','[]','軍書日日催，處處起塵埃。黎庶何由泰，鑾輿早晚回。',48,'御定全唐詩/json/833.json','["軍書日日催，處處起塵埃。黎庶何由泰，鑾輿早晚回。", "夏租方減食，秋日更聞雷。莫道蒼蒼意，蒼蒼眼甚開。"]'),
('yuding-25','詩','貫休','唐','御定全唐诗','yuding','','[]','經天緯地物，動必計仙才。幾處覓不得，有時還自來。',48,'御定全唐詩/json/833.json','["經天緯地物，動必計仙才。幾處覓不得，有時還自來。", "真風含素發，秋色入靈台。吟向霜蟾下，終須神鬼哀。"]'),
('yuding-26','秋末江上望','貫休','唐','御定全唐诗','yuding','','[]','莽莽古江濱，紛紛墜葉頻。煙霞誰是主，丘隴自傷神。',48,'御定全唐詩/json/833.json','["莽莽古江濱，紛紛墜葉頻。煙霞誰是主，丘隴自傷神。", "吞併寧唯漢，淒涼莫問陳。盡隨流水去，寂莫野花春。"]'),
('yuding-27','乞食僧','貫休','唐','御定全唐诗','yuding','','[]','擎缽貌清羸，天寒出寺遲。朱門當大路，風雪立多時。',48,'御定全唐詩/json/833.json','["擎缽貌清羸，天寒出寺遲。朱門當大路，風雪立多時。", "似月心常淨，如麻事不知。行人莫輕誚，古佛盡如斯。"]'),
('yuding-28','寒望九峰作','貫休','唐','御定全唐诗','yuding','','[]','九朵碧芙蕖，王維圖未圖。層層皆有瀑，一一合吾居。',48,'御定全唐詩/json/833.json','["九朵碧芙蕖，王維圖未圖。層層皆有瀑，一一合吾居。", "雨歇如爭出，霜嚴不例枯。世猶多事在，為爾久躊躇。"]'),
('yuding-29','薊北寒月作','貫休','唐','御定全唐诗','yuding','','[]','薊門寒到骨，戰磧雁相悲。古屋不勝雪，嚴風欲斷髭。',48,'御定全唐詩/json/833.json','["薊門寒到骨，戰磧雁相悲。古屋不勝雪，嚴風欲斷髭。", "清吟得冷句，遠念失佳期。寂寞誰相問，迢迢天一涯。"]'),
('yuding-30','新猿','貫休','唐','御定全唐诗','yuding','','[]','尋常看不見，花落樹多苔。忽向高枝發，又從何處來。',48,'御定全唐詩/json/833.json','["尋常看不見，花落樹多苔。忽向高枝發，又從何處來。", "風清聲更揭，月苦意彌哀。多少求名者，年年被爾催。"]'),
('yuding-31','懷南嶽隱士二首','貫休','唐','御定全唐诗','yuding','','[]','千峰映碧湘，真隱此中藏。餅不煮石吃，眉應似發長。',96,'御定全唐詩/json/833.json','["千峰映碧湘，真隱此中藏。餅不煮石吃，眉應似發長。", "風榸支酒甕，鶴虱落琴床。雖斅忘機者，斯人尚未忘。", "見說祝融峰，擎天勢似騰。藏千尋瀑布，出十八高僧。", "古路無人跡，新霞出石棱。終期將爾叟，一一月中登。"]'),
('yuding-32','追憶馮少常','貫休','唐','御定全唐诗','yuding','','[]','盛德方清貴，旋聞逐逝波。令人翻不會，積善合如何。',48,'御定全唐詩/json/833.json','["盛德方清貴，旋聞逐逝波。令人翻不會，積善合如何。", "直道登朝晚，分憂及物多。至今新定郡，猶詠袴襦歌。"]'),
('yuding-33','聞閔廷言周璉下第','貫休','唐','御定全唐诗','yuding','','[]','前榜年年見，高名日日聞。常因不平事，便欲見吾君。',48,'御定全唐詩/json/833.json','["前榜年年見，高名日日聞。常因不平事，便欲見吾君。", "兄弟居清島，園林生白雲。相思空悵望，庭葉赤紛紛。"]'),
('yuding-34','寄景地判官','貫休','唐','御定全唐诗','yuding','','[]','渚宮江上別，倏忽十餘年。舉世唯攻說，多君即不然。',48,'御定全唐詩/json/833.json','["渚宮江上別，倏忽十餘年。舉世唯攻說，多君即不然。", "浦珠為履重，園柳助詩玄。勉力酬知己，昌朝正急賢。"]'),
('yuding-35','讀賈區、賈島集','貫休','唐','御定全唐诗','yuding','','[]','區終不下島，島亦不多區。冷格俱無敵，貧根亦似愚。',48,'御定全唐詩/json/833.json','["區終不下島，島亦不多區。冷格俱無敵，貧根亦似愚。", "青雲終歎命，白閣久圍爐。今日成名者，還堪為爾籲。"]'),
('yuding-36','送衲僧之江西','貫休','唐','御定全唐诗','yuding','','[]','索索複索索，無憑卻有憑。過溪遭惡雨，乞食得幹菱。',48,'御定全唐詩/json/833.json','["索索複索索，無憑卻有憑。過溪遭惡雨，乞食得幹菱。", "只有山相伴，終無事可仍。如逢梅嶺旦，向道只寧馨。"]'),
('yuding-37','故林偶作','貫休','唐','御定全唐诗','yuding','','[]','朗吟無一事，孤坐瀔江濆。媚世非吾道，良圖有白雲。',48,'御定全唐詩/json/833.json','["朗吟無一事，孤坐瀔江濆。媚世非吾道，良圖有白雲。", "蠹魚開卷落，啄木隔花聞。唯寄壺中客，金丹許共分。"]'),
('yuding-38','寄棲白大師二首','貫休','唐','御定全唐诗','yuding','','[]','流浪江湖久，攀緣歲月闌。高名當世重，好句逼人寒。',96,'御定全唐詩/json/833.json','["流浪江湖久，攀緣歲月闌。高名當世重，好句逼人寒。", "月苦蟬聲嗄，鐘清柿葉幹。龍鍾千萬里，擬欲訪師難。", "蒼蒼龍闕晚，九陌雜香塵。方外無他事，僧中有近臣。", "青門玉露滴，紫閣錦霞新。莫話三峰去，澆風正蕩淳。"]'),
('yuding-39','送人之渤海','貫休','唐','御定全唐诗','yuding','','[]','國之東北角，有國每朝天。海力浸不盡，夷風常宛然。',48,'御定全唐詩/json/833.json','["國之東北角，有國每朝天。海力浸不盡，夷風常宛然。", "山藏羅刹宅，水雜巨鼇涎。好去吳鄉子，歸來莫來年。"]'),
('yuding-40','寄李道士','貫休','唐','御定全唐诗','yuding','','[]','常見高人說，猶來不偶然。致身同槁木，話道出忘詮。',48,'御定全唐詩/json/833.json','["常見高人說，猶來不偶然。致身同槁木，話道出忘詮。", "長嘯仙鐘外，眠楂海月邊。倘修陰姹姹，一望寄餘焉。"]'),
('yuding-41','秋送夏郢歸錢塘','貫休','唐','御定全唐诗','yuding','','[]','歸客指吳國，風帆幾日程。新詩陶雪字，玄發有霜莖。',48,'御定全唐詩/json/833.json','["歸客指吳國，風帆幾日程。新詩陶雪字，玄發有霜莖。", "微月生滄海，殘濤傍石城。從茲江島意，應續子陵名。"]'),
('yuding-42','送僧歸翠微','貫休','唐','御定全唐诗','yuding','','[]','只衲一個衲，翠微歸舊岑。不知何歲月，即得到師心。',48,'御定全唐詩/json/833.json','["只衲一個衲，翠微歸舊岑。不知何歲月，即得到師心。", "徑繞千峰細，庵開亂木深。倘然雲外老，他日亦相尋。"]'),
('yuding-43','經友生墳','貫休','唐','御定全唐诗','yuding','','[]','多君墳在此，令我過悲涼。可惜為人好，剛須被數將。',48,'御定全唐詩/json/833.json','["多君墳在此，令我過悲涼。可惜為人好，剛須被數將。", "白雲從塚出，秋草為誰荒。不覺頻回首，西風滿白楊。"]'),
('yuding-44','懷洛下盧縉雲','貫休','唐','御定全唐诗','yuding','','[]','一減三張價，幽居少室前。豈應貧似我，不得信經年。',48,'御定全唐詩/json/833.json','["一減三張價，幽居少室前。豈應貧似我，不得信經年。", "木落多詩槁，山枯見墨煙。何時深夜坐，共話草堂禪。"]'),
('yuding-45','送李鉶赴舉','貫休','唐','御定全唐诗','yuding','','[]','詩業務經綸，新皆意外新。因知登第榜，不著不平人。',48,'御定全唐詩/json/833.json','["詩業務經綸，新皆意外新。因知登第榜，不著不平人。", "句得孤舟月，心飛九陌塵。明年相賀日，應到曲江濱。"]'),
('yuding-46','寶禪師見訪','貫休','唐','御定全唐诗','yuding','','[]','山兄心似我，岸穀亦難交。不見還相憶，來唯添寂寥。',48,'御定全唐詩/json/833.json','["山兄心似我，岸穀亦難交。不見還相憶，來唯添寂寥。", "茶煙粘衲葉，雲水透蘅茆。因話流年事，斯須不可拋。"]'),
('yuding-47','觀棋','貫休','唐','御定全唐诗','yuding','','[]','逸格格難及，半先相遇稀。落花方滿地，一局到斜暉。',48,'御定全唐詩/json/833.json','["逸格格難及，半先相遇稀。落花方滿地，一局到斜暉。", "褚胤死不死，將軍飛已飛。今朝慚一行，無以造玄微。"]'),
('yuding-48','題一上人經閣','貫休','唐','御定全唐诗','yuding','','[]','鳥外何須去，衣如蘚亦從。但能無一事，即是住孤峰。',48,'御定全唐詩/json/833.json','["鳥外何須去，衣如蘚亦從。但能無一事，即是住孤峰。", "雨歇雲埋閣，月明霜灑松。師心多似我，所以訪師重。"]'),
('yuding-49','和毛學士舍人早春','貫休','唐','御定全唐诗','yuding','','[]','陋巷冬將盡，東風細雜籃。解牽窗夢遠，先是澗梅諳。',144,'御定全唐詩/json/833.json','["陋巷冬將盡，東風細雜籃。解牽窗夢遠，先是澗梅諳。", "茶癖金鐺快，松香玉露含。書齋山帚撅，盤饌藥花甘。", "雅得琴中妙，常挪臉似酣。雪消聞苦蟄，氣候似宜蠶。", "密勿須清甲，朝歸繞碧潭。丹心空拱北，新作繼周南。", "竹杖無斑點，紗巾不著簪。大朝名益重，後進力皆覃。", "至理雖亡一，臣時亦說三。不知門下客，誰上晏嬰驂。"]'),
('yuding-0','壽春進祝聖七首：千載降祥','貫休','唐','御定全唐诗','yuding','','[]','九天宮上聖，降世共昭回。萬匯須亭毓，群仙送下來。',48,'御定全唐詩/json/834.json','["九天宮上聖，降世共昭回。萬匯須亭毓，群仙送下來。", "承幹當否極，庶事盡康哉。只有羲軒比，其餘不可陪。"]'),
('yuding-1','壽春進祝聖七首：文有武備','貫休','唐','御定全唐诗','yuding','','[]','武宿與文星，常如掌上擎。孫吳機不動，周邵事多行。',48,'御定全唐詩/json/834.json','["武宿與文星，常如掌上擎。孫吳機不動，周邵事多行。", "旰食爐煙細，宵衣隙月明。還聞夔進曲，吹出泰階平。"]'),
('yuding-2','壽春進祝聖七首：從諫如流','貫休','唐','御定全唐诗','yuding','','[]','及溜龍鱗動，君臣道義深。萬年軒後鏡，一片漢高心。',48,'御定全唐詩/json/834.json','["及溜龍鱗動，君臣道義深。萬年軒後鏡，一片漢高心。", "北狄皆輸款，南夷盡貢琛。從茲千萬歲，枝葉玉森森。"]'),
('yuding-3','壽春進祝聖七首：搜揚草澤','貫休','唐','御定全唐诗','yuding','','[]','俟時兼待價，垂棘出塵埃。仄席三旌切，移山萬里來。',48,'御定全唐詩/json/834.json','["俟時兼待價，垂棘出塵埃。仄席三旌切，移山萬里來。", "煙霞衣上落，閶闔雪中開。壽酒今朝進，無非出世才。"]'),
('yuding-4','壽春進祝聖七首：守在四夷','貫休','唐','御定全唐诗','yuding','','[]','天將興大蜀，有道遂君臨。四塞同諸子，三邊共一心。',48,'御定全唐詩/json/834.json','["天將興大蜀，有道遂君臨。四塞同諸子，三邊共一心。", "闍婆香似雪，回鶻馬如林。曾讀前皇傳，巍巍冠古今。"]'),
('yuding-5','壽春進祝聖七首：大興三教','貫休','唐','御定全唐诗','yuding','','[]','曈曈懸佛日，天俁動雲韶。縫掖諸生集，麟洲羽客朝。',48,'御定全唐詩/json/834.json','["曈曈懸佛日，天俁動雲韶。縫掖諸生集，麟洲羽客朝。", "非煙生玉砌，禦柳吐金條。擊壤翁知否，吾皇即帝堯。"]'),
('yuding-6','壽春進祝聖七首：山呼萬歲','貫休','唐','御定全唐诗','yuding','','[]','聲教無為日，山呼萬歲聲。隆隆如穀響，合合似雷鳴。',48,'御定全唐詩/json/834.json','["聲教無為日，山呼萬歲聲。隆隆如穀響，合合似雷鳴。", "翠拔為天柱，根盤倚鳳城。恭唯千萬歲，歲歲致升平。"]'),
('yuding-7','早秋夜坐','貫休','唐','御定全唐诗','yuding','','[]','微涼砧滿城，林下石床平。發豈無端白，詩須出世清。',48,'御定全唐詩/json/834.json','["微涼砧滿城，林下石床平。發豈無端白，詩須出世清。", "鄰僧同樹影，砌月浸蛩聲。獨自更深坐，無人知此情。"]'),
('yuding-8','早起','貫休','唐','御定全唐诗','yuding','','[]','夜坐還早起，寂寥多病身。神清尋夢在，香極覺花新。',48,'御定全唐詩/json/834.json','["夜坐還早起，寂寥多病身。神清尋夢在，香極覺花新。", "樹露繁於雨，溪雲動似人。又知何處客，軋軋轉征輪。"]'),
('yuding-9','秋晚野步','貫休','唐','御定全唐诗','yuding','','[]','閒步不覺遠，蕭蕭木落初。詩情拋閫閾，江影動襟裾。',48,'御定全唐詩/json/834.json','["閒步不覺遠，蕭蕭木落初。詩情拋閫閾，江影動襟裾。", "閣北鴻行出，霞西雨腳疏。金峰秋更好，乞取又何如。"]'),
('yuding-10','晚望','貫休','唐','御定全唐诗','yuding','','[]','曠望危橋上，微吟落照前。煙霞濃浸海，川岳闊連天。',48,'御定全唐詩/json/834.json','["曠望危橋上，微吟落照前。煙霞濃浸海，川岳闊連天。", "白鳥格不俗，孤雲態可憐。終期將爾輩，歸去舊江邊。"]'),
('yuding-11','寄翰林陸學士','貫休','唐','御定全唐诗','yuding','','[]','顏冉商參甲，鸞凰密勿才。簾垂仙鳥下，吟次聖人來。',48,'御定全唐詩/json/834.json','["顏冉商參甲，鸞凰密勿才。簾垂仙鳥下，吟次聖人來。", "寶輦千官捧，宮花九色開。何時重一見，為我話蓬萊。"]'),
('yuding-12','贈造微禪師院','貫休','唐','御定全唐诗','yuding','','[]','薝蔔氣雍雍，門深聖澤重。七絲奔小蟹，五字逼雕龍。',48,'御定全唐詩/json/834.json','["薝蔔氣雍雍，門深聖澤重。七絲奔小蟹，五字逼雕龍。", "藥轉紅金鼎，茶開紫閣封。圭峰爭去得，卿相日憧憧。"]'),
('yuding-13','南海晚望','貫休','唐','御定全唐诗','yuding','','[]','海上聊一望，舶帆天際飛。狂蠻莫掛甲，聖主正垂衣。',48,'御定全唐詩/json/834.json','["海上聊一望，舶帆天際飛。狂蠻莫掛甲，聖主正垂衣。", "風惡巨魚出，山昏群獠歸。無人知此意，吟到月騰輝。"]'),
('yuding-14','寄廬山大願和尚','貫休','唐','御定全唐诗','yuding','','[]','石上桂成叢，師庵在桂中。皆雲習鑿齒，未可扣真風。',48,'御定全唐詩/json/834.json','["石上桂成叢，師庵在桂中。皆雲習鑿齒，未可扣真風。", "雪洗香爐碧，霞藏瀑布紅。何時甘露偈，一寄剡山東。"]'),
('yuding-15','懷薛尚書兼呈東陽王使君','貫休','唐','御定全唐诗','yuding','','[]','得力未得力，高吟夏又殘。二毛非自出，萬事到詩難。',48,'御定全唐詩/json/834.json','["得力未得力，高吟夏又殘。二毛非自出，萬事到詩難。", "蟬見木葉落，雷將雨氣寒。何妨槌琢後，更獻至公看。"]'),
('yuding-16','上馮使君水晶數珠','貫休','唐','御定全唐诗','yuding','','[]','泠泠瀑滴清，貫串有規程。將諷觀空偈，全勝照乘明。',48,'御定全唐詩/json/834.json','["泠泠瀑滴清，貫串有規程。將諷觀空偈，全勝照乘明。", "龍神多共惜，金玉比終輕。願在玄暉手，常資物外情。"]'),
('yuding-17','送明覺大師兼寄鄭山人','貫休','唐','御定全唐诗','yuding','','[]','去去楞伽子，春深道路長。鳥啼青嶂險，花落紫衣香。',48,'御定全唐詩/json/834.json','["去去楞伽子，春深道路長。鳥啼青嶂險，花落紫衣香。", "此去非餘事，還歸內道場。憑師將老倒，一向說滎陽。"]'),
('yuding-18','廬山尋靈紀不遇','貫休','唐','御定全唐诗','yuding','','[]','久別稀相見，深山道益孤。葉全離大朴，君尚在新吳。',48,'御定全唐詩/json/834.json','["久別稀相見，深山道益孤。葉全離大朴，君尚在新吳。", "鐘嗄聲飄驛，山頑氣噴湖。留詩如和得，一望寄前途。"]'),
('yuding-19','題曹溪祖師堂','貫休','唐','御定全唐诗','yuding','','[]','皎潔曹溪月，嵯峨七寶林。空傳智藥記，豈見祖禪心。',48,'御定全唐詩/json/834.json','["皎潔曹溪月，嵯峨七寶林。空傳智藥記，豈見祖禪心。", "信衣非苧麻，白雲無知音。大哉雙峰溪，萬古青沉沉。"]'),
('yuding-20','懷匡山道侶','貫休','唐','御定全唐诗','yuding','','[]','常憶將吾友，穿雲過瀑西。有碑皆讀徹，無處不相攜。',48,'御定全唐詩/json/834.json','["常憶將吾友，穿雲過瀑西。有碑皆讀徹，無處不相攜。", "檉桂株株濕，猿猱個個啼。等閒成遠別，窗月又如珪。"]'),
('yuding-21','懷盧延讓','貫休','唐','御定全唐诗','yuding','','[]','冥搜忍饑凍，嗟爾不能休。幾歎不得力，到頭還白頭。',48,'御定全唐詩/json/834.json','["冥搜忍饑凍，嗟爾不能休。幾歎不得力，到頭還白頭。", "姓名歸紫府，妻子在滄洲。又是蟬聲也，如今何處遊。"]'),
('yuding-22','春晚訪鏡湖方幹','貫休','唐','御定全唐诗','yuding','','[]','幽居湖北濱，相訪值殘春。路遠諸峰雨，時多擉鱉人。',48,'御定全唐詩/json/834.json','["幽居湖北濱，相訪值殘春。路遠諸峰雨，時多擉鱉人。", "蒸花初釀酒，漁艇劣容身。莫訝頻來此，伊餘亦隱淪。"]'),
('yuding-23','秋過相思寺','貫休','唐','御定全唐诗','yuding','','[]','見說相思寺，今來似有期。瘴鄉終有出，天意固難欺。',48,'御定全唐詩/json/834.json','["見說相思寺，今來似有期。瘴鄉終有出，天意固難欺。", "晝雨先花島，秋雲掛戍旗。故人多在蜀，不去更何之。"]'),
('yuding-0','蜀王入大慈寺聽講','貫休','唐','御定全唐诗','yuding','','[]','玉節金珂響似雷，水晶宮殿步裴回。只緣支遁談經妙，',96,'御定全唐詩/json/835.json','["玉節金珂響似雷，水晶宮殿步裴回。只緣支遁談經妙，", "千重香擁龍鱗立，五種風生錦繡開。寬似大溟生日月，", "謝太傅須同八凱，姚梁公可並三台。登樓喜色禾將熟，", "六條消息心常苦，一劍晶熒敵盡摧。木鐸聲中天降福，"]'),
('yuding-1','蜀王登福感寺塔三首','貫休','唐','御定全唐诗','yuding','','[]','天資忠孝佐金輪，香火空王有宿因。此世喜登金骨塔，',120,'御定全唐詩/json/835.json','["天資忠孝佐金輪，香火空王有宿因。此世喜登金骨塔，", "釋子沾恩無以報，只擎章句貢平津。", "似聖悲增道不窮，憂民憂國契堯聰。兩髯有雪丹霄外，", "林僧歲月知何幸，還似支公見謝公。", "步步層層孰可陪，相輪邊日照三台。喜歡烝庶皆相逐，", "一年一度常如此，願見文翁百度來。"]'),
('yuding-2','少監三首','貫休','唐','御定全唐诗','yuding','','[]','器琢仙珪美有餘，席珍國寶比難如。銜花乳燕看調瑟，',120,'御定全唐詩/json/835.json','["器琢仙珪美有餘，席珍國寶比難如。銜花乳燕看調瑟，", "即期寰海隆平日，歸佐吾皇侍玉除。", "益友相隨益自強，趨庭問禮日昭彰。袍新宮錦千人目，", "八龍三虎森如也，萬古千秋瑞聖唐。", "具體而微太少年，鳳毛五色帶非煙。倚天長劍看無敵，", "即應出將傳家法，聖澤恩波浩浩然。"]'),
('yuding-3','再到鐘陵作','貫休','唐','御定全唐诗','yuding','','[]','六七年來到豫章，舊游知己半凋傷。春風還有花千樹，',40,'御定全唐詩/json/835.json','["六七年來到豫章，舊游知己半凋傷。春風還有花千樹，", "只應唯有西山色，依舊崔巍上寺牆。"]'),
('yuding-4','經弟妹墳','貫休','唐','御定全唐诗','yuding','','[]','淚不曾垂此日垂，山前弟妹塚離離。年長於吾未得力，',40,'御定全唐詩/json/835.json','["淚不曾垂此日垂，山前弟妹塚離離。年長於吾未得力，", "恩愛苦情拋未得，不堪回首步遲遲。"]'),
('yuding-5','到蜀與鄭中丞相遇','貫休','唐','御定全唐诗','yuding','','[]','深隱猶為未死灰，遠尋知己遇三台。如何麋鹿群中出，',40,'御定全唐詩/json/835.json','["深隱猶為未死灰，遠尋知己遇三台。如何麋鹿群中出，", "謾期王謝來相訪，不是支公出世才。"]'),
('yuding-6','別馮使君','貫休','唐','御定全唐诗','yuding','','[]','瓦礫文章豈有媒，兩三年只在金台。本師頭白須歸去，',40,'御定全唐詩/json/835.json','["瓦礫文章豈有媒，兩三年只在金台。本師頭白須歸去，", "從茲林下終無事，唯只焚香祝上臺。"]'),
('yuding-7','上新定宋使君','貫休','唐','御定全唐诗','yuding','','[]','禪坐吟行誰與同，杉松共在寂寥中。碧雲詩裏終難到，',40,'御定全唐詩/json/835.json','["禪坐吟行誰與同，杉松共在寂寥中。碧雲詩裏終難到，", "十年勤苦今酬了，得句桐江識謝公。"]'),
('yuding-8','和李判官見新榜為兄下第','貫休','唐','御定全唐诗','yuding','','[]','失意荊枝滴淚頻，陟岡何翅不知春。心中岐路平如砥，',40,'御定全唐詩/json/835.json','["失意荊枝滴淚頻，陟岡何翅不知春。心中岐路平如砥，", "從茲相次紅霞裏，留取方書與世人。"]'),
('yuding-9','送羅鄴赴許昌辟','貫休','唐','御定全唐诗','yuding','','[]','方得論心又別離，黯然江上步遲遲。不堪回首崎嶇路，',40,'御定全唐詩/json/835.json','["方得論心又別離，黯然江上步遲遲。不堪回首崎嶇路，", "前程不少南飛雁，聊寄新詩慰所思。"]'),
('yuding-10','酬韋相公見寄','貫休','唐','御定全唐诗','yuding','','[]','鹽梅金鼎美調和，詩寄空林問訊多。秦客弈棋拋已久，',40,'御定全唐詩/json/835.json','["鹽梅金鼎美調和，詩寄空林問訊多。秦客弈棋拋已久，", "空諷平津好珠玉，不知更得及門麼。"]'),
('yuding-11','酬張相公見寄','貫休','唐','御定全唐诗','yuding','','[]','周郎懷抱好知音，常愛山僧物外心。閉戶不知芳草歇，',40,'御定全唐詩/json/835.json','["周郎懷抱好知音，常愛山僧物外心。閉戶不知芳草歇，", "但似前朝蕭與蔣，老僧風雪亦相尋。"]'),
('yuding-12','酬王相公見贈','貫休','唐','御定全唐诗','yuding','','[]','孤拙將來豈偶然，不能為漏滴青蓮。一從麟筆題牆後，',40,'御定全唐詩/json/835.json','["孤拙將來豈偶然，不能為漏滴青蓮。一從麟筆題牆後，", "今朝幸捧瓊瑤贈，始見玄中更有玄。"]'),
('yuding-13','酬周相公見贈','貫休','唐','御定全唐诗','yuding','','[]','三界無家是出家，豈宜拊鳳睹新麻。幸生白髮逢今聖，',40,'御定全唐詩/json/835.json','["三界無家是出家，豈宜拊鳳睹新麻。幸生白髮逢今聖，", "喜擎繡段攀金鼎，謝脁餘霞始是霞。"]'),
('yuding-14','道情偈三首','貫休','唐','御定全唐诗','yuding','','[]','崆峒老人專一一，黃梅真叟卻無無。',96,'御定全唐詩/json/835.json','["崆峒老人專一一，黃梅真叟卻無無。", "獨坐松根石頭上，四溟無限月輪孤。", "非色非空非不空，空中真色不玲瓏。", "可憐盧大擔柴者，拾得驪珠橐鑰中。", "優缽羅花萬劫春，頻犁田地絕纖塵。", "道吾道者相招好，不是香林采葉人。"]'),
('yuding-15','馬上作','貫休','唐','御定全唐诗','yuding','','[]','柳岸花堤夕照紅，風清襟袖轡璁瓏。',32,'御定全唐詩/json/835.json','["柳岸花堤夕照紅，風清襟袖轡璁瓏。", "行人莫訝頻回首，家在凝嵐一點中。"]'),
('yuding-16','道中逢乞食老僧','貫休','唐','御定全唐诗','yuding','','[]','赤棕櫚笠眉毫垂，拄楖栗杖行遲遲。',32,'御定全唐詩/json/835.json','["赤棕櫚笠眉毫垂，拄楖栗杖行遲遲。", "時人只施盂中飯，心似白蓮那得知。"]'),
('yuding-17','秋末寄武昌一公','貫休','唐','御定全唐诗','yuding','','[]','見說武昌江上住，柏枯槐朽戰時風。',32,'御定全唐詩/json/835.json','["見說武昌江上住，柏枯槐朽戰時風。", "知師詩癖難醫也，霜灑蘆花明月中。"]'),
('yuding-18','陋巷','貫休','唐','御定全唐诗','yuding','','[]','墜葉如花欲滿溝，破籬荒井一蟬幽。',32,'御定全唐詩/json/835.json','["墜葉如花欲滿溝，破籬荒井一蟬幽。", "亦知希驥無希者，作麼令人強轉頭。"]'),
('yuding-19','終南僧','貫休','唐','御定全唐诗','yuding','','[]','聲利掀天竟不聞，草衣木食度朝昏。',32,'御定全唐詩/json/835.json','["聲利掀天竟不聞，草衣木食度朝昏。", "遙思山雪深一丈，時有仙人來打門。"]'),
('yuding-20','聽僧彈琴','貫休','唐','御定全唐诗','yuding','','[]','家近吳王古戰城，海風終日打牆聲。',32,'御定全唐詩/json/835.json','["家近吳王古戰城，海風終日打牆聲。", "今朝鄉思渾堆積，琴上聞師大蟹行。"]'),
('yuding-21','漁者','貫休','唐','御定全唐诗','yuding','','[]','風惡波狂身似閑，滿頭霜雪背青山。',32,'御定全唐詩/json/835.json','["風惡波狂身似閑，滿頭霜雪背青山。", "相逢略問家何在，回指蘆花滿舍間。"]'),
('yuding-22','大蜀皇帝潛龍日述聖德詩五首','貫休','唐','御定全唐诗','yuding','','[]','嶽瀆殊祥日月精，入堯金鏡佐休明。衣嚴黼黻皇恩重，',200,'御定全唐詩/json/835.json','["嶽瀆殊祥日月精，入堯金鏡佐休明。衣嚴黼黻皇恩重，", "已聞圖上淩煙閣，寵渥穹窿玉不名。", "扶持社稷似齊桓，百萬雄師貴可觀。神智發中真莫測，", "堪羨蜀民恒有福，太平時節一般般。", "珠履三千侍玉除，宮花飄錦早鶯初。雖然周孔心相似，", "若論朝野艱難日，第一之功美有餘。", "紫髯青眼代天才，韓白孫吳稍可陪。只見赤心堯日下，", "盡祝莊椿同壽考，人間歲月豈能催。", "丈夫勳業正乾坤，麟鳳龜龍盡在門。西伯最憐耕讓畔，", "從此於門轉高大，可憐子子與孫孫。"]'),
('yuding-23','陳情獻蜀皇帝','貫休','唐','御定全唐诗','yuding','','[]','河北江東處處災，唯聞全蜀勿塵埃。一瓶一缽垂垂老，',40,'御定全唐詩/json/835.json','["河北江東處處災，唯聞全蜀勿塵埃。一瓶一缽垂垂老，", "自慚林藪龍鍾者，亦得親登郭隗台。"]'),
('yuding-24','壽春節進大蜀皇帝五首','貫休','唐','御定全唐诗','yuding','','[]','上玄大帝降坤維，箕尾為臣副聖期。豈比赤光盈室日，',200,'御定全唐詩/json/835.json','["上玄大帝降坤維，箕尾為臣副聖期。豈比赤光盈室日，", "今日降神天上會，願將天福比須彌。", "異香滴露降紛紛，紫電環樞照禁門。先冠百王臨億兆，", "今以謏才歌睿德，猶如飲海妙難論。", "茂祉遐宣勝事並，熏風微入舜弦清。四洲不必歸王化，", "西逾昆岳東連海，誰不梯山賀聖明。", "遠人玉帛盡來歸，及物天慈物物肥。春力遍時皆甲拆，", "為報蜀皇勤禱祝，聖明天子古今稀。", "積劫修來似煉金，為皇為帝萬靈欽。能當濁世為清世，", "今朝獻壽將何比，願似莊椿一萬尋。"]'),
('yuding-25','對雪寄新定馮使君二首','貫休','唐','御定全唐诗','yuding','','[]','仙掌空思歸未能，焚香冥目對殘燈。豈知瑞雪千山合，',80,'御定全唐詩/json/835.json','["仙掌空思歸未能，焚香冥目對殘燈。豈知瑞雪千山合，", "因思太守憂民切，吟對瓊枝喜不勝。", "政化由來通上靈，豐年祥瑞滿窗明。氣嚴坐久燈凝焰，", "雪林中客雖無事，還有新詩半夜成。"]'),
('yuding-26','送劉相公朝覲二首','貫休','唐','御定全唐诗','yuding','','[]','九苞仙瑞曜垂衣，一品高標百辟師。魏相十思常自切，',80,'御定全唐詩/json/835.json','["九苞仙瑞曜垂衣，一品高標百辟師。魏相十思常自切，", "唯杜荊州最惆悵，柳門回首落花時。", "急征只是再登庸，生意人心萬國同。燮理久征殷傅說，", "從此龍顏又應瘦，寰瀛俱荷代天功。"]'),
('yuding-27','避寇游成福山院','貫休','唐','御定全唐诗','yuding','','[]','成福僧留不擬歸，獼猴菌嫩豆苗肌。那堪蠶月偏多雨，',40,'御定全唐詩/json/835.json','["成福僧留不擬歸，獼猴菌嫩豆苗肌。那堪蠶月偏多雨，", "堪嗟大似悠悠者，只向詩中話息機。"]'),
('yuding-28','別李常侍','貫休','唐','御定全唐诗','yuding','','[]','楚水和煙海浪通，又擎杯錫去山東。道情雖擬攀孤鶴，',40,'御定全唐詩/json/835.json','["楚水和煙海浪通，又擎杯錫去山東。道情雖擬攀孤鶴，", "朱門再到知何日，一片征帆萬里風。"]'),
('yuding-29','送鄭閣赴閩辟','貫休','唐','御定全唐诗','yuding','','[]','便便書腹德無鄰，健筆從知又入閩。鸚鵡才須歸紫禁，',40,'御定全唐詩/json/835.json','["便便書腹德無鄰，健筆從知又入閩。鸚鵡才須歸紫禁，", "從此應多好消息，莫忘江上一閒人。"]'),
('yuding-30','寄信州張使君','貫休','唐','御定全唐诗','yuding','','[]','水壇檉殿地含煙，領鶴行吟積翠間。數閣涼颸終日去，',40,'御定全唐詩/json/835.json','["水壇檉殿地含煙，領鶴行吟積翠間。數閣涼颸終日去，", "唯羨靈溪賢太守，一麾清坐似深山。"]'),
('yuding-31','春末寄周璉','貫休','唐','御定全唐诗','yuding','','[]','暮角含風雨氣曛，寂寥莓翠上衣巾。道情不向鶯花薄，',40,'御定全唐詩/json/835.json','["暮角含風雨氣曛，寂寥莓翠上衣巾。道情不向鶯花薄，", "手中孤桂月中在，來聽泉聲莫厭頻。"]'),
('yuding-32','《讀吳越春秋》','貫休','唐','御定全唐诗','yuding','','[]','猶來吳越盡須慚，背德違盟又信讒。宰嚭一言終殺伍，',40,'御定全唐詩/json/835.json','["猶來吳越盡須慚，背德違盟又信讒。宰嚭一言終殺伍，", "今日雄圖又何在，野花香徑鳥喃喃。"]'),
('yuding-33','春遊靈泉寺','貫休','唐','御定全唐诗','yuding','','[]','水蹴危梁翠擁沙，鐘聲微徑入深花。嘴紅澗鳥啼芳草，',40,'御定全唐詩/json/835.json','["水蹴危梁翠擁沙，鐘聲微徑入深花。嘴紅澗鳥啼芳草，", "因尋古跡空惆悵，滿袖香風白日斜。"]'),
('yuding-34','歸東陽臨岐上杜使君七首','貫休','唐','御定全唐诗','yuding','','[]','小謝清高大謝才，聖君令泰此方來。',224,'御定全唐詩/json/835.json','["小謝清高大謝才，聖君令泰此方來。", "一從到後常無事，鈴閣公庭滿綠苔。", "紅錦帳中歌白雪，烏皮幾畔撫青英。", "不知何物為心地，賽卻澄江徹底清。", "誰報田中有黑蟲，一家齋戒減仙容。", "分憂若也皆如此，天下家家有剩舂。", "憂民心切出沖炎，禾稼如雲喜氣兼。", "林下閒人亦何幸，也隨旌旆到銀尖。", "方恐獄中桃樹出，忽聞枯木卻生煙。", "褚祥為郡曾如此，卻恐當時是偶然。", "枯骨縱橫遍水湄，盡收為塚碧參差。", "分明為報精靈輩，好送旌旗到鳳池。", "舍魯依劉一片雲，好風吹去遠纖塵。", "猶期明月清風夜，來作西園第八人。"]'),
('yuding-0','春','貫休','唐','御定全唐诗','yuding','','[]','自來自去動洪爐，無象無私無處無。回雁不多消氣力，',40,'御定全唐詩/json/836.json','["自來自去動洪爐，無象無私無處無。回雁不多消氣力，", "莫訝相逢只添睡，伊余心不在榮枯。"]'),
('yuding-1','聞迎真身','貫休','唐','御定全唐诗','yuding','','[]','四海無波八表臣，恭聞今歲禮真身。七重鎖未開金鑰，',40,'御定全唐詩/json/836.json','["四海無波八表臣，恭聞今歲禮真身。七重鎖未開金鑰，", "可憐優缽羅花樹，三十年來一度春。"]'),
('yuding-2','灞陵戰叟','貫休','唐','御定全唐诗','yuding','','[]','劍刓秋水鬢梳霜，回首胡天與恨長。官竟不封右校尉，',40,'御定全唐詩/json/836.json','["劍刓秋水鬢梳霜，回首胡天與恨長。官竟不封右校尉，", "今日灞陵陵畔見，春風花霧共茫茫。"]'),
('yuding-3','遇道者','貫休','唐','御定全唐诗','yuding','','[]','鶴骨松筋風貌殊，不言名姓絕榮枯。尋常藜杖九衢裏，',40,'御定全唐詩/json/836.json','["鶴骨松筋風貌殊，不言名姓絕榮枯。尋常藜杖九衢裏，", "只應張果支公輩，時複相逢醉海隅。"]'),
('yuding-4','贈鐘陵陳處士','貫休','唐','御定全唐诗','yuding','','[]','否極方生社稷才，唯譚帝道鄙梯媒。高吟千首精怪動，',40,'御定全唐詩/json/836.json','["否極方生社稷才，唯譚帝道鄙梯媒。高吟千首精怪動，", "吾皇仄席求賢久，莫待征書兩度來。"]'),
('yuding-5','懷鄰叟','貫休','唐','御定全唐诗','yuding','','[]','常思東溪龐眉翁，是非不解兩頰紅。桔槔打水聲嘎嘎，',40,'御定全唐詩/json/836.json','["常思東溪龐眉翁，是非不解兩頰紅。桔槔打水聲嘎嘎，", "千門萬戶皆車馬，誰愛如斯太古風。"]'),
('yuding-6','贈軒轅先生','貫休','唐','御定全唐诗','yuding','','[]','曾親文景上金鑾，語共容城語一般。久向紅霞居不出，',40,'御定全唐詩/json/836.json','["曾親文景上金鑾，語共容城語一般。久向紅霞居不出，", "略問先生真甲子，只言弟子是劉安。"]'),
('yuding-7','偶作因懷山中道侶','貫休','唐','御定全唐诗','yuding','','[]','是是非非竟不真，桃花流水送青春。姓劉姓項今何在，',40,'御定全唐詩/json/836.json','["是是非非竟不真，桃花流水送青春。姓劉姓項今何在，", "深雲道者相思否，歸去來兮湘水濱。"]'),
('yuding-8','送新羅人及第歸','貫休','唐','御定全唐诗','yuding','','[]','捧桂香和紫禁煙，遠鄉程徹巨鼇邊。莫言掛席飛連夜，',40,'御定全唐詩/json/836.json','["捧桂香和紫禁煙，遠鄉程徹巨鼇邊。莫言掛席飛連夜，", "到鄉必遇來王使，與作唐書寄一篇。"]'),
('yuding-9','送新羅衲僧','貫休','唐','御定全唐诗','yuding','','[]','扶桑枝西真氣奇，古人呼為師子兒。六環金錫輕擺撼，',40,'御定全唐詩/json/836.json','["扶桑枝西真氣奇，古人呼為師子兒。六環金錫輕擺撼，", "多慚不便隨高步，正是風清無事時。"]'),
('yuding-10','春晚桐江上閑望作','貫休','唐','御定全唐诗','yuding','','[]','江上車聲落日催，紛紛擾擾起紅埃。更無人望青山立，',40,'御定全唐詩/json/836.json','["江上車聲落日催，紛紛擾擾起紅埃。更無人望青山立，", "可憐瀟灑鴟夷子，散發扁舟去不回。"]'),
('yuding-11','商山道者','貫休','唐','御定全唐诗','yuding','','[]','五千言外得玄音，石屋寒棲隔雪林。多傍松風梳綠發，',40,'御定全唐詩/json/836.json','["五千言外得玄音，石屋寒棲隔雪林。多傍松風梳綠發，", "曾夢先生非此處，碧桃溪上紫煙深。"]'),
('yuding-12','聞許棠及第因寄桂雍','貫休','唐','御定全唐诗','yuding','','[]','時清道合出塵埃，清苦為詩不仗媒。今日桂枝平折得，',40,'御定全唐詩/json/836.json','["時清道合出塵埃，清苦為詩不仗媒。今日桂枝平折得，", "更有平人居蟄屋，還應為作一聲雷。"]'),
('yuding-13','瀔江秋居作','貫休','唐','御定全唐诗','yuding','','[]','無事相關性自攄，庭前拾葉等閒書。青山萬里竟不足，',40,'御定全唐詩/json/836.json','["無事相關性自攄，庭前拾葉等閒書。青山萬里竟不足，", "面前小沼清如鏡，終養琴高赤鯉魚。"]'),
('yuding-14','上縉雲段使君','貫休','唐','御定全唐诗','yuding','','[]','清畏人知人盡知，縉雲三載得宣尼。活民刀尺雖無象，',40,'御定全唐詩/json/836.json','["清畏人知人盡知，縉雲三載得宣尼。活民刀尺雖無象，", "今朝暫到金臺上，頗覺心如太古時。"]'),
('yuding-15','春末蘭溪道中作','貫休','唐','御定全唐诗','yuding','','[]','山花零落紅與緋，汀煙蒙茸江水肥。人擔犁鋤細雨歇，',40,'御定全唐詩/json/836.json','["山花零落紅與緋，汀煙蒙茸江水肥。人擔犁鋤細雨歇，", "清平時節何時是，轉覺人心與道違。"]'),
('yuding-16','野居偶作','貫休','唐','御定全唐诗','yuding','','[]','高淡清虛即是家，何須須占好煙霞。無心於道道自得，',40,'御定全唐詩/json/836.json','["高淡清虛即是家，何須須占好煙霞。無心於道道自得，", "但令如此還如此，誰羨前程未可涯。"]'),
('yuding-17','再游東林寺作五首','貫休','唐','御定全唐诗','yuding','','[]','台殿參差聳瑞煙，桂花飄雪水潺潺。',160,'御定全唐詩/json/836.json','["台殿參差聳瑞煙，桂花飄雪水潺潺。", "莫疑遠去無消息，七萬餘年始半年。", "桓玄舊輦殘雲濕，耶舍孤墳落照遲。", "有個山僧倚松睡，恐人來取白猿兒。", "玉像珠龕香陣橫，錦霞多傍石牆生。", "辟蛇行者今何在，花裏唯聞鳩鳥聲。", "愛陶長官醉兀兀，送陸道士行遲遲。", "買酒過溪皆破戒，斯何人斯師如斯。", "白薝蔔花露滴滴，紅苾芻草香濛濛。", "田地更無塵一點，是何人合住其中。"]'),
('yuding-18','題蘭江言上人院二首','貫休','唐','御定全唐诗','yuding','','[]','一生只著一麻衣，道業還欺習彥威。',64,'御定全唐詩/json/836.json','["一生只著一麻衣，道業還欺習彥威。", "手把新詩說山夢，石橋天柱雪霏霏。", "只是危吟坐翠層，門前岐路自崩騰。", "青雲名士時相訪，茶煮西峰瀑布冰。"]'),
('yuding-19','中秋十五夜月','貫休','唐','御定全唐诗','yuding','','[]','噀雪噴霜滿碧虛，王孫公子玩相呼。從來天匠為輪足，',40,'御定全唐詩/json/836.json','["噀雪噴霜滿碧虛，王孫公子玩相呼。從來天匠為輪足，", "坐來惟覺情無極，何況三湘與五湖。"]'),
('yuding-20','鷺鷥有懷','貫休','唐','御定全唐诗','yuding','','[]','粉魄霜華為爾枯，鴛鴦相伴更堪圖。愛來沙島遺銀屋，',40,'御定全唐詩/json/836.json','["粉魄霜華為爾枯，鴛鴦相伴更堪圖。愛來沙島遺銀屋，", "今朝不覺頻回首，曾伴瑤花近玉壺。"]'),
('yuding-21','東陽罹亂後懷王慥使君五首','貫休','唐','御定全唐诗','yuding','','[]','昨來隻對漢諸侯，勝事消磨不自由。裂地鼓鼙軍□急，',200,'御定全唐詩/json/836.json','["昨來隻對漢諸侯，勝事消磨不自由。裂地鼓鼙軍□急，", "誰為今朝奉明主，使君司戶在隋州。", "只報精兵過大河，東西南北殺人多。可憐白日渾如此，", "不勝惆悵還惆悵，一曲東風月胯歌。", "為郡無如王使君，一家清冷似雲根。貨財不入崔洪口，", "不堪西望西風起，縱火昆侖誰為論。", "魄懾魂飛骨亦銷，此魂此魄亦難招。黃金白玉家家盡，", "恭聞國有英雄將，擬把何心答聖朝。", "不是龔黃覆育才，即須清苦遠塵埃。無人與奏吾皇去，", "令人轉憶王夫子，一片真風去不回。"]'),
('yuding-22','秋夜懷嵩少因寄洛中舊知','貫休','唐','御定全唐诗','yuding','','[]','爐爇旃檀不稱貧，霏霏玉露濕禪巾。紫金地上三更月，',40,'御定全唐詩/json/836.json','["爐爇旃檀不稱貧，霏霏玉露濕禪巾。紫金地上三更月，", "如今憔悴頭成雪，空想嵯峨羨故人。"]'),
('yuding-23','避地毗陵，寒月上孫徽使君兼寄東陽王使君三首','貫休','唐','御定全唐诗','yuding','','[]','一到毗陵心更勞，冷吟閒步擁雲袍。豈緣思妙塵埃少，',120,'御定全唐詩/json/836.json','["一到毗陵心更勞，冷吟閒步擁雲袍。豈緣思妙塵埃少，", "終須愚谷中安致，不是人間好羽毛。", "常憶雙溪八詠前，講詩論道接清賢。文欺白鳳真難及，", "自憐不是悠悠者，吟嚼真風二十年。", "□雷車雨滴階聲，寂寞焚香獨閉扃。錦繡文章無路達，", "唯有孤高江太守，不忘病客在禪靈。"]'),
('yuding-24','秋末寄上桐江馮使君','貫休','唐','御定全唐诗','yuding','','[]','山東山色勝諸山，謝守清高不可攀。薄俗盡於言下泰，',40,'御定全唐詩/json/836.json','["山東山色勝諸山，謝守清高不可攀。薄俗盡於言下泰，", "野客沾恩歸未得，蕭蕭霜葉滿柴關。"]'),
('yuding-25','禪師','貫休','唐','御定全唐诗','yuding','','[]','擊鼓求亡益是非，木中生火更何為。',32,'御定全唐詩/json/836.json','["擊鼓求亡益是非，木中生火更何為。", "吾師別是醍醐味，不是知心人不知。"]'),
('yuding-26','道士','貫休','唐','御定全唐诗','yuding','','[]','花島相逢滿袖雲，藉花論道過金巾。',32,'御定全唐詩/json/836.json','["花島相逢滿袖雲，藉花論道過金巾。", "騰騰又入仙山去，只恐是青城丈人。"]'),
('yuding-27','風琴','貫休','唐','御定全唐诗','yuding','','[]','至境心為造化功，一枝青竹四弦風。',32,'御定全唐詩/json/836.json','["至境心為造化功，一枝青竹四弦風。", "寥寥雙耳更深後，如在緱山明月中。"]'),
('yuding-28','庭橘','貫休','唐','御定全唐诗','yuding','','[]','蟻踏金苞四五株，洞庭山上味何殊。',32,'御定全唐詩/json/836.json','["蟻踏金苞四五株，洞庭山上味何殊。", "不緣松樹稱君子，肯便甘人喚木奴。"]'),
('yuding-29','落花','貫休','唐','御定全唐诗','yuding','','[]','蝶醉蜂癡一簇香，繡葩紅蒂墮殘芳。',32,'御定全唐詩/json/836.json','["蝶醉蜂癡一簇香，繡葩紅蒂墮殘芳。", "因嗟好德人難得，公子王孫盡斷腸。"]'),
('yuding-30','孤雲','貫休','唐','御定全唐诗','yuding','','[]','將比鷺鷥還恐屈，始思殘雪不如多。',32,'御定全唐詩/json/836.json','["將比鷺鷥還恐屈，始思殘雪不如多。", "清風相引去更遠，皎潔孤高奈爾何。"]'),
('yuding-31','苦吟','貫休','唐','御定全唐诗','yuding','','[]','河薄星疏雪月孤，松枝清氣入肌膚。',32,'御定全唐詩/json/836.json','["河薄星疏雪月孤，松枝清氣入肌膚。", "因知好句勝金玉，心極神勞特地無。"]'),
('yuding-32','古戰處','貫休','唐','御定全唐诗','yuding','','[]','鬼氣蒼黃棘葉紅，昔時人血此時風。',32,'御定全唐詩/json/836.json','["鬼氣蒼黃棘葉紅，昔時人血此時風。", "相憐極目無疆地，曾落將軍一陣中。"]'),
('yuding-33','偶然作','貫休','唐','御定全唐诗','yuding','','[]','蟬聲引出石中蛩，寂寞門扃葉數重。',32,'御定全唐詩/json/836.json','["蟬聲引出石中蛩，寂寞門扃葉數重。", "誰道思山心不切，等閒盡出兩三峰。"]'),
('yuding-34','招友人宿','貫休','唐','御定全唐诗','yuding','','[]','銀地無塵金菊開，紫梨紅棗墮莓苔。',32,'御定全唐詩/json/836.json','["銀地無塵金菊開，紫梨紅棗墮莓苔。", "一泓秋水一輪月，今夜故人來不來。"]'),
('yuding-0','山居詩二十四首','貫休','唐','御定全唐诗','yuding','','[]','休話喧嘩事事難，山翁只合住深山。數聲清磬是非外，',480,'御定全唐詩/json/837.json','["休話喧嘩事事難，山翁只合住深山。數聲清磬是非外，", "無人與向群儒說，岩桂枝高亦好扳。", "難是言休即便休，清吟孤坐碧溪頭。三間茆屋無人到，", "修心未到無心地，萬種千般逐水流。", "好鳥聲長睡眼開，好茶擎乳坐莓苔。不聞榮辱成番盡，", "由來此事知音少，不是真風去不回。", "萬境忘機是道華，碧芙蓉裏日空斜。幽深有徑通仙窟，", "君看江上英雄塚，只有松根與柏槎。", "鞭後從他素發兼，湧清奔碧冷侵簾。高奇章句無人愛，", "居山別有非山意，莫錯將予比宋纖。", "鳥外塵中四十秋，亦曾高挹漢諸侯。如斯標緻雖清拙，", "終須心到曹溪叟，千歲櫧根雪滿頭。", "慵甚嵇康竟不回，何妨方寸似寒灰。山精日作兒童出，", "不行朝市多時也，許史金張安在哉。", "心心心不住希夷，石屋巉岩鬢髮垂。養竹不除當路筍，", "多少故人頭盡白，不知今日又何之。", "龍藏琅函遍九垓，霜鐘金鼓振瓊台。堪嗟一句無人得，", "令人轉憶龐居士，天上人間不可陪。", "五嶽煙霞連不斷，三山洞穴去應通。石窗欹枕疏疏雨，", "因思往事拋心力，六七年來楚水東。", "塵埃中更有埃塵，時複雙眉十為顰。賴有年光飛似箭，", "天意剛容此徒在，不堪惆悵不堪陳。", "翠竇煙岩畫不成，桂華瀑沫雜芳馨。撥霞掃雪和雲母，", "從他人說從他笑，地覆天翻也只寧。"]'),
('yuding-1','再逢虛中道士三首','貫休','唐','御定全唐诗','yuding','','[]','天目西峰古壞壇，壇邊相別雪漫漫。',96,'御定全唐詩/json/837.json','["天目西峰古壞壇，壇邊相別雪漫漫。", "如今四十餘年也，還共當時恰一般。", "囊裏靈龜小似錢，道伊年與我同年。", "壺中長挈天相逐，何處升天更有天。", "吾道將君道且殊，君須全似老君須。", "尋常有語爭堪信，愛說蟠桃似甕粗。"]'),
('yuding-2','上盧使君二首','貫休','唐','御定全唐诗','yuding','','[]','一領彤弓下赤墀，惟將清淨作藩籬。馬卿山嶽金相似，',80,'御定全唐詩/json/837.json','["一領彤弓下赤墀，惟將清淨作藩籬。馬卿山嶽金相似，", "鄱陽黎庶還堪羨，頭有重天足有犛。", "司馬遷文亞聖人，三頭九陌碾香塵。盡傳棣萼麟兼鳳，", "因知寰海升平去，又見高宗夢裏人。"]'),
('yuding-3','陪馮使君遊六首：登幹霄亭','貫休','唐','御定全唐诗','yuding','','[]','擁翠捫蘿山屐輕，飄颻紅旆在青冥。仙科朱紱言非貴，',40,'御定全唐詩/json/837.json','["擁翠捫蘿山屐輕，飄颻紅旆在青冥。仙科朱紱言非貴，", "因思廬嶽彌天客，手把金書倚石屏。"]'),
('yuding-4','陪馮使君遊六首：遊靈泉院','貫休','唐','御定全唐诗','yuding','','[]','珂佩喧喧滿路岐，亂泉聲裏扣禪扉。對花語合希夷境，',40,'御定全唐詩/json/837.json','["珂佩喧喧滿路岐，亂泉聲裏扣禪扉。對花語合希夷境，", "惠岩亦有孤峰在，只戀翻經未得歸。"]'),
('yuding-5','陪馮使君遊六首：過相思嶺','貫休','唐','御定全唐诗','yuding','','[]','譽自馨香道自怡，相思嶺上卻無機。荒渠葉覆深霞在，',40,'御定全唐詩/json/837.json','["譽自馨香道自怡，相思嶺上卻無機。荒渠葉覆深霞在，", "因思往事真堪笑，鶴背漁竿未是歸。"]'),
('yuding-6','陪馮使君遊六首：錦沙墩','貫休','唐','御定全唐诗','yuding','','[]','臨水登山興自奇，錦沙墩上最多時。雖雲發白孤峰好，',40,'御定全唐詩/json/837.json','["臨水登山興自奇，錦沙墩上最多時。雖雲發白孤峰好，", "翛然別是神仙趣，豈羨東山妓樂隨。"]'),
('yuding-7','陪馮使君遊六首：釣罾潭','貫休','唐','御定全唐诗','yuding','','[]','境靜江清無事時，紅旌畫鷁動漁磯。心期只是行春去，',40,'御定全唐詩/json/837.json','["境靜江清無事時，紅旌畫鷁動漁磯。心期只是行春去，", "自憐亦在仙舟上，玉浪翻翻濺草衣。"]'),
('yuding-8','陪馮使君遊六首：迎仙閣','貫休','唐','御定全唐诗','yuding','','[]','澗香霞影繞樓臺，卷箔憑闌耳目開。況從旌旗近鸞鳳，',40,'御定全唐詩/json/837.json','["澗香霞影繞樓臺，卷箔憑闌耳目開。況從旌旗近鸞鳳，", "誰道迎仙仙不至，今朝還有謝公來。"]'),
('yuding-9','賀雨上王使君二首','貫休','唐','御定全唐诗','yuding','','[]','一片丹心合萬靈，應時甘雨帶龍腥。驅塵煞燒連窮□，',80,'御定全唐詩/json/837.json','["一片丹心合萬靈，應時甘雨帶龍腥。驅塵煞燒連窮□，", "應須蚤勒南山石，黃霸清風滿內庭。", "由來天贊德唯馨，朋禱心期事盡行。玄妙久聞談佛母，", "他日為霖亦如此，諸生無不沐經營。"]'),
('yuding-10','感懷寄盧給事二首','貫休','唐','御定全唐诗','yuding','','[]','綿綿遠念近來多，喜鵲隨函到綠蘿。雖匪二賢曾入洛，',80,'御定全唐詩/json/837.json','["綿綿遠念近來多，喜鵲隨函到綠蘿。雖匪二賢曾入洛，", "好更因人寄消息，沃州歸去已蹉跎。", "常憶團圓繡像前，東歸經亂獨生全。孤峰已住六七處，", "如今憔悴荊枝盡，一諷來書一愴然。"]'),
('yuding-11','賀鄭使君','貫休','唐','御定全唐诗','yuding','','[]','三衢蜂蠆陷城池，八詠龍韜整武貔。才諭危亡書半幅，',168,'御定全唐詩/json/837.json','["三衢蜂蠆陷城池，八詠龍韜整武貔。才諭危亡書半幅，", "死地再生知德重，精兵連譀覺山移。人和美葉禎祥出，", "清威嚴令無纖壒，長路深山不拾遺。七邑恩波歌浩渺，", "戰馬閑眠汀草遠，秋鼙幹揭嶽霞隳。義為土地精靈伏，", "笙歌席上偏憐客，刀劍林中亦念詩。縠渚美為長飲水，", "寵渥豈唯分節鉞，勳庸須勒上鐘彝。神資天贊誰堪比，", "扶堯社稷常憂老，到郭汾陽亦未遲。釋子沾恩無以報，"]'),
('yuding-12','送鄭使君','貫休','唐','御定全唐诗','yuding','','[]','刺婺廉閩動帝台，唯將清淨作梯媒。綠沈槍卓妖星落，',96,'御定全唐詩/json/837.json','["刺婺廉閩動帝台，唯將清淨作梯媒。綠沈槍卓妖星落，", "天資劉邵龔黃筆，神助韓彭衛霍才。古驛劍江分掩映，", "禮樂封疆添禮樂，塵埃時節勿塵埃。荔支花下驅千騎，", "謳歌合合千門樂，鼙角雄雄一閣雷。君父恩深頭早白，"]'),
('yuding-13','贈楊公杜之舅','貫休','唐','御定全唐诗','yuding','','[]','分盡君憂一不遺，鳳書征入萬民悲。風雲終日如相逐，',112,'御定全唐詩/json/837.json','["分盡君憂一不遺，鳳書征入萬民悲。風雲終日如相逐，", "談諧儘是經邦術，頭角由來出世姿。天地事須歸橐鑰，", "霞影滿江搖枕簟，鳥行和月下漣漪。周秦漢魏書書在，", "郡中條令春常在，境外歌謠美更奇。道者藥壚留要妙，", "應念衢民千萬戶，家家皆置一生祠。"]'),
('yuding-14','游金華山禪院','貫休','唐','御定全唐诗','yuding','','[]','茲地曾棲菩薩僧，旃檀樓殿瀑崩騰。因知境勝終難到，',40,'御定全唐詩/json/837.json','["茲地曾棲菩薩僧，旃檀樓殿瀑崩騰。因知境勝終難到，", "多慚不及當時海，又下嵯峨一萬層。"]'),
('yuding-15','寄鄭道士二首','貫休','唐','御定全唐诗','yuding','','[]','常憶蘇耽好羽儀，信安山觀住多時。',64,'御定全唐詩/json/837.json','["常憶蘇耽好羽儀，信安山觀住多時。", "不知玉質雙棲處，兩個仙人是阿誰。", "誰帶金輪髻裏珠，何妨相逐去清都。", "舊山大有閒田地，五色香茆有子無。"]'),
('yuding-16','送少年禪師二首','貫休','唐','御定全唐诗','yuding','','[]','秀眉青目樹花衣，一缽隨緣智不知。',64,'御定全唐詩/json/837.json','["秀眉青目樹花衣，一缽隨緣智不知。", "佛與輪王嫌不作，世間剛有個癡兒。", "萬水千山一鶴飛，豈愁遊子暮何之。", "古今此著無人會，王積新輸更不疑。"]'),
('yuding-17','古劍池','貫休','唐','御定全唐诗','yuding','','[]','秋水蓮花三四枝，我來慷慨步遲遲。',32,'御定全唐詩/json/837.json','["秋水蓮花三四枝，我來慷慨步遲遲。", "不決浮雲斬邪佞，真成龍去擬何為。"]'),
('yuding-18','曹娥碑','貫休','唐','御定全唐诗','yuding','','[]','高碑說爾孝應難，彈指端思白浪間。',32,'御定全唐詩/json/837.json','["高碑說爾孝應難，彈指端思白浪間。", "堪歎行人不回首，前山應是苧蘿山。"]'),
('yuding-19','比干傳','貫休','唐','御定全唐诗','yuding','','[]','昏王亡國豈堪陳，只見明誠不見身。',32,'御定全唐詩/json/837.json','["昏王亡國豈堪陳，只見明誠不見身。", "想得先生也知自，欲將留與後來人。"]'),
('yuding-20','送人遊茆山','貫休','唐','御定全唐诗','yuding','','[]','鳥啼花笑暖紛紛，路入青雲白石門。',32,'御定全唐詩/json/837.json','["鳥啼花笑暖紛紛，路入青雲白石門。", "君到前頭好看好，老僧或恐是茆君。"]'),
('yuding-21','聞杜宇','貫休','唐','御定全唐诗','yuding','','[]','咽雨哀風更不停，春光於爾豈無情。',32,'御定全唐詩/json/837.json','["咽雨哀風更不停，春光於爾豈無情。", "宜須喚得謝豹出，方始年年無此聲。"]'),
('yuding-22','聽曉角','貫休','唐','御定全唐诗','yuding','','[]','三會單于滿閣風，五行無忒月朦朧。',32,'御定全唐詩/json/837.json','["三會單于滿閣風，五行無忒月朦朧。", "如何十萬家休戚，只在嗚嗚咽咽中。"]'),
('yuding-23','宿赤松山觀題道人水閣兼寄郡守','貫休','唐','御定全唐诗','yuding','','[]','珠殿香輧倚翠棱，寒棲吾道寄孫登。豈應肘後終無分，',40,'御定全唐詩/json/837.json','["珠殿香輧倚翠棱，寒棲吾道寄孫登。豈應肘後終無分，", "還如華頂清談夜，因有新詩寄鄭弘。"]'),
('yuding-24','春遊涼泉寺','貫休','唐','御定全唐诗','yuding','','[]','一到涼泉未擬歸，迸珠噴玉落階墀。幾多僧只因泉在，',40,'御定全唐詩/json/837.json','["一到涼泉未擬歸，迸珠噴玉落階墀。幾多僧只因泉在，", "青山看著不可上，多病多慵爭奈伊。"]'),
('yuding-25','經吳宮','貫休','唐','御定全唐诗','yuding','','[]','夫差昏暗霸圖傾，千古淒涼地不靈。妖豔恩餘宮露濁，',40,'御定全唐詩/json/837.json','["夫差昏暗霸圖傾，千古淒涼地不靈。妖豔恩餘宮露濁，", "此是前車況非遠，六朝何更不惺惺。"]'),
('yuding-26','送薛侍郎貶峽州司馬','貫休','唐','御定全唐诗','yuding','','[]','得罪唯驚恩未酬，夷陵山水稱閒遊。人如八凱須當國，',40,'御定全唐詩/json/837.json','["得罪唯驚恩未酬，夷陵山水稱閒遊。人如八凱須當國，", "因人好寄新詩好，不獨江東有沃州。"]'),
('yuding-27','將入匡山宿韓判官宅','貫休','唐','御定全唐诗','yuding','','[]','一宿蘭堂接上才，白雪歸去幾裴回。黛青峰朵孤吟後，',40,'御定全唐詩/json/837.json','["一宿蘭堂接上才，白雪歸去幾裴回。黛青峰朵孤吟後，", "明朝江上空回首，始覺清風不可陪。"]'),
('yuding-28','送鄭侍郎騫赴闕','貫休','唐','御定全唐诗','yuding','','[]','文章國器盡琅玕，朝騎駸駸歲欲殘。彩筆只宜天上用，',40,'御定全唐詩/json/837.json','["文章國器盡琅玕，朝騎駸駸歲欲殘。彩筆只宜天上用，", "翰苑舊知憑與說，紫金輪畔寄書難。"]'),
('yuding-29','上盧使君','貫休','唐','御定全唐诗','yuding','','[]','一別旌旗已一年，二林真子勸安禪。常思雙戟華堂裏，',40,'御定全唐詩/json/837.json','["一別旌旗已一年，二林真子勸安禪。常思雙戟華堂裏，", "自憐酷似隨陽雁，霜打風飄到日邊。"]'),
('yuding-30','寄匡山大願和尚','貫休','唐','御定全唐诗','yuding','','[]','一聽玄音下竹亭，卻思窗雪與囊螢。只將清淨酬恩德，',40,'御定全唐詩/json/837.json','["一聽玄音下竹亭，卻思窗雪與囊螢。只將清淨酬恩德，", "不堪回首滄江上，萬仞廬峰在杳冥。"]'),
('yuding-31','別盧使君歸東陽二首','貫休','唐','御定全唐诗','yuding','','[]','雨氣濛濛草滿庭，式微吟劇更誰聽。詩逢匠化唯貪住，',80,'御定全唐詩/json/837.json','["雨氣濛濛草滿庭，式微吟劇更誰聽。詩逢匠化唯貪住，", "從茲還似歸回首，唯祝台星與福星。", "家在嚴陵釣渚旁，細漣嘉樹拂窗涼。難醫林藪煙霞癖，", "終期金鼎調羹日，再近尼丘日月光。"]'),
('yuding-32','溪寺水閣閑眺因寄宋使君','貫休','唐','御定全唐诗','yuding','','[]','溪木蕭條一憑闌，玉霜飛後浪花寒。釣魚船上風煙暝，',40,'御定全唐詩/json/837.json','["溪木蕭條一憑闌，玉霜飛後浪花寒。釣魚船上風煙暝，", "誰如太守分憂外，時把西經盡日看。"]'),
('yuding-33','春送趙文觀送故合州座主神櫬歸洛','貫休','唐','御定全唐诗','yuding','','[]','喜繼于悲錦水東，還鄉仙騎卻尋嵩。再燒良玉堯雲動，',40,'御定全唐詩/json/837.json','["喜繼于悲錦水東，還鄉仙騎卻尋嵩。再燒良玉堯雲動，", "他年必立吾君側，好把書紳答至公。"]'),
('yuding-34','z6光大師草書歌','貫休','唐','御定全唐诗','yuding','','[]','雪壓千峰橫枕上，窮困雖多還激壯。看師逸跡兩相宜，',88,'御定全唐詩/json/837.json','["雪壓千峰橫枕上，窮困雖多還激壯。看師逸跡兩相宜，", "江樓曾見落星石，幾回試發將軍炮。別有寒雕掠絕壁，", "好文天子揮宸翰，禦制本多推玉案。晨開水殿教題壁，", "唯師草聖藝偏高，一掬山泉心便足。"]'),
('yuding-35','題成都玉局觀孫位畫龍','貫休','唐','御定全唐诗','yuding','','[]','我見蘇州昆山佛殿中，金城柱上有二龍。',72,'御定全唐詩/json/837.json','["我見蘇州昆山佛殿中，金城柱上有二龍。", "老僧相傳道是僧繇手，尋常入海共龍鬥。", "又聞蜀國玉局觀有孫遇跡，蟠屈身長八十尺。", "遊人爭看不敢近，頭覷寒泉萬丈碧。"]'),
('yuding-36','觀地獄圖','貫休','唐','御定全唐诗','yuding','','[]','峨峨非劍閣，有樹不堪攀。佛手遮不得，人心似等閒。',48,'御定全唐詩/json/837.json','["峨峨非劍閣，有樹不堪攀。佛手遮不得，人心似等閒。", "周王應未雪，白起作何顏。盡日空彈指，茫茫塵世間。"]'),
('yuding-37','贈雷卿張明府','貫休','唐','御定全唐诗','yuding','','[]','任官征戰後，度日寄閑身。封卷還高客，飛書問野人。',48,'御定全唐詩/json/837.json','["任官征戰後，度日寄閑身。封卷還高客，飛書問野人。", "廢田教種穀，生路遣尋薪。若起柴桑興，無先漉酒巾。"]'),
('yuding-38','獻錢尚父','貫休','唐','御定全唐诗','yuding','','[]','貴逼人來不自由，龍驤鳳翥勢難收。滿堂花醉三千客，',40,'御定全唐詩/json/837.json','["貴逼人來不自由，龍驤鳳翥勢難收。滿堂花醉三千客，", "東南永作金天柱，誰羨當時萬戶侯。"]'),
('yuding-39','繡州張相公見訪','貫休','唐','御定全唐诗','yuding','','[]','德符唐德瑞通天，曾叱讒諛玉座前。千襲彩衣宮錦薄，',40,'御定全唐詩/json/837.json','["德符唐德瑞通天，曾叱讒諛玉座前。千襲彩衣宮錦薄，", "未報君恩終必報，不妨金地禮青蓮。"]'),
('yuding-40','題某公宅','貫休','唐','御定全唐诗','yuding','','[]','宅成天下借圖看，始笑平生眼力慳。地占百灣多是水，',40,'御定全唐詩/json/837.json','["宅成天下借圖看，始笑平生眼力慳。地占百灣多是水，", "只恐中原方鼎沸，天心未遣主人閑。"]'),
('yuding-41','海覺禪師山院','貫休','唐','御定全唐诗','yuding','','[]','人言海覺老宗師，隱絕層巔世莫知。青草不生行道跡，',40,'御定全唐詩/json/837.json','["人言海覺老宗師，隱絕層巔世莫知。青草不生行道跡，", "借問大心能濟物，龍門風雹卷天池。"]'),
('yuding-42','悼張道古','貫休','唐','御定全唐诗','yuding','','[]','清河逝水大匆匆，東觀無人失至公。天上君恩三載隔，',40,'御定全唐詩/json/837.json','["清河逝水大匆匆，東觀無人失至公。天上君恩三載隔，", "惆悵斯人又如此，一聲蠻笛滿江風。"]'),
('yuding-43','月夕','貫休','唐','御定全唐诗','yuding','','[]','霜月夜裴回，樓中羌笛催。曉風吹不盡，江上落殘梅。',24,'御定全唐詩/json/837.json','["霜月夜裴回，樓中羌笛催。曉風吹不盡，江上落殘梅。"]'),
('yuding-44','夜雨','貫休','唐','御定全唐诗','yuding','','[]','夜雨山草濕，爽籟雜枯木。閑吟竺仙偈，清絕過於玉。',24,'御定全唐詩/json/837.json','["夜雨山草濕，爽籟雜枯木。閑吟竺仙偈，清絕過於玉。"]'),
('yuding-45','晚望','貫休','唐','御定全唐诗','yuding','','[]','落日碧江靜，蓮唱清且閑。更尋花發處，借月過前灣。',24,'御定全唐詩/json/837.json','["落日碧江靜，蓮唱清且閑。更尋花發處，借月過前灣。"]'),
('yuding-46','早霜寄蔡大','貫休','唐','御定全唐诗','yuding','','[]','昨夜楚鐘鳴，飛霜下楚城。定知遷客鬢，先向鑒中生。',24,'御定全唐詩/json/837.json','["昨夜楚鐘鳴，飛霜下楚城。定知遷客鬢，先向鑒中生。"]'),
('yuding-47','贈寫經僧楚雲','貫休','唐','御定全唐诗','yuding','','[]','剔皮刺血誠何苦，為寫靈山九會文。',32,'御定全唐詩/json/837.json','["剔皮刺血誠何苦，為寫靈山九會文。", "十指瀝幹終七軸，後來求法更無君。"]'),
('yuding-48','寄題詮律師院','貫休','唐','御定全唐诗','yuding','','[]','錦溪光裏聳樓臺，師院高淩積翠開。深竹杪聞殘磬盡，',40,'御定全唐詩/json/837.json','["錦溪光裏聳樓臺，師院高淩積翠開。深竹杪聞殘磬盡，", "莫訝題詩又東去，石房清冷在天臺。"]'),
('yuding-49','寄天臺葉道士','貫休','唐','御定全唐诗','yuding','','[]','負局高風不可陪，玉霄峰北置樓臺。注參同契未將出，',40,'御定全唐詩/json/837.json','["負局高風不可陪，玉霄峰北置樓臺。注參同契未將出，", "終須肘後相傳好，莫便乘鸞去不回。"]'),
('yuding-50','送道友歸天臺','貫休','唐','御定全唐诗','yuding','','[]','蘚濃苔濕冷層層，珍重先生獨去登。氣養三田傳未得，',40,'御定全唐詩/json/837.json','["蘚濃苔濕冷層層，珍重先生獨去登。氣養三田傳未得，", "太守苦留終不住，可憐江上去騰騰。"]'),
('yuding-51','陶種柑橙，令山童買之','貫休','唐','御定全唐诗','yuding','','[]','高步南山南，高歌北山北。數載買柑橙，山資近又足。',24,'御定全唐詩/json/837.json','["高步南山南，高歌北山北。數載買柑橙，山資近又足。"]'),
('yuding-52','春送僧','貫休','唐','御定全唐诗','yuding','','[]','蜀魄關關花雨深，送師沖雨到江潯。',32,'御定全唐詩/json/837.json','["蜀魄關關花雨深，送師沖雨到江潯。", "不能更折江頭柳，自有青青松柏心。"]'),
('yuding-53','律師','貫休','唐','御定全唐诗','yuding','','[]','薝蔔花紅徑草青，雪膚冰骨步輕輕。',32,'御定全唐詩/json/837.json','["薝蔔花紅徑草青，雪膚冰骨步輕輕。", "今朝暫到焚香處，只恐床前有虱聲。"]'),
('yuding-54','書石壁禪居屋壁','貫休','唐','御定全唐诗','yuding','','[]','赤旃檀塔六七級，白菡萏花三四枝。',32,'御定全唐詩/json/837.json','["赤旃檀塔六七級，白菡萏花三四枝。", "禪客相逢只彈指，此心能有幾人知。"]'),
('yuding-55','句','貫休','唐','御定全唐诗','yuding','','[]','今日再三難更識，讖辭唯道待錢來。（周寶蒞丹陽，州人',223,'御定全唐詩/json/837.json','["今日再三難更識，讖辭唯道待錢來。（周寶蒞丹陽，州人", "有事，輒雲待錢來，後果以錢鏐代之。此上錢鏐句也）", "雁蕩經行雲漠漠，龍湫宴坐雨濛濛。（雁蕩山今有經行台、", "宴坐峰，皆以休得名）", "刻成箏柱雁相挨。", "黃昏風雨黑如盤，別我不知何處去。（《俠客》，", "郭尚父休誇塞北，裴中令莫說淮西。", "萬計交人買，華軒保惜深。", "如何忠為主，至竟不封侯。", "但看千騎去，知有幾人歸。", "一生不蓄買田錢，華屋何心亦偶然。客至多逢僧在坐，", "家為買琴添舊價，廚因養鶴減晨炊。", "粘粉為題棲鳳竹，帶香因洗落花泉。"]'),
('yuding-0','夏日草堂作','齊己','唐','御定全唐诗','yuding','','[]','沙泉帶草堂，紙帳卷空床。靜是真消息，吟非俗肺腸。',48,'御定全唐詩/json/838.json','["沙泉帶草堂，紙帳卷空床。靜是真消息，吟非俗肺腸。", "園林坐清影，梅杏嚼紅香。誰住原西寺，鐘聲送夕陽。"]'),
('yuding-1','寄鏡湖方幹處士','齊己','唐','御定全唐诗','yuding','','[]','賀監舊山川，空來近百年。聞君與琴鶴，終日在漁船。',48,'御定全唐詩/json/838.json','["賀監舊山川，空來近百年。聞君與琴鶴，終日在漁船。", "島露深秋石，湖澄半夜天。雲門幾回去，題遍好林泉。"]'),
('yuding-2','送人歸吳','齊己','唐','御定全唐诗','yuding','','[]','比說歸耕釣，迢迢向海涯。春寒遊子路，村晚主人家。',48,'御定全唐詩/json/838.json','["比說歸耕釣，迢迢向海涯。春寒遊子路，村晚主人家。", "□□□□□，□山綠過茶。重尋舊鄰里，菱藕正開花。"]'),
('yuding-3','贈仰上人','齊己','唐','御定全唐诗','yuding','','[]','避地依真境，安閒似舊溪。干戈百裏外，泉石亂峰西。',48,'御定全唐詩/json/838.json','["避地依真境，安閒似舊溪。干戈百裏外，泉石亂峰西。", "草瑞香難歇，松靈蓋盡低。尋應報休馬，瓶錫向南攜。"]'),
('yuding-4','夜坐','齊己','唐','御定全唐诗','yuding','','[]','百蟲聲裏坐，夜色共冥冥。遠憶諸峰頂，曾棲此性靈。',48,'御定全唐詩/json/838.json','["百蟲聲裏坐，夜色共冥冥。遠憶諸峰頂，曾棲此性靈。", "月華澄有象，詩思在無形。徹曙都忘寢，虛窗日照經。"]'),
('yuding-5','新栽松','齊己','唐','御定全唐诗','yuding','','[]','野僧教種法，苒苒出蓬蒿。百歲催人老，千年待爾高。',48,'御定全唐詩/json/838.json','["野僧教種法，苒苒出蓬蒿。百歲催人老，千年待爾高。", "靜宜兼竹石，幽合近猿猱。他日成陰後，秋風吹海濤。"]'),
('yuding-6','期友人','齊己','唐','御定全唐诗','yuding','','[]','早晚逐茲來，閑門日為開。亂蛩鳴白草，殘菊藉蒼苔。',48,'御定全唐詩/json/838.json','["早晚逐茲來，閑門日為開。亂蛩鳴白草，殘菊藉蒼苔。", "困臥誰驚起，閑行自欲回。何時此攜手，吾子本多才。"]'),
('yuding-7','和鄭谷郎中看棋','齊己','唐','御定全唐诗','yuding','','[]','個是仙家事，何人合用心。幾時終一局，萬木老千岑。',48,'御定全唐詩/json/838.json','["個是仙家事，何人合用心。幾時終一局，萬木老千岑。", "有路如飛出，無機似陸沈。樵夫可能解，也此廢光陰。"]'),
('yuding-8','寄錢塘羅給事','齊己','唐','御定全唐诗','yuding','','[]','憤憤嘔讒書，無人誦子虛。傷心天佑末，搔首懿宗初。',48,'御定全唐詩/json/838.json','["憤憤嘔讒書，無人誦子虛。傷心天佑末，搔首懿宗初。", "海樹青叢短，湖山翠點疏。秋濤看足否，羅刹石邊居。"]'),
('yuding-9','戊辰歲湘中寄鄭谷郎中','齊己','唐','御定全唐诗','yuding','','[]','白髮久慵簪，常聞病亦吟。瘦應成鶴骨，閑想似禪心。',48,'御定全唐詩/json/838.json','["白髮久慵簪，常聞病亦吟。瘦應成鶴骨，閑想似禪心。", "上國楊花亂，滄洲荻筍深。不堪思翠巘，西望獨沾襟。"]'),
('yuding-10','寓言','齊己','唐','御定全唐诗','yuding','','[]','造化安能保，山川鑿欲翻。精華銷地底，珠玉聚侯門。',48,'御定全唐詩/json/838.json','["造化安能保，山川鑿欲翻。精華銷地底，珠玉聚侯門。", "始作驕奢本，終為禍亂根。亡家與亡國，雲此更何言。"]'),
('yuding-11','寄王振拾遺','齊己','唐','御定全唐诗','yuding','','[]','折檻意何如，平安信不虛。近來焚諫草，深去覓山居。',48,'御定全唐詩/json/838.json','["折檻意何如，平安信不虛。近來焚諫草，深去覓山居。", "□□□□□，□□□□餘。分明知在處，難寄亂離書。"]'),
('yuding-12','經賈島舊居','齊己','唐','御定全唐诗','yuding','','[]','先生居處所，野燒幾為灰。若有吟魂在，應隨夜魄回。',48,'御定全唐詩/json/838.json','["先生居處所，野燒幾為灰。若有吟魂在，應隨夜魄回。", "地寧銷志氣，天忍罪清才。古木霜風晚，江禽共宿來。"]'),
('yuding-13','送人游塞','齊己','唐','御定全唐诗','yuding','','[]','槐柳野橋邊，行塵暗馬前。秋風來漢地，客路入胡天。',48,'御定全唐詩/json/838.json','["槐柳野橋邊，行塵暗馬前。秋風來漢地，客路入胡天。", "雁聚河流濁，羊群磧草膻。那堪隴頭宿，鄉夢逐潺湲。"]'),
('yuding-14','桃花','齊己','唐','御定全唐诗','yuding','','[]','千株含露態，何處照人紅。風暖仙源裏，春和水國中。',48,'御定全唐詩/json/838.json','["千株含露態，何處照人紅。風暖仙源裏，春和水國中。", "流鶯應見落，舞蝶未知空。擬欲求圖畫，枝枝帶竹叢。"]'),
('yuding-15','聞雁','齊己','唐','御定全唐诗','yuding','','[]','何處人驚起，飛來過草堂。丹心勞避弋，萬里念隨陽。',48,'御定全唐詩/json/838.json','["何處人驚起，飛來過草堂。丹心勞避弋，萬里念隨陽。", "影斷風天月，聲孤荻岸霜。明年趁春去，江上別鴛鴦。"]'),
('yuding-16','送人游南','齊己','唐','御定全唐诗','yuding','','[]','南國多山水，君遊興可知。船中江上景，晚泊早行時。',48,'御定全唐詩/json/838.json','["南國多山水，君遊興可知。船中江上景，晚泊早行時。", "子美遺魂地，藏真舊墨池。經過幾銷日，荒草裏尋碑。"]'),
('yuding-17','送益公歸舊居','齊己','唐','御定全唐诗','yuding','','[]','舊隱終牽夢，春殘結束歸。溪山無伴過，風雨有花飛。',48,'御定全唐詩/json/838.json','["舊隱終牽夢，春殘結束歸。溪山無伴過，風雨有花飛。", "片石留題字，孤潭照浣衣。鄰僧喜相接，掃徑與開扉。"]'),
('yuding-18','不睡','齊己','唐','御定全唐诗','yuding','','[]','永夜不欲睡，虛堂閉複開。卻離燈影去，待得月光來。',48,'御定全唐詩/json/838.json','["永夜不欲睡，虛堂閉複開。卻離燈影去，待得月光來。", "落葉逢巢住，飛螢值我回。天明拂經案，一炷白檀灰。"]'),
('yuding-19','新秋雨後','齊己','唐','御定全唐诗','yuding','','[]','夜雨洗河漢，詩懷覺有靈。籬聲新蟋蟀，草影老蜻蜓。',48,'御定全唐詩/json/838.json','["夜雨洗河漢，詩懷覺有靈。籬聲新蟋蟀，草影老蜻蜓。", "靜引閑機發，涼吹遠思醒。逍遙向誰說，時注漆園經。"]'),
('yuding-20','送劉蛻秀才赴舉','齊己','唐','御定全唐诗','yuding','','[]','百發百中□，□□□□年。丹枝如計分，一箭的無偏。',48,'御定全唐詩/json/838.json','["百發百中□，□□□□年。丹枝如計分，一箭的無偏。", "文物兵銷國，關河雪霽天。都人看春榜，韓字在誰前。"]'),
('yuding-21','留題仰山大師塔院','齊己','唐','御定全唐诗','yuding','','[]','嵐光疊杳冥，曉翠濕窗明。欲起游方去，重來繞塔行。',48,'御定全唐詩/json/838.json','["嵐光疊杳冥，曉翠濕窗明。欲起游方去，重來繞塔行。", "亂雲開鳥道，群木發秋聲。曾約諸徒弟，香燈盡此生。"]'),
('yuding-22','亂中聞鄭谷、吳延保下世','齊己','唐','御定全唐诗','yuding','','[]','小諫才埋玉，星郎亦逝川。國由多聚盜，天似不容賢。',48,'御定全唐詩/json/838.json','["小諫才埋玉，星郎亦逝川。國由多聚盜，天似不容賢。", "兵火焚詩草，江流漲墓田。長安已塗炭，追想更淒然。"]'),
('yuding-23','送東林寺睦公往吳國','齊己','唐','御定全唐诗','yuding','','[]','八月江行好，風帆日夜飄。煙霞經北固，禾黍過南朝。',48,'御定全唐詩/json/838.json','["八月江行好，風帆日夜飄。煙霞經北固，禾黍過南朝。", "社客無宗炳，詩家有鮑昭。莫因賢相請，不返舊山椒。"]'),
('yuding-24','除夜','齊己','唐','御定全唐诗','yuding','','[]','夜久誰同坐，爐寒鼎亦澄。亂松飄雨雪，一室掩香燈。',48,'御定全唐詩/json/838.json','["夜久誰同坐，爐寒鼎亦澄。亂松飄雨雪，一室掩香燈。", "白髮添新歲，清吟減舊朋。明朝待晴旭，池上看春冰。"]'),
('yuding-25','送秘上人','齊己','唐','御定全唐诗','yuding','','[]','誰喜老閑身，春山起送君。欲憑蓮社信，轉入洞庭雲。',48,'御定全唐詩/json/838.json','["誰喜老閑身，春山起送君。欲憑蓮社信，轉入洞庭雲。", "道路長無阻，干戈漸不聞。秋來向何處，相憶雁成群。"]'),
('yuding-26','寓居岳麓，謝進士沈彬再訪','齊己','唐','御定全唐诗','yuding','','[]','去歲來尋我，留題在蘚痕。又因風雪夜，重宿古松門。',48,'御定全唐詩/json/838.json','["去歲來尋我，留題在蘚痕。又因風雪夜，重宿古松門。", "玉有疑休泣，詩無主且言。明朝此相送，披褐入桃源。"]'),
('yuding-27','對雪','齊己','唐','御定全唐诗','yuding','','[]','松門堆複積，埋石亦埋莎。為瑞還難得，居貧莫厭多。',48,'御定全唐詩/json/838.json','["松門堆複積，埋石亦埋莎。為瑞還難得，居貧莫厭多。", "聽憐終夜落，吟惜一年過。誰在江樓望，漫漫墮綠波。"]'),
('yuding-28','和岷公送李評事往宜春','齊己','唐','御定全唐诗','yuding','','[]','兵火銷鄰境，龍沙有去人。江潭牽興遠，風物入題新。',48,'御定全唐詩/json/838.json','["兵火銷鄰境，龍沙有去人。江潭牽興遠，風物入題新。", "雪湛將殘臘，霞明向早春。郡侯開宴處，桃李照歌塵。"]'),
('yuding-29','送僧','齊己','唐','御定全唐诗','yuding','','[]','老憶游方日，天涯錫獨搖。淩晨從北固，沖雪向南朝。',48,'御定全唐詩/json/838.json','["老憶游方日，天涯錫獨搖。淩晨從北固，沖雪向南朝。", "鬢髮泉邊剃，香燈樹下燒。雙峰諸道友，夏滿有書招。"]'),
('yuding-30','過荊門','齊己','唐','御定全唐诗','yuding','','[]','路出荊門遠，行行日欲西。草枯蠻塚亂，山斷漢江低。',48,'御定全唐詩/json/838.json','["路出荊門遠，行行日欲西。草枯蠻塚亂，山斷漢江低。", "野店叢蒿短，煙村簇樹齊。翻思故林去，在處有猿啼。"]'),
('yuding-31','山中答人','齊己','唐','御定全唐诗','yuding','','[]','謾道詩名出，何曾著苦吟。忽來還有意，已過即無心。',48,'御定全唐詩/json/838.json','["謾道詩名出，何曾著苦吟。忽來還有意，已過即無心。", "夏月山長往，霜天寺獨尋。故人憐拙朴，時複寄空林。"]'),
('yuding-32','贈盧明府閒居','齊己','唐','御定全唐诗','yuding','','[]','鬢霜垂七十，江國久辭官。滿篋新風雅，何人舊歲寒。',48,'御定全唐詩/json/838.json','["鬢霜垂七十，江國久辭官。滿篋新風雅，何人舊歲寒。", "閒居當野水，幽鳥宿漁竿。終欲相尋去，兵戈時轉難。"]'),
('yuding-33','幽庭','齊己','唐','御定全唐诗','yuding','','[]','不放生纖草，從教遍綠苔。還防長者至，未著牡丹栽。',48,'御定全唐詩/json/838.json','["不放生纖草，從教遍綠苔。還防長者至，未著牡丹栽。", "蛺蝶空飛過，鶺鴒時下來。南鄰折芳子，到此寂寥回。"]'),
('yuding-34','送休師歸長沙甯覲','齊己','唐','御定全唐诗','yuding','','[]','吾子此歸寧，風煙是舊經。無窮芳草色，何處故山青。',48,'御定全唐詩/json/838.json','["吾子此歸寧，風煙是舊經。無窮芳草色，何處故山青。", "偶泊鳴蟬島，難眠好月汀。殷勤問安外，湘岸采詩靈。"]'),
('yuding-35','將游嵩華行次荊渚','齊己','唐','御定全唐诗','yuding','','[]','蓮峰映敷水，嵩岳壓伊河。兩處思歸久，前賢隱去多。',48,'御定全唐詩/json/838.json','["蓮峰映敷水，嵩岳壓伊河。兩處思歸久，前賢隱去多。", "閑身應絕跡，在世幸無他。會向紅霞嶠，僧龕對薜蘿。"]'),
('yuding-36','遠思','齊己','唐','御定全唐诗','yuding','','[]','遠思極何處，南樓煙水長。秋風過鴻雁，遊子在瀟湘。',48,'御定全唐詩/json/838.json','["遠思極何處，南樓煙水長。秋風過鴻雁，遊子在瀟湘。", "海面雲生白，天涯墮晚光。徘徊古堤上，曾此贈垂楊。"]'),
('yuding-37','寄勉二三子','齊己','唐','御定全唐诗','yuding','','[]','不見二三子，悠然吳楚間。盡應生白髮，幾個在青山。',48,'御定全唐詩/json/838.json','["不見二三子，悠然吳楚間。盡應生白髮，幾個在青山。", "□□□□□，□□莫放閑。君聞國風否，千載詠關關。"]'),
('yuding-38','渚宮江亭寓目','齊己','唐','御定全唐诗','yuding','','[]','津亭雖極望，未稱本心閑。白有三江水，青無一點山。',48,'御定全唐詩/json/838.json','["津亭雖極望，未稱本心閑。白有三江水，青無一點山。", "新鴻喧夕浦，遠棹聚空灣。終遂歸匡社，孤帆即此還。"]'),
('yuding-39','蝴蝶','齊己','唐','御定全唐诗','yuding','','[]','何處背繁紅，迷芳到檻重。分飛還獨出，成隊偶相逢。',96,'御定全唐詩/json/838.json','["何處背繁紅，迷芳到檻重。分飛還獨出，成隊偶相逢。", "遠害終防雀，爭先不避蜂。桃蹊牽往復，蘭徑引相從。", "翠裛丹心冷，香凝粉翅濃。可尋穿樹影，難覓宿花蹤。", "日晚來仍急，春殘舞未慵。西風舊池館，猶得采芙蓉。"]'),
('yuding-40','送劉秀才往東洛','齊己','唐','御定全唐诗','yuding','','[]','羨子去東周，行行非旅遊。煙霄有兄弟，事業盡曹劉。',48,'御定全唐詩/json/838.json','["羨子去東周，行行非旅遊。煙霄有兄弟，事業盡曹劉。", "洛水清奔夏，嵩雲白入秋。來年遂鵬化，一舉上瀛洲。"]'),
('yuding-41','移竹','齊己','唐','御定全唐诗','yuding','','[]','舊溪千萬竿，風雨夜珊珊。白首來江國，黃金買歲寒。',48,'御定全唐詩/json/838.json','["舊溪千萬竿，風雨夜珊珊。白首來江國，黃金買歲寒。", "乍移傷粉節，終繞著朱欄。會得承春力，新抽錦籜看。"]'),
('yuding-42','雉','齊己','唐','御定全唐诗','yuding','','[]','角角類關關，春晴錦羽幹。文呈五色異，瑞入九苞難。',48,'御定全唐詩/json/838.json','["角角類關關，春晴錦羽幹。文呈五色異，瑞入九苞難。", "暮宿紅蘭暖，朝飛綠野寒。山梁從行者，錯解仲尼歎。"]'),
('yuding-43','懷軒轅先生','齊己','唐','御定全唐诗','yuding','','[]','不得先生信，空懷汗漫秋。月華離鶴背，日影上鼇頭。',48,'御定全唐詩/json/838.json','["不得先生信，空懷汗漫秋。月華離鶴背，日影上鼇頭。", "欲學孤雲去，其如重骨留。槎程在何處，人世屢荒丘。"]'),
('yuding-44','永夜感懷寄鄭谷郎中','齊己','唐','御定全唐诗','yuding','','[]','輾轉複輾轉，所思安可論。夜涼難就枕，月好重開門。',48,'御定全唐詩/json/838.json','["輾轉複輾轉，所思安可論。夜涼難就枕，月好重開門。", "霜殺百草盡，蛩歸四壁根。生來苦章句，早遇至公言。"]'),
('yuding-45','賣松者','齊己','唐','御定全唐诗','yuding','','[]','未得淩雲價，何慚所買真。自知桃李世，有愛歲寒人。',48,'御定全唐詩/json/838.json','["未得淩雲價，何慚所買真。自知桃李世，有愛歲寒人。", "瑟瑟初離澗，青青未識塵。寧同買花者，貴逐片時春。"]'),
('yuding-46','丙寅歲寄潘歸仁','齊己','唐','御定全唐诗','yuding','','[]','九土盡荒墟，干戈殺害餘。更須憂去國，未可守貧居。',48,'御定全唐詩/json/838.json','["九土盡荒墟，干戈殺害餘。更須憂去國，未可守貧居。", "康泰終來在，編聯莫破除。他年遇知己，無恥報襜褕。"]'),
('yuding-47','嘗茶','齊己','唐','御定全唐诗','yuding','','[]','石屋晚煙生，松窗鐵碾聲。因留來客試，共說寄僧名。',48,'御定全唐詩/json/838.json','["石屋晚煙生，松窗鐵碾聲。因留來客試，共說寄僧名。", "味擊詩魔亂，香搜睡思輕。春風霅川上，憶傍綠叢行。"]'),
('yuding-48','楊花','齊己','唐','御定全唐诗','yuding','','[]','暖景照悠悠，遮空勢漸稠。乍如飛雪遠，未似落花休。',144,'御定全唐詩/json/838.json','["暖景照悠悠，遮空勢漸稠。乍如飛雪遠，未似落花休。", "萬帶都門外，千株渭水頭。紛紜知近夏，銷歇恐成秋。", "軟著朝簪去，狂隨別騎遊。旆沖離館驛，鶯撲繞宮樓。", "江國晴愁對，池塘晚見浮。虛窗縈筆雅，深院藉苔幽。", "靜墮王孫酒，繁黏客子裘。詠吟何潔白，根本屬風流。", "向日還輕舉，因風更自由。不堪思汴岸，千里到揚州。"]'),
('yuding-49','詠影','齊己','唐','御定全唐诗','yuding','','[]','萬物患有象，不能逃大明。始隨殘魄滅，又逐曉光生。',48,'御定全唐詩/json/838.json','["萬物患有象，不能逃大明。始隨殘魄滅，又逐曉光生。", "曲直甯相隱，洪纖必自呈。還如至公世，洞鑒是非情。"]'),
('yuding-50','南歸舟中二首','齊己','唐','御定全唐诗','yuding','','[]','南歸乘客棹，道路免崎嶇。江上經時節，船中聽鷓鴣。',96,'御定全唐詩/json/838.json','["南歸乘客棹，道路免崎嶇。江上經時節，船中聽鷓鴣。", "春容含眾岫，雨氣泛平蕪。落日停舟望，王維未有圖。", "長江春氣寒，客況棹聲閑。夜泊諸村雨，程回數郡山。", "桑根垂斷岸，浪沫聚空灣。已去鄰園近，隨緣是暫還。"]'),
('yuding-51','送遷客','齊己','唐','御定全唐诗','yuding','','[]','天涯即愛州，謫去莫多愁。若似承恩好，何如傍主休。',48,'御定全唐詩/json/838.json','["天涯即愛州，謫去莫多愁。若似承恩好，何如傍主休。", "瘴昏銅柱黑，草赤火山秋。應想堯陰下，當時獬豸頭。"]'),
('yuding-52','題中上人院','齊己','唐','御定全唐诗','yuding','','[]','高房占境幽，講退即冥搜。欠鶴同支遁，多詩似惠休。',48,'御定全唐詩/json/838.json','["高房占境幽，講退即冥搜。欠鶴同支遁，多詩似惠休。", "瓶澄孤井浪，案白小窗秋。莫道歸山字，朝賢日獻酬。"]'),
('yuding-53','逢鄉友','齊己','唐','御定全唐诗','yuding','','[]','無況來江島，逢君話滯留。生緣同一國，相識共他州。',48,'御定全唐詩/json/838.json','["無況來江島，逢君話滯留。生緣同一國，相識共他州。", "竹影斜青蘚，茶香在白甌。猶憐心道合，多事亦冥搜。"]'),
('yuding-54','自勉','齊己','唐','御定全唐诗','yuding','','[]','試算平生事，中年欠五年。知非未落後，讀易尚加前。',48,'御定全唐詩/json/838.json','["試算平生事，中年欠五年。知非未落後，讀易尚加前。", "分受詩魔役，甯容俗態牽。閑吟見秋水，數隻釣魚船。"]'),
('yuding-55','寄詩友','齊己','唐','御定全唐诗','yuding','','[]','天地有萬物，盡應輸苦心。他人雖欲解，此道奈何深。',48,'御定全唐詩/json/838.json','["天地有萬物，盡應輸苦心。他人雖欲解，此道奈何深。", "返樸遺時態，關門度歲陰。相思去秋夕，共對冷燈吟。"]'),
('yuding-56','居道林寺書懷','齊己','唐','御定全唐诗','yuding','','[]','花落水喧喧，端居信晝昏。誰來看山寺，自要掃松門。',48,'御定全唐詩/json/838.json','["花落水喧喧，端居信晝昏。誰來看山寺，自要掃松門。", "是事皆能諱，唯詩未懶言。傳聞好時世，亦欲背啼猿。"]'),
('yuding-57','經吳平觀','齊己','唐','御定全唐诗','yuding','','[]','中元齋醮後，殘燼滿空壇。老鶴心何待，尊師鬢已幹。',48,'御定全唐詩/json/838.json','["中元齋醮後，殘燼滿空壇。老鶴心何待，尊師鬢已幹。", "幡燈古殿夜，霜霰大椿寒。誰見長生路，人間事萬端。"]'),
('yuding-58','劍客','齊己','唐','御定全唐诗','yuding','','[]','拔劍繞殘樽，歌終便出門。西風滿天雪，何處報人恩。',48,'御定全唐詩/json/838.json','["拔劍繞殘樽，歌終便出門。西風滿天雪，何處報人恩。", "勇死尋常事，輕讎不足論。翻嫌易水上，細碎動離魂。"]'),
('yuding-59','白髮','齊己','唐','御定全唐诗','yuding','','[]','莫染亦莫鑷，任從伊滿頭。白雖無耐藥，黑也不禁秋。',48,'御定全唐詩/json/838.json','["莫染亦莫鑷，任從伊滿頭。白雖無耐藥，黑也不禁秋。", "靜枕聽蟬臥，閑垂看水流。浮生未達此，多為爾為愁。"]'),
('yuding-60','秋興寄胤公','齊己','唐','御定全唐诗','yuding','','[]','風聲吹竹健，涼氣著身輕。誰有閒心去，江邊看水行。',48,'御定全唐詩/json/838.json','["風聲吹竹健，涼氣著身輕。誰有閒心去，江邊看水行。", "村遙紅樹遠，野闊白煙平。試裂芭蕉片，題詩問竺卿。"]'),
('yuding-61','野步','齊己','唐','御定全唐诗','yuding','','[]','城裏無閑處，卻尋城外行。田園經雨水，鄉國憶桑耕。',48,'御定全唐詩/json/838.json','["城裏無閑處，卻尋城外行。田園經雨水，鄉國憶桑耕。", "傍澗蕨薇老，隔村岡隴橫。何窮此心興，時複鷓鴣聲。"]'),
('yuding-62','殘春','齊己','唐','御定全唐诗','yuding','','[]','三月看無也，芳時此可嗟。園林欲向夕，風雨更吹花。',48,'御定全唐詩/json/838.json','["三月看無也，芳時此可嗟。園林欲向夕，風雨更吹花。", "影亂沖人蝶，聲繁繞塹蛙。那堪傍楊柳，飛絮滿鄰家。"]'),
('yuding-63','酬尚顏','齊己','唐','御定全唐诗','yuding','','[]','取盡風騷妙，名高身倍閑。久離王者闕，欲向祖師山。',48,'御定全唐詩/json/838.json','["取盡風騷妙，名高身倍閑。久離王者闕，欲向祖師山。", "幕府秋招去，溪鄰日望還。伊餘豈酬敵，來往踏苔斑。"]'),
('yuding-64','苦熱','齊己','唐','御定全唐诗','yuding','','[]','雲勢嶮于峰，金流斷竹風。萬方應望雨，片景欲焚空。',48,'御定全唐詩/json/838.json','["雲勢嶮于峰，金流斷竹風。萬方應望雨，片景欲焚空。", "毒害芙蓉死，煩蒸瀑布紅。恩多是團扇，出入畫屏中。"]'),
('yuding-65','送歐陽秀才赴舉','齊己','唐','御定全唐诗','yuding','','[]','莫疑空手去，無援取高科。直是文章好，爭如德行多。',48,'御定全唐詩/json/838.json','["莫疑空手去，無援取高科。直是文章好，爭如德行多。", "煙霄心一寸，霜雪路千坡。稱意東歸後，交親那喜何。"]'),
('yuding-66','放鷺鷥','齊己','唐','御定全唐诗','yuding','','[]','潔白雖堪愛，腥膻不那何。到頭從所欲，還汝舊滄波。',24,'御定全唐詩/json/838.json','["潔白雖堪愛，腥膻不那何。到頭從所欲，還汝舊滄波。"]'),
('yuding-67','謝王秀才見示詩卷','齊己','唐','御定全唐诗','yuding','','[]','誰見少年心，低摧向苦吟。後須離影響，得必洞精深。',48,'御定全唐詩/json/838.json','["誰見少年心，低摧向苦吟。後須離影響，得必洞精深。", "道院春苔徑，僧樓夏竹林。天如愛才子，何慮未知音。"]'),
('yuding-68','送徐秀才之吳','齊己','唐','御定全唐诗','yuding','','[]','吳都霸道昌，才子去觀光。望闕雲天近，朝宗水路長。',48,'御定全唐詩/json/838.json','["吳都霸道昌，才子去觀光。望闕雲天近，朝宗水路長。", "海門收片雨，建業泊殘陽。欲問淮王信，仙都即帝鄉。"]'),
('yuding-69','獨院偶作','齊己','唐','御定全唐诗','yuding','','[]','風篁清一院，坐臥潤肌膚。此境終拋去，鄰房肯信無。',48,'御定全唐詩/json/838.json','["風篁清一院，坐臥潤肌膚。此境終拋去，鄰房肯信無。", "身非王者役，門是祖師徒。畢竟伊雲鳥，從來我友于。"]'),
('yuding-70','酬元員外見寄','齊己','唐','御定全唐诗','yuding','','[]','僻巷誰相訪，風籬翠蔓牽。易中通性命，貧裏過流年。',48,'御定全唐詩/json/838.json','["僻巷誰相訪，風籬翠蔓牽。易中通性命，貧裏過流年。", "且有吟情撓，都無俗事煎。時聞得新意，多是此忘緣。"]'),
('yuding-71','寄文秀大師','齊己','唐','御定全唐诗','yuding','','[]','皎然靈一時，還有屈於詩。世豈無英主，天何惜大師。',48,'御定全唐詩/json/838.json','["皎然靈一時，還有屈於詩。世豈無英主，天何惜大師。", "道終歸正始，心莫問多岐。覽卷堪驚立，貞風喜未衰。"]'),
('yuding-72','夏雨','齊己','唐','御定全唐诗','yuding','','[]','霮zw蔽穹蒼，冥蒙自一方。當時消酷毒，隨處有清涼。',145,'御定全唐詩/json/838.json','["霮zw蔽穹蒼，冥蒙自一方。當時消酷毒，隨處有清涼。", "著物聲雖暴，滋農潤即長。乍紅縈急電，微白露殘陽。", "應禱尤難得，經旬甚不妨。吟聽喧竹樹，立見漲池塘。", "眾類聲休出，群峰色盡藏。頹沱來洞壑，汗漫入瀟湘。", "下葉黎甿望，高袪旱暵光。幽齋飄臥簟，極浦灑歸檣。", "蘚在階從濕，花衰苑任傷。閑思濟時力，歌詠發哀腸。"]'),
('yuding-73','謝興公上人寄山水簇子','齊己','唐','御定全唐诗','yuding','','[]','半幅古潺顏，看來心意閑。何須尋鳥道，即此出人間。',48,'御定全唐詩/json/838.json','["半幅古潺顏，看來心意閑。何須尋鳥道，即此出人間。", "巘暮疑啼狖，松深認掩關。知君遠相惠，免我憶歸山。"]'),
('yuding-74','酬微上人','齊己','唐','御定全唐诗','yuding','','[]','古律皆深妙，新吟複造微。搜難窮月窟，琢苦盡天機。',48,'御定全唐詩/json/838.json','["古律皆深妙，新吟複造微。搜難窮月窟，琢苦盡天機。", "晚檜清蟬咽，寒江白鳥飛。他年舊山去，為子遠攜歸。"]'),
('yuding-75','同光歲送人及第東歸','齊己','唐','御定全唐诗','yuding','','[]','西笑道何光，新朝舊桂堂。春官如白傅，內試似文皇。',48,'御定全唐詩/json/838.json','["西笑道何光，新朝舊桂堂。春官如白傅，內試似文皇。", "變化龍三十，升騰鳳一行。還家幾多興，滿袖月中香。"]'),
('yuding-76','寄江居耿處士','齊己','唐','御定全唐诗','yuding','','[]','野癖雖相似，生涯即不同。紅霞禪石上，明月釣船中。',48,'御定全唐詩/json/838.json','["野癖雖相似，生涯即不同。紅霞禪石上，明月釣船中。", "醉倒蘆花白，吟緣蓼岸紅。相思何以寄，吾道本空空。"]'),
('yuding-77','病起二首','齊己','唐','御定全唐诗','yuding','','[]','一臥四十日，起來秋氣深。已甘長逝魄，還見舊交心。',96,'御定全唐詩/json/838.json','["一臥四十日，起來秋氣深。已甘長逝魄，還見舊交心。", "撐拄筇猶重，枝梧力未任。終將此形陋，歸死故丘林。", "秋風已傷骨，更帶竹聲吹。抱疾關門久，扶羸傍砌時。", "無生即不可，有死必相隨。除卻歸真覺，何由擬免之。"]'),
('yuding-78','送中觀進公歸巴陵','齊己','唐','御定全唐诗','yuding','','[]','一論破雙空，持行大國中。不知從此去，何處挫邪宗。',48,'御定全唐詩/json/838.json','["一論破雙空，持行大國中。不知從此去，何處挫邪宗。", "晝雨懸帆黑，殘陽泊島紅。應遊到灉岸，相憶繞茶叢。"]'),
('yuding-0','寄鄭谷郎中','齊己','唐','御定全唐诗','yuding','','[]','高名喧省闥，雅頌出吾唐。疊巘供秋望，無雲到夕陽。',48,'御定全唐詩/json/839.json','["高名喧省闥，雅頌出吾唐。疊巘供秋望，無雲到夕陽。", "自封修藥院，別掃著僧床。幾夢中朝事，依依鵷鷺行。"]'),
('yuding-1','歸雁','齊己','唐','御定全唐诗','yuding','','[]','塞門春已暖，連影起蘋風。雲夢千行去，瀟湘一夜空。',48,'御定全唐詩/json/839.json','["塞門春已暖，連影起蘋風。雲夢千行去，瀟湘一夜空。", "江人休舉網，虜將又虛弓。莫失南來伴，衡陽樹即紅。"]'),
('yuding-2','登大林寺觀白太傅題版','齊己','唐','御定全唐诗','yuding','','[]','九疊蒼崖裏，禪家鑿翠開。清時誰夢到，白傅獨尋來。',48,'御定全唐詩/json/839.json','["九疊蒼崖裏，禪家鑿翠開。清時誰夢到，白傅獨尋來。", "怪石和僧定，閑雲共鶴回。任茲休去者，心是不然灰。"]'),
('yuding-3','贈曹松先輩','齊己','唐','御定全唐诗','yuding','','[]','今歲赴春闈，達如夫子稀。山中把卷去，榜下注官歸。',48,'御定全唐詩/json/839.json','["今歲赴春闈，達如夫子稀。山中把卷去，榜下注官歸。", "楚月吟前落，江禽酒外飛。閒遊向諸寺，卻看白麻衣。"]'),
('yuding-4','夏日江寺寄無上人','齊己','唐','御定全唐诗','yuding','','[]','講終齋磬罷，何處稱真心。古寺高杉下，炎天獨院深。',48,'御定全唐詩/json/839.json','["講終齋磬罷，何處稱真心。古寺高杉下，炎天獨院深。", "燕和江鳥語，牆奪暮花陰。大府多才子，閑過在竹林。"]'),
('yuding-5','夏日梅雨中寄睦公','齊己','唐','御定全唐诗','yuding','','[]','梅月來林寺，冥冥各閉門。已應雙履跡，全沒亂雲根。',48,'御定全唐詩/json/839.json','["梅月來林寺，冥冥各閉門。已應雙履跡，全沒亂雲根。", "琢句心無味，看經眼亦昏。何時見清霽，招我憑岩軒。"]'),
('yuding-6','傷鄭谷郎中','齊己','唐','御定全唐诗','yuding','','[]','鐘陵千首作，筆絕亦身終。知落干戈裏，誰家煨燼中。',48,'御定全唐詩/json/839.json','["鐘陵千首作，筆絕亦身終。知落干戈裏，誰家煨燼中。", "吟齋春長蕨，釣渚夜鳴鴻。惆悵秋江月，曾招我看同。"]'),
('yuding-7','臨行題友生壁','齊己','唐','御定全唐诗','yuding','','[]','山衲宜何處，經行避暑深。峰西多古寺，日午亂松陰。',48,'御定全唐詩/json/839.json','["山衲宜何處，經行避暑深。峰西多古寺，日午亂松陰。", "鶴默堪分靜，蟬涼解助吟。殷勤題壁去，秋早此相尋。"]'),
('yuding-8','別東林後回寄修睦','齊己','唐','御定全唐诗','yuding','','[]','昨夜從香社，辭君出薜蘿。晚來巾舄上，已覺俗塵多。',48,'御定全唐詩/json/839.json','["昨夜從香社，辭君出薜蘿。晚來巾舄上，已覺俗塵多。", "遠路縈芳草，遙空共白波。南朝在天末，此去重經過。"]'),
('yuding-9','古松','齊己','唐','御定全唐诗','yuding','','[]','雷電不敢伐，鱗皴勢萬端。蠹依枯節死，蛇入朽根盤。',48,'御定全唐詩/json/839.json','["雷電不敢伐，鱗皴勢萬端。蠹依枯節死，蛇入朽根盤。", "影浸僧禪濕，聲吹鶴夢寒。尋常風雨夜，應有鬼神看。"]'),
('yuding-10','夏日西霞寺書懷寄張逸人','齊己','唐','御定全唐诗','yuding','','[]','人中林下現，名自有閑忙。建業紅塵熱，棲霞白石涼。',48,'御定全唐詩/json/839.json','["人中林下現，名自有閑忙。建業紅塵熱，棲霞白石涼。", "倚身檉幾穩，灑面瀑流香。不似高齋裏，花連竹影長。"]'),
('yuding-11','訪自牧上人不遇','齊己','唐','御定全唐诗','yuding','','[]','然諾竟如何，諸侯見重多。高房度江雨，經月長寒莎。',48,'御定全唐詩/json/839.json','["然諾竟如何，諸侯見重多。高房度江雨，經月長寒莎。", "道本同騷雅，書曾到薜蘿。相尋未相見，危閣望滄波。"]'),
('yuding-12','題東林白蓮','齊己','唐','御定全唐诗','yuding','','[]','大士生兜率，空池滿白蓮。秋風明月下，齋日影堂前。',48,'御定全唐詩/json/839.json','["大士生兜率，空池滿白蓮。秋風明月下，齋日影堂前。", "色後群芳拆，香殊百和燃。誰知不染性，一片好心田。"]'),
('yuding-13','寄懷江西征岷二律師','齊己','唐','御定全唐诗','yuding','','[]','亂後江邊寺，堪懷二律師。幾番新弟子，一樣舊威儀。',48,'御定全唐詩/json/839.json','["亂後江邊寺，堪懷二律師。幾番新弟子，一樣舊威儀。", "院影連春竹，窗聲接雨池。共緣山水癖，久別共題詩。"]'),
('yuding-14','東林作寄金陵知己','齊己','唐','御定全唐诗','yuding','','[]','十八賢真在，時來拂榻看。已知前事遠，更結後人難。',48,'御定全唐詩/json/839.json','["十八賢真在，時來拂榻看。已知前事遠，更結後人難。", "泉滴勝清磬，松香掩白檀。憑君聽朝貴，誰欲厭簪冠。"]'),
('yuding-15','山寺喜道者至','齊己','唐','御定全唐诗','yuding','','[]','閏年春過後，山寺始花開。還有無心者，閑尋此境來。',48,'御定全唐詩/json/839.json','["閏年春過後，山寺始花開。還有無心者，閑尋此境來。", "鳥幽聲忽斷，茶好味重回。知住南岩久，冥心坐綠苔。"]'),
('yuding-16','再游匡山','齊己','唐','御定全唐诗','yuding','','[]','紫霄兼二老，相對倚空寒。久別成衰病，重來更上難。',48,'御定全唐詩/json/839.json','["紫霄兼二老，相對倚空寒。久別成衰病，重來更上難。", "徑危雲母滑，崖旱瀑流幹。目斷嵐煙際，神仙有石壇。"]'),
('yuding-17','贈浙西李推官','齊己','唐','御定全唐诗','yuding','','[]','他皆恃勳貴，君獨愛詩玄。終日秋光裏，無人竹影邊。',48,'御定全唐詩/json/839.json','["他皆恃勳貴，君獨愛詩玄。終日秋光裏，無人竹影邊。", "東樓生倚月，北固積吟煙。聞說鴛行裏，多才複少年。"]'),
('yuding-18','題終南山隱者室','齊己','唐','御定全唐诗','yuding','','[]','終南山北面，直下是長安。自掃青苔室，閑欹白石看。',48,'御定全唐詩/json/839.json','["終南山北面，直下是長安。自掃青苔室，閑欹白石看。", "風吹窗樹老，日曬竇雲幹。時向圭峰宿，僧房瀑布寒。"]'),
('yuding-19','禪庭蘆竹十二韻呈鄭谷郎中','齊己','唐','御定全唐诗','yuding','','[]','錯錯在禪庭，高宜與竹名。健添秋雨響，幹助夜風清。',144,'御定全唐詩/json/839.json','["錯錯在禪庭，高宜與竹名。健添秋雨響，幹助夜風清。", "雀靜知枯折，僧閑見筍生。對吟殊灑落，負氣甚孤貞。", "密謝編欄固，齊由灌溉平。松姿真可敵，柳態薄難並。", "映帶兼苔石，參差近畫楹。雪霜消後色，蟲鳥默時聲。", "遠憶滄洲岸，寒連暮角城。幽根狂亂迸，勁葉動相撐。", "避暑須臨坐，逃眠必繞行。未逢仙手詠，俗眼見猶輕。"]'),
('yuding-20','送孫鳳秀才赴舉','齊己','唐','御定全唐诗','yuding','','[]','九重方側席，四海仰文明。好把孤吟去，便隨公道行。',48,'御定全唐詩/json/839.json','["九重方側席，四海仰文明。好把孤吟去，便隨公道行。", "梁園浮雪氣，汴水漲春聲。此日登仙眾，君應最後生。"]'),
('yuding-21','落花','齊己','唐','御定全唐诗','yuding','','[]','朝開暮亦衰，雨打複風吹。古屋無人處，殘陽滿地時。',48,'御定全唐詩/json/839.json','["朝開暮亦衰，雨打複風吹。古屋無人處，殘陽滿地時。", "靜依青蘚片，閑綴綠莎枝。繁豔根枝在，明年向此期。"]'),
('yuding-22','秋苔','齊己','唐','御定全唐诗','yuding','','[]','獨憐蒼翠文，長與寂寥存。鶴靜窺秋片，僧閑踏冷痕。',48,'御定全唐詩/json/839.json','["獨憐蒼翠文，長與寂寥存。鶴靜窺秋片，僧閑踏冷痕。", "月明疏竹徑，雨歇敗莎根。別有深宮裏，兼花鎖斷魂。"]'),
('yuding-23','老將','齊己','唐','御定全唐诗','yuding','','[]','破虜與平戎，曾居第一功。明時不用武，白首向秋風。',48,'御定全唐詩/json/839.json','["破虜與平戎，曾居第一功。明時不用武，白首向秋風。", "馬病霜飛草，弓閑雁過空。兒孫已成立，膽氣亦英雄。"]'),
('yuding-24','城中示友人','齊己','唐','御定全唐诗','yuding','','[]','久與寒灰合，人中亦覺閑。重城不鎖夢，每夜自歸山。',48,'御定全唐詩/json/839.json','["久與寒灰合，人中亦覺閑。重城不鎖夢，每夜自歸山。", "雨破冥鴻出，桐枯井月還。唯君道心在，來往寂寥間。"]'),
('yuding-25','送友人游湘中','齊己','唐','御定全唐诗','yuding','','[]','懷才難自住，此去亦如僧。何處西風夜，孤吟旅舍燈。',48,'御定全唐詩/json/839.json','["懷才難自住，此去亦如僧。何處西風夜，孤吟旅舍燈。", "路沿湘樹疊，山入楚雲層。若有東來劄，歸鴻亦可憑。"]'),
('yuding-26','經費征君舊居','齊己','唐','御定全唐诗','yuding','','[]','高眠當聖代，雲鳥未為孤。天子征不起，閒人親得無。',48,'御定全唐詩/json/839.json','["高眠當聖代，雲鳥未為孤。天子征不起，閒人親得無。", "猿猱狂欲墜，水石怪難圖。寂寞荒齋外，松杉相倚枯。"]'),
('yuding-27','嚴陵釣台','齊己','唐','御定全唐诗','yuding','','[]','夫子垂竿處，空江照古台。無人更如此，白浪自成堆。',48,'御定全唐詩/json/839.json','["夫子垂竿處，空江照古台。無人更如此，白浪自成堆。", "鶴靜尋僧去，魚狂入海回。登臨秋值晚，樹石盡多苔。"]'),
('yuding-28','原上晚望','齊己','唐','御定全唐诗','yuding','','[]','倚杖聊攄望，寒原遠近分。夜來何處火，燒出古人墳。',48,'御定全唐詩/json/839.json','["倚杖聊攄望，寒原遠近分。夜來何處火，燒出古人墳。", "野勢盤空澤，江流合暮雲。殘陽催百鳥，各自著棲群。"]'),
('yuding-29','送惠空上人歸','齊己','唐','御定全唐诗','yuding','','[]','塵中名利熱，鳥外水雲閑。吾子多高趣，秋風獨自還。',48,'御定全唐詩/json/839.json','["塵中名利熱，鳥外水雲閑。吾子多高趣，秋風獨自還。", "空囊隨客棹，幾宿泊湖山。應有吟僧在，鄰居樹影間。"]'),
('yuding-30','酬章水知己','齊己','唐','御定全唐诗','yuding','','[]','新吟忽有寄，千里到荊門。落日雲初碧，殘年眼正昏。',48,'御定全唐詩/json/839.json','["新吟忽有寄，千里到荊門。落日雲初碧，殘年眼正昏。", "已為難敵手，誰更入深論。後信多相寄，吾生重此言。"]'),
('yuding-31','閒居','齊己','唐','御定全唐诗','yuding','','[]','漸覺春光媚，塵銷作土膏。微寒放楊柳，纖草入風騷。',48,'御定全唐詩/json/839.json','["漸覺春光媚，塵銷作土膏。微寒放楊柳，纖草入風騷。", "睡少全無病，身輕乍去袍。前溪泛紅片，何處落金桃。"]'),
('yuding-32','次韻酬鄭谷郎中','齊己','唐','御定全唐诗','yuding','','[]','林下高眠起，相招得句時。開門流水入，靜話鷺鷥知。',48,'御定全唐詩/json/839.json','["林下高眠起，相招得句時。開門流水入，靜話鷺鷥知。", "每許題成晚，多嫌雪阻期。西齋坐來久，風竹撼疏籬。"]'),
('yuding-33','思游峨嵋寄林下諸友','齊己','唐','御定全唐诗','yuding','','[]','剛有峨嵋念，秋來錫欲飛。會拋湘寺去，便逐蜀帆歸。',48,'御定全唐詩/json/839.json','["剛有峨嵋念，秋來錫欲飛。會拋湘寺去，便逐蜀帆歸。", "難世堪言善，閒人合見機。殷勤別諸友，莫厭楚江薇。"]'),
('yuding-34','送劉秀才南游','齊己','唐','御定全唐诗','yuding','','[]','南去謁諸侯，名山亦得遊。便應尋瀑布，乘興上岣嶁。',48,'御定全唐詩/json/839.json','["南去謁諸侯，名山亦得遊。便應尋瀑布，乘興上岣嶁。", "高鳥隨雲起，寒星向地流。相思應北望，天晚石橋頭。"]'),
('yuding-35','示諸侄','齊己','唐','御定全唐诗','yuding','','[]','莫問年將朽，加餐已不多。形容渾瘦削，行止強牽拖。',48,'御定全唐詩/json/839.json','["莫問年將朽，加餐已不多。形容渾瘦削，行止強牽拖。", "死也何憂惱，生而有詠歌。侯門終謝去，卻掃舊松蘿。"]'),
('yuding-36','荊渚病中，因思匡廬，遂成三百字，寄梁先輩','齊己','唐','御定全唐诗','yuding','','[]','生老病死者，早聞天竺書。相隨幾汩沒，不了堪欷歔。',360,'御定全唐詩/json/839.json','["生老病死者，早聞天竺書。相隨幾汩沒，不了堪欷歔。", "自理自可適，他人誰與袪。應當入寂滅，乃得長銷除。", "前月已骨立，今朝還貌舒。披衣試步履，倚策聊躊躇。", "江月青眸冷，秋風白髮疏。新題憶剡硾，舊約懷匡廬。", "張野久絕跡，樂天曾卜居。空龕掩薜荔，瀑布噴蟾蜍。", "古檜鳴玄鶴，涼泉躍錦魚。狂吟樹蔭映，縱踏花蔫煙。", "唇舌既已閑，心脾亦散攄。松窗有偃息，石徑無趑趄。", "夢冷通仙闕，神融合太虛。千峰杳靄際，萬壑明清初。", "長往期非晚，半生閑有餘。依劉未是詠，訪戴甯忘諸。", "稽古堪求己，觀時好笑渠。埋頭逐小利，沒腳拖長裾。", "道種將閑養，情田把藥鉏。幽香發蘭蕙，穢莽摧丘墟。", "敢謂囊盈物，那言庾滿儲。微煙動晨爨，細雨滋園蔬。", "蘚亂珍禽羽，門稀長者車。冥機坐兀兀，著履行徐徐。", "每許親朱履，多憐奉隼旟。簪嫌紅玳瑁，社念金芙蕖。", "海內競鐵馬，篋中藏紙驢。常言謝時去，此意將何如。"]'),
('yuding-37','竟陵遇晝公','齊己','唐','御定全唐诗','yuding','','[]','高跡何來此，游方漸老身。欲投蓮岳夏，初過竟陵春。',48,'御定全唐詩/json/839.json','["高跡何來此，游方漸老身。欲投蓮岳夏，初過竟陵春。", "錫影離雲遠，衣痕拂蘚新。無言即相別，此處不迷津。"]'),
('yuding-38','聞貫休下世','齊己','唐','御定全唐诗','yuding','','[]','吾師詩匠者，真個碧雲流。爭得梁太子，重為文選樓。',48,'御定全唐詩/json/839.json','["吾師詩匠者，真個碧雲流。爭得梁太子，重為文選樓。", "錦江新塚樹，婺女舊山秋。欲去焚香禮，啼猿峽阻修。"]'),
('yuding-39','金山寺','齊己','唐','御定全唐诗','yuding','','[]','山帶金名遠，樓臺壓翠層。魚龍光照像，風浪影搖燈。',48,'御定全唐詩/json/839.json','["山帶金名遠，樓臺壓翠層。魚龍光照像，風浪影搖燈。", "檻外揚州樹，船通建業僧。塵埃何所到，青石坐如冰。"]'),
('yuding-40','早秋雨後晚望','齊己','唐','御定全唐诗','yuding','','[]','暑氣時將薄，蟲聲夜轉稠。江湖經一雨，日月換新秋。',48,'御定全唐詩/json/839.json','["暑氣時將薄，蟲聲夜轉稠。江湖經一雨，日月換新秋。", "有景堪援筆，何人未上樓。欲承涼冷興，西向碧嵩遊。"]'),
('yuding-41','過西塞山','齊己','唐','御定全唐诗','yuding','','[]','空江平野流，風島葦颼颼。殘日銜西塞，孤帆向北洲。',48,'御定全唐詩/json/839.json','["空江平野流，風島葦颼颼。殘日銜西塞，孤帆向北洲。", "邊鴻渡漢口，楚樹出吳頭。終入高雲裏，身依片石休。"]'),
('yuding-42','溪齋二首','齊己','唐','御定全唐诗','yuding','','[]','豈敢言招隱，歸休喜自安。一溪雲臥穩，四海路行難。',96,'御定全唐詩/json/839.json','["豈敢言招隱，歸休喜自安。一溪雲臥穩，四海路行難。", "瑞獸藏頭角，幽禽惜羽翰。子猷何處在，老盡碧琅玕。", "杉竹映溪關，修修共歲寒。幽人眠日晏，花雨落春殘。", "道妙言何強，詩玄論甚難。閒居有親賦，搔首憶潘安。"]'),
('yuding-43','新秋','齊己','唐','御定全唐诗','yuding','','[]','始驚三伏盡，又遇立秋時。露彩朝還冷，雲峰晚更奇。',48,'御定全唐詩/json/839.json','["始驚三伏盡，又遇立秋時。露彩朝還冷，雲峰晚更奇。", "壟香禾半熟，原迥草微衰。幸好清光裏，安仁謾起悲。"]'),
('yuding-44','寄上荊渚，因夢廬嶽，乃圖壁賦詩','齊己','唐','御定全唐诗','yuding','','[]','夢繞嵯峨裏，神疏骨亦寒。覺來誰共說，壁上自圖看。',48,'御定全唐詩/json/839.json','["夢繞嵯峨裏，神疏骨亦寒。覺來誰共說，壁上自圖看。", "古翠松藏寺，春紅杏濕壇。歸心幾時遂，日向漸衰殘。"]'),
('yuding-45','己卯歲值凍阻歸有作','齊己','唐','御定全唐诗','yuding','','[]','河冰連地凍，朔氣壓春寒。開戶思歸遠，出門移步難。',48,'御定全唐詩/json/839.json','["河冰連地凍，朔氣壓春寒。開戶思歸遠，出門移步難。", "湖雲黏雁重，廟樹颳風幹。坐看孤燈焰，微微向曉殘。"]'),
('yuding-46','送盧說亂後投知己','齊己','唐','御定全唐诗','yuding','','[]','兵寇殘江墅，生涯盡蕩除。事堪煎桂玉，時莫倚詩書。',48,'御定全唐詩/json/839.json','["兵寇殘江墅，生涯盡蕩除。事堪煎桂玉，時莫倚詩書。", "暮狖啼空半，春山列雨餘。舟中有新作，回寄示慵疏。"]'),
('yuding-47','讀峴山碑','齊己','唐','御定全唐诗','yuding','','[]','三載羊公政，千年峴首碑。何人更墮淚，此道亦殊時。',48,'御定全唐詩/json/839.json','["三載羊公政，千年峴首碑。何人更墮淚，此道亦殊時。", "兵火燒文缺，江雲觸蘚滋。那堪望黎庶，匝地是瘡痍。"]'),
('yuding-48','過鹿門作','齊己','唐','御定全唐诗','yuding','','[]','鹿門埋孟子，峴首載羊公。萬古千秋裏，青山明月中。',48,'御定全唐詩/json/839.json','["鹿門埋孟子，峴首載羊公。萬古千秋裏，青山明月中。", "政從襄沔絕，詩過洞庭空。塵路誰回眼，松聲兩處風。"]'),
('yuding-49','題玉泉寺大師影堂','齊己','唐','御定全唐诗','yuding','','[]','大化終華頂，靈蹤示玉泉。由來負高尚，合向好山川。',48,'御定全唐詩/json/839.json','["大化終華頂，靈蹤示玉泉。由來負高尚，合向好山川。", "洞壑藏諸怪，杉松列瘦煙。千秋空樹影，猶似覆長禪。"]'),
('yuding-50','秋日錢塘作','齊己','唐','御定全唐诗','yuding','','[]','秋光明水國，遊子倚長亭。海浸全吳白，山澄百越青。',48,'御定全唐詩/json/839.json','["秋光明水國，遊子倚長亭。海浸全吳白，山澄百越青。", "英雄貴黎庶，封土絕精靈。句踐魂如在，應懸戰血腥。"]'),
('yuding-51','送人赴舉','齊己','唐','御定全唐诗','yuding','','[]','分有爭忘得，時來須出山。白雲終許在，清世莫空還。',48,'御定全唐詩/json/839.json','["分有爭忘得，時來須出山。白雲終許在，清世莫空還。", "驛樹秋聲健，行衣雨點斑。明年從月裏，滿握度春關。"]'),
('yuding-52','友人寒夜所寄','齊己','唐','御定全唐诗','yuding','','[]','通宵亦孤坐，但念舊峰雲。白日還如此，清閒本共君。',48,'御定全唐詩/json/839.json','["通宵亦孤坐，但念舊峰雲。白日還如此，清閒本共君。", "二毛凋一半，百歲去三分。早晚尋流水，同歸麋鹿群。"]'),
('yuding-53','酬洞庭陳秀才','齊己','唐','御定全唐诗','yuding','','[]','何必要識面，見詩驚苦心。此門從自古，難學至如今。',48,'御定全唐詩/json/839.json','["何必要識面，見詩驚苦心。此門從自古，難學至如今。", "青草湖雲闊，黃陵廟木深。精搜當好景，得即動知音。"]'),
('yuding-54','題鶴鳴泉八韻','齊己','唐','御定全唐诗','yuding','','[]','嘹唳遺蹤去，澄明物掩難。噴開山面碧，飛落寺門寒。',96,'御定全唐詩/json/839.json','["嘹唳遺蹤去，澄明物掩難。噴開山面碧，飛落寺門寒。", "汲引隨瓶滿，分流逐處安。幽蟲乘葉過，渴狖擁條看。", "上有危峰疊，旁宜怪石盤。冷吞雙樹影，甘潤百毛端。", "異早聞鐫玉，靈終別建壇。瀟湘在何處，終日自波瀾。"]'),
('yuding-55','登金山寺','齊己','唐','御定全唐诗','yuding','','[]','四面白波聲，中流翠嶠橫。望來堪目斷，上徹始心平。',48,'御定全唐詩/json/839.json','["四面白波聲，中流翠嶠橫。望來堪目斷，上徹始心平。", "鳥向天涯去，雲連水國生。重來與誰約，題罷自吟行。"]'),
('yuding-56','寄吳都沈員外彬','齊己','唐','御定全唐诗','yuding','','[]','歸休興若何，朱紱盡還他。自有園林闊，誰爭山水多。',48,'御定全唐詩/json/839.json','["歸休興若何，朱紱盡還他。自有園林闊，誰爭山水多。", "村煙晴莽蒼，僧磬晚嵯峨。野醉題招隱，相思可寄麼。"]'),
('yuding-57','寄明月山僧','齊己','唐','御定全唐诗','yuding','','[]','山稱明月好，月出遍山明。要上諸峰去，無妨半夜行。',48,'御定全唐詩/json/839.json','["山稱明月好，月出遍山明。要上諸峰去，無妨半夜行。", "白猿真雪色，幽鳥古琴聲。吾子居來久，應忘我在城。"]'),
('yuding-58','寄哭西川壇長廣濟大師','齊己','唐','御定全唐诗','yuding','','[]','千萬僧中寶，三朝帝寵身。還源未化火，舉國葬全真。',48,'御定全唐詩/json/839.json','["千萬僧中寶，三朝帝寵身。還源未化火，舉國葬全真。", "文集編金在，碑銘刻玉新。有誰於異代，彈指禮遺塵。"]'),
('yuding-59','酬西川楚巒上人卷','齊己','唐','御定全唐诗','yuding','','[]','玉壘峨嵋秀，岷江錦水清。古人搜不盡，吾子得何精。',48,'御定全唐詩/json/839.json','["玉壘峨嵋秀，岷江錦水清。古人搜不盡，吾子得何精。", "可信由前習，堪聞正後生。東西五千里，多謝寄無成。"]'),
('yuding-60','覽延棲上人卷','齊己','唐','御定全唐诗','yuding','','[]','今體雕鏤妙，古風研考精。何人忘律韻，為子辨詩聲。',48,'御定全唐詩/json/839.json','["今體雕鏤妙，古風研考精。何人忘律韻，為子辨詩聲。", "賈島苦兼此，孟郊清獨行。荊門見編集，愧我老無成。"]'),
('yuding-61','寄洛下王彝訓先輩二首','齊己','唐','御定全唐诗','yuding','','[]','賈島存正始，王維留格言。千篇千古在，一詠一驚魂。',96,'御定全唐詩/json/839.json','["賈島存正始，王維留格言。千篇千古在，一詠一驚魂。", "離別無他寄，相思共此門。陽春堪永恨，郢路轉塵昏。", "北極新英主，高科舊少年。風流傳貴達，談笑取榮遷。", "洛水秋空底，嵩峰曉翠巔。尋常誰並馬，橋上戲成篇。"]'),
('yuding-62','酬岳陽李主簿卷','齊己','唐','御定全唐诗','yuding','','[]','把卷思高興，瀟湘闊浸門。無雲生翠浪，有月動清魂。',48,'御定全唐詩/json/839.json','["把卷思高興，瀟湘闊浸門。無雲生翠浪，有月動清魂。", "倚檻應窮底，凝情合到源。為君吟所寄，難甚至忘筌。"]'),
('yuding-63','寄懷江西僧達禪翁','齊己','唐','御定全唐诗','yuding','','[]','長憶舊山日，與君同聚沙。未能精貝葉，便學詠楊花。',48,'御定全唐詩/json/839.json','["長憶舊山日，與君同聚沙。未能精貝葉，便學詠楊花。", "苦甚傷心骨，清還切齒牙。何妨繼餘習，前世是詩家。"]'),
('yuding-64','送吳守明先輩游蜀','齊己','唐','御定全唐诗','yuding','','[]','憑君遊蜀去，細為話幽奇。喪亂嘉陵驛，塵埃賈島詩。',48,'御定全唐詩/json/839.json','["憑君遊蜀去，細為話幽奇。喪亂嘉陵驛，塵埃賈島詩。", "未應過錦府，且合上峨嵋。既逐高科後，東西任所之。"]'),
('yuding-65','寄普明大師可准','齊己','唐','御定全唐诗','yuding','','[]','蓮嶽三征者，論詩舊與君。相留曾幾歲，酬唱有新文。',48,'御定全唐詩/json/839.json','["蓮嶽三征者，論詩舊與君。相留曾幾歲，酬唱有新文。", "翠竇容閑憩，嵐峰許共分。當年若同訪，合得伴吟雲。"]'),
('yuding-66','還黃平素秀才卷','齊己','唐','御定全唐诗','yuding','','[]','求己甚忘筌，得之經渾然。僻能離詭差，清不尚妖妍。',48,'御定全唐詩/json/839.json','["求己甚忘筌，得之經渾然。僻能離詭差，清不尚妖妍。", "冷澹聞姚監，精奇見浪仙。如君好風格，自可繼前賢。"]'),
('yuding-67','與張先輩話別','齊己','唐','御定全唐诗','yuding','','[]','為□□□者，各自話離心。及第還全蜀，游方歸二林。',48,'御定全唐詩/json/839.json','["為□□□者，各自話離心。及第還全蜀，游方歸二林。", "巴江□□漲，楚野入吳深。他日傳消息，東西不易尋。"]'),
('yuding-68','寄朱拾遺','齊己','唐','御定全唐诗','yuding','','[]','一聞歸闕下，幾番熟金桃。滄海期仍晚，清資路漸高。',48,'御定全唐詩/json/839.json','["一聞歸闕下，幾番熟金桃。滄海期仍晚，清資路漸高。", "研冰濡諫筆，賦雪擁朝袍。豈念空林下，冥心坐石勞。"]'),
('yuding-69','荊門送興禪師','齊己','唐','御定全唐诗','yuding','','[]','灑落南宗子，游方跡似雲。青山尋處處，赤葉路紛紛。',48,'御定全唐詩/json/839.json','["灑落南宗子，游方跡似雲。青山尋處處，赤葉路紛紛。", "虎共松岩宿，猿和石溜聞。何峰一回首，憶我在人群。"]'),
('yuding-70','過西山施肩吾舊居','齊己','唐','御定全唐诗','yuding','','[]','大志終難起，西峰臥翠堆。床前倒秋壑，枕上過春雷。',48,'御定全唐詩/json/839.json','["大志終難起，西峰臥翠堆。床前倒秋壑，枕上過春雷。", "鶴見丹成去，僧聞栗熟來。荒齋松竹老，鸞鶴自裴回。"]'),
('yuding-71','喜夏雨','齊己','唐','御定全唐诗','yuding','','[]','四郊雲影合，千里雨聲來。盡洗紅埃去，並將清氣回。',48,'御定全唐詩/json/839.json','["四郊雲影合，千里雨聲來。盡洗紅埃去，並將清氣回。", "潺湲浮楚甸，蕭散露荊台。欲賦隨車瑞，濡毫渴謏才。"]'),
('yuding-72','酬元員外見寄八韻','齊己','唐','御定全唐诗','yuding','','[]','舊隱夢牽仍，歸心只似蒸。遠青憐島峭，輕白愛雲騰。',96,'御定全唐詩/json/839.json','["舊隱夢牽仍，歸心只似蒸。遠青憐島峭，輕白愛雲騰。", "豔冶叢翻蝶，腥膻地聚蠅。雨聲連灑竹，詩興繼填膺。", "訪戴情彌切，依劉力不勝。眾人忘苦苦，獨自愧兢兢。", "處世無他望，流年有病僧。時慚大雅客，遺韻許相承。"]'),
('yuding-73','浣口泊舟曉望天柱峰','齊己','唐','御定全唐诗','yuding','','[]','根盤潛嶽半，頂逼日輪邊。冷碧無雲點，危棱有瀑懸。',48,'御定全唐詩/json/839.json','["根盤潛嶽半，頂逼日輪邊。冷碧無雲點，危棱有瀑懸。", "秀輕毛女下，名與鼎湖偏。誰見扶持力，峨峨出後天。"]'),
('yuding-74','寄楚萍上人','齊己','唐','御定全唐诗','yuding','','[]','北面香爐秀，南邊瀑布寒。自來還獨去，夏滿又秋殘。',48,'御定全唐詩/json/839.json','["北面香爐秀，南邊瀑布寒。自來還獨去，夏滿又秋殘。", "日影松杉亂，雲容洞壑寬。何峰是鄰側，片石許相安。"]'),
('yuding-75','竹裏作六韻','齊己','唐','御定全唐诗','yuding','','[]','我來深處坐，剩覺有吟思。忽似瀟湘岸，欲生風雨時。',72,'御定全唐詩/json/839.json','["我來深處坐，剩覺有吟思。忽似瀟湘岸，欲生風雨時。", "冷煙蒙古屋，幹籜墮秋墀。徑熟因頻入，身閑得遍欹。", "踏多鞭節損，題亂粉痕隳。猶見前山疊，微茫隔短籬。"]'),
('yuding-76','寄江西幕中孫魴員外','齊己','唐','御定全唐诗','yuding','','[]','簪履為官興，芙蓉結社緣。應思陶令醉，時訪遠公禪。',48,'御定全唐詩/json/839.json','["簪履為官興，芙蓉結社緣。應思陶令醉，時訪遠公禪。", "茶影中殘月，松聲裏落泉。此門曾共說，知未遂終焉。"]'),
('yuding-77','盆池','齊己','唐','御定全唐诗','yuding','','[]','盆沼陷花邊，孤明似玉泉。涵虛心不淺，待月底長圓。',48,'御定全唐詩/json/839.json','["盆沼陷花邊，孤明似玉泉。涵虛心不淺，待月底長圓。", "平穩承天澤，依微泛曙煙。何須照菱鏡，即此鑒媸妍。"]'),
('yuding-78','喜幹晝上人遠相訪','齊己','唐','御定全唐诗','yuding','','[]','彼此垂七十，相逢意若何。聖明殊未至，離亂更應多。',48,'御定全唐詩/json/839.json','["彼此垂七十，相逢意若何。聖明殊未至，離亂更應多。", "澹泊門難到，從容日易過。餘生消息外，只合聽詩魔。"]'),
('yuding-0','過陳陶處士舊居','齊己','唐','御定全唐诗','yuding','','[]','一室貯琴尊，詩皆大雅言。夜過秋竹寺，醉打老僧門。',48,'御定全唐詩/json/840.json','["一室貯琴尊，詩皆大雅言。夜過秋竹寺，醉打老僧門。", "遠燒來籬下，寒蔬簇石根。閒庭除鶴跡，半是杖頭痕。"]'),
('yuding-1','寄敬亭清越','齊己','唐','御定全唐诗','yuding','','[]','敬亭山色古，廟與寺松連。住此修行過，春風四十年。',48,'御定全唐詩/json/840.json','["敬亭山色古，廟與寺松連。住此修行過，春風四十年。", "鼎嘗天柱茗，詩硾剡溪箋。冥目應思著，終南北闕前。"]'),
('yuding-2','湘江漁父','齊己','唐','御定全唐诗','yuding','','[]','湘潭春水滿，岸遠草青青。有客釣煙月，無人論醉醒。',48,'御定全唐詩/json/840.json','["湘潭春水滿，岸遠草青青。有客釣煙月，無人論醉醒。", "門前蛟蜃氣，蓑上蕙蘭馨。曾受蒙莊子，逍遙一卷經。"]'),
('yuding-3','書古寺僧房','齊己','唐','御定全唐诗','yuding','','[]','綠樹深深處，長明焰焰燈。春時遊寺客，花落閉門僧。',48,'御定全唐詩/json/840.json','["綠樹深深處，長明焰焰燈。春時遊寺客，花落閉門僧。", "萬法心中寂，孤泉石上澄。勞生莫相問，喧默不相應。"]'),
('yuding-4','湖西逸人','齊己','唐','御定全唐诗','yuding','','[]','老隱洞庭西，漁樵共一溪。琴前孤鶴影，石上遠僧題。',48,'御定全唐詩/json/840.json','["老隱洞庭西，漁樵共一溪。琴前孤鶴影，石上遠僧題。", "橘柚園林熟，蒹葭徑路迷。君能許鄰並，分藥劚春畦。"]'),
('yuding-5','瀟湘二十韻','齊己','唐','御定全唐诗','yuding','','[]','二水遠難論，從離向坎奔。冷穿千嶂脈，清過幾州門。',240,'御定全唐詩/json/840.json','["二水遠難論，從離向坎奔。冷穿千嶂脈，清過幾州門。", "闊去都凝白，傍來盡帶渾。經游聞舜禹，表裏見乾坤。", "浦靜魚閑釣，灣涼雁自屯。月來分夜底，雲度見秋痕。", "暮氣藏鄰寺，寒濤聒近村。離騷傳永恨，鼓瑟奏遺魂。", "霧擁魚龍窟，槎欹島嶼根。秋風帆上下，落日樹沈昏。", "柳少沙洲缺，苔多古岸存。禽巢依橘柚，獺徑入蘭蓀。", "色自江南絕，名聞海內尊。吳頭雄莫遏，漢口壯堪吞。", "寥泬晴方映，馮夷信忽翻。渡遙峰翠疊，汀小荻花繁。", "勢接湖煙漲，聲和瘴雨噴。急搖吟客舫，狂濺野人樽。", "疏鑿誰窮本，澄鮮自有源。對茲傷九曲，含濁出昆侖。"]'),
('yuding-6','江行早發','齊己','唐','御定全唐诗','yuding','','[]','舟子相呼起，長江未五更。幾看星月在，猶帶夢魂行。',48,'御定全唐詩/json/840.json','["舟子相呼起，長江未五更。幾看星月在，猶帶夢魂行。", "鳥亂村林迥，人喧水柵橫。蒼茫平野外，漸認遠峰名。"]'),
('yuding-7','宜陽道中作','齊己','唐','御定全唐诗','yuding','','[]','宜陽南面路，下嶽又經過。楓葉紅遮店，芒花白滿坡。',48,'御定全唐詩/json/840.json','["宜陽南面路，下嶽又經過。楓葉紅遮店，芒花白滿坡。", "猿無山漸薄，雁眾水還多。日落猶前去，諸村牧豎歌。"]'),
('yuding-8','落日','齊己','唐','御定全唐诗','yuding','','[]','晚照背高臺，殘鐘殘角催。能銷幾度落，已是半生來。',48,'御定全唐詩/json/840.json','["晚照背高臺，殘鐘殘角催。能銷幾度落，已是半生來。", "吹葉陰風發，漫空暝色回。因思古人事，更變盡塵埃。"]'),
('yuding-9','春興','齊己','唐','御定全唐诗','yuding','','[]','柳暖鶯多語，花明草盡長。風流在詩句，牽率繞池塘。',48,'御定全唐詩/json/840.json','["柳暖鶯多語，花明草盡長。風流在詩句，牽率繞池塘。", "叫切禽名宇，飛忙蝶姓莊。時來真可惜，自勉掇蘭芳。"]'),
('yuding-10','遠山','齊己','唐','御定全唐诗','yuding','','[]','天際雲根破，寒山列翠回。幽人當立久，白鳥背飛來。',48,'御定全唐詩/json/840.json','["天際雲根破，寒山列翠回。幽人當立久，白鳥背飛來。", "瀑濺何州地，僧尋幾嶠苔。終須拂巾履，獨去謝塵埃。"]'),
('yuding-11','和鄭谷郎中幽棲之什','齊己','唐','御定全唐诗','yuding','','[]','誰知閑退跡，門徑入寒汀。靜倚雲僧杖，孤看野燒星。',48,'御定全唐詩/json/840.json','["誰知閑退跡，門徑入寒汀。靜倚雲僧杖，孤看野燒星。", "墨沾吟石黑，苔染釣船青。相對唯溪寺，初宵聞念經。"]'),
('yuding-12','勉道林謙光鴻蘊二侄','齊己','唐','御定全唐诗','yuding','','[]','舊林諸侄在，還住本師房。共掃焚修地，同聞水石香。',48,'御定全唐詩/json/840.json','["舊林諸侄在，還住本師房。共掃焚修地，同聞水石香。", "莫將閑世界，擬敵好時光。須看南山下，無名塚滿岡。"]'),
('yuding-13','渚宮自勉二首','齊己','唐','御定全唐诗','yuding','','[]','晨午殊豐足，伊何撓肺腸。形容侵老病，山水憶韜藏。',96,'御定全唐詩/json/840.json','["晨午殊豐足，伊何撓肺腸。形容侵老病，山水憶韜藏。", "必謝金台去，還攜鐵錫將。東林露壇畔，舊對白蓮房。", "畢竟擬何求，隨緣去住休。天涯遊勝境，海上宿仙洲。", "夢好尋無跡，詩成旋不留。從他笑輕事，獨自憶莊周。"]'),
('yuding-14','謝灉湖茶','齊己','唐','御定全唐诗','yuding','','[]','灉湖唯上貢，何以惠尋常。還是詩心苦，堪消蠟面香。',48,'御定全唐詩/json/840.json','["灉湖唯上貢，何以惠尋常。還是詩心苦，堪消蠟面香。", "碾聲通一室，烹色帶殘陽。若有新春者，西來信勿忘。"]'),
('yuding-15','寄歸州馬判官','齊己','唐','御定全唐诗','yuding','','[]','郡帶女媭名，民康境亦寧。晏梳秋鬢白，閑坐暮山青。',48,'御定全唐詩/json/840.json','["郡帶女媭名，民康境亦寧。晏梳秋鬢白，閑坐暮山青。", "贈客椒初熟，尋僧酒半醒。應懷舊居處，歌管隔牆聽。"]'),
('yuding-16','倦客','齊己','唐','御定全唐诗','yuding','','[]','閉眼即開門，人間事倦聞。如何迎好客，不似看閑雲。',48,'御定全唐詩/json/840.json','["閉眼即開門，人間事倦聞。如何迎好客，不似看閑雲。", "少欲資三要，多言讓十分。疏慵本吾性，任笑早離群。"]'),
('yuding-17','送靈z6上人遊五台','齊己','唐','御定全唐诗','yuding','','[]','此去清涼頂，期瞻大聖容。便應過洛水，即未上嵩峰。',48,'御定全唐詩/json/840.json','["此去清涼頂，期瞻大聖容。便應過洛水，即未上嵩峰。", "殘照催行影，幽林惜駐蹤。想登金閣望，東北極兵鋒。"]'),
('yuding-18','靜坐','齊己','唐','御定全唐诗','yuding','','[]','坐臥與行住，入禪還出吟。也應長日月，消得個身心。',48,'御定全唐詩/json/840.json','["坐臥與行住，入禪還出吟。也應長日月，消得個身心。", "默論相如少，黃梅付囑深。門前古松徑，時起步清陰。"]'),
('yuding-19','謝虛中上人寄示題天策閣詩','齊己','唐','御定全唐诗','yuding','','[]','天策二首作，境幽搜亦玄。閣橫三楚上，題掛九霄邊。',48,'御定全唐詩/json/840.json','["天策二首作，境幽搜亦玄。閣橫三楚上，題掛九霄邊。", "寺額因標勝，詩人合遇賢。他時誰倚檻，吟此豈忘筌。"]'),
('yuding-20','荊門寄懷章供奉兼呈幕中知己','齊己','唐','御定全唐诗','yuding','','[]','紫衣居貴上，青衲老關中。事佛門相似，朝天路不同。',48,'御定全唐詩/json/840.json','["紫衣居貴上，青衲老關中。事佛門相似，朝天路不同。", "神凝無惡夢，詩澹老真風。聞道知音在，官高信莫通。"]'),
('yuding-21','江令石','齊己','唐','御定全唐诗','yuding','','[]','思量江令意，愛石甚悠悠。貪向深宮去，死同亡國休。',48,'御定全唐詩/json/840.json','["思量江令意，愛石甚悠悠。貪向深宮去，死同亡國休。", "兩株荒草裏，千古暮江頭。若似黃金貴，隋軍也不留。"]'),
('yuding-22','月下作','齊己','唐','御定全唐诗','yuding','','[]','良夜如清晝，幽人在小庭。滿空垂列宿，那個是文星。',48,'御定全唐詩/json/840.json','["良夜如清晝，幽人在小庭。滿空垂列宿，那個是文星。", "世界歸誰是，心魂向自寧。何當見堯舜，重為造生靈。"]'),
('yuding-23','游道林寺四絕亭，觀宋杜詩版','齊己','唐','御定全唐诗','yuding','','[]','宋杜詩題在，風騷到此真。獨來終日看，一為拂秋塵。',48,'御定全唐詩/json/840.json','["宋杜詩題在，風騷到此真。獨來終日看，一為拂秋塵。", "古石生寒仞，春松脫老鱗。高僧眼根靜，應見客吟神。"]'),
('yuding-24','勉詩僧','齊己','唐','御定全唐诗','yuding','','[]','莫把毛生刺，低佪謁李膺。須防知佛者，解笑愛名僧。',48,'御定全唐詩/json/840.json','["莫把毛生刺，低佪謁李膺。須防知佛者，解笑愛名僧。", "道性宜如水，詩情合似冰。還同蓮社客，聯唱繞香燈。"]'),
('yuding-25','謝人墨','齊己','唐','御定全唐诗','yuding','','[]','珍重歲寒煙，攜來路幾千。只應真典誥，消得苦磨研。',48,'御定全唐詩/json/840.json','["珍重歲寒煙，攜來路幾千。只應真典誥，消得苦磨研。", "正色浮端硯，精光動蜀箋。因君強濡染，舍此即忘筌。"]'),
('yuding-26','送人遊玉泉寺','齊己','唐','御定全唐诗','yuding','','[]','西峰大雪開，萬疊向空堆。客貴猶尋去，僧高肯不來。',48,'御定全唐詩/json/840.json','["西峰大雪開，萬疊向空堆。客貴猶尋去，僧高肯不來。", "潭澄猿覷月，竇冷鹿眠苔。公子將才子，聯題興未回。"]'),
('yuding-27','寄鄭谷郎中','齊己','唐','御定全唐诗','yuding','','[]','詩心何以傳，所證自同禪。覓句如探虎，逢知似得仙。',48,'御定全唐詩/json/840.json','["詩心何以傳，所證自同禪。覓句如探虎，逢知似得仙。", "神清太古在，字好雅風全。曾沐星郎許，終慚是斐然。"]'),
('yuding-28','春雨','齊己','唐','御定全唐诗','yuding','','[]','欲布如膏勢，先聞動地雷。雲龍相得起，風電一時來。',48,'御定全唐詩/json/840.json','["欲布如膏勢，先聞動地雷。雲龍相得起，風電一時來。", "霢霂農桑野，冥蒙楊柳台。何人待晴暖，庭有牡丹開。"]'),
('yuding-29','明月峰','齊己','唐','御定全唐诗','yuding','','[]','明月峰頭石，曾聞學月明。別舒長夜彩，高照一村耕。',48,'御定全唐詩/json/840.json','["明月峰頭石，曾聞學月明。別舒長夜彩，高照一村耕。", "頗亂無私理，徒驚鄙俗情。傳雲遭鑿後，頑白在崢嶸。"]'),
('yuding-30','謝人惠紫栗拄杖','齊己','唐','御定全唐诗','yuding','','[]','仙掌峰前得，何當此見遺。百年衰朽骨，六尺歲寒姿。',48,'御定全唐詩/json/840.json','["仙掌峰前得，何當此見遺。百年衰朽骨，六尺歲寒姿。", "雪外兼松憑，泉邊待月欹。他時出山去，猶謝見相隨。"]'),
('yuding-31','送人遊湘湖','齊己','唐','御定全唐诗','yuding','','[]','君游南國去，旅夢若為寧。一路隨鴻雁，千峰繞洞庭。',48,'御定全唐詩/json/840.json','["君游南國去，旅夢若為寧。一路隨鴻雁，千峰繞洞庭。", "林明楓盡落，野黑燒初經。有興尋僧否，湘西寺最靈。"]'),
('yuding-32','小松','齊己','唐','御定全唐诗','yuding','','[]','發地才過膝，蟠根已有靈。嚴霜百草白，深院一林青。',48,'御定全唐詩/json/840.json','["發地才過膝，蟠根已有靈。嚴霜百草白，深院一林青。", "後夜蕭騷動，空階蟋蟀聽。誰于千歲外，吟繞老龍形。"]'),
('yuding-33','金江寓居','齊己','唐','御定全唐诗','yuding','','[]','考盤應未永，聊此養閑疏。野趣今何似，詩題舊不如。',48,'御定全唐詩/json/840.json','["考盤應未永，聊此養閑疏。野趣今何似，詩題舊不如。", "春篁離籜盡，陂藕折花初。終要秋雲是，從風恣卷舒。"]'),
('yuding-34','晚夏金江寓居答友生','齊己','唐','御定全唐诗','yuding','','[]','日日沖殘熱，相尋入亂蒿。閑中滋味遠，詩裏是非高。',48,'御定全唐詩/json/840.json','["日日沖殘熱，相尋入亂蒿。閑中滋味遠，詩裏是非高。", "碧聳新生竹，紅垂半熟桃。時難未可出，且欲淬豪曹。"]'),
('yuding-35','寄李洞秀才','齊己','唐','御定全唐诗','yuding','','[]','到處聽時論，知君屈最深。秋風幾西笑，抱玉但傷心。',48,'御定全唐詩/json/840.json','["到處聽時論，知君屈最深。秋風幾西笑，抱玉但傷心。", "野水翻紅藕，滄江老白禽。相思未相識，聞在蜀中吟。"]'),
('yuding-36','過商山','齊己','唐','御定全唐诗','yuding','','[]','疊疊疊嵐寒，紅塵翠裏盤。前程有名利，此路莫艱難。',48,'御定全唐詩/json/840.json','["疊疊疊嵐寒，紅塵翠裏盤。前程有名利，此路莫艱難。", "雲水侵天老，輪蹄到月殘。何能尋四皓，過盡見長安。"]'),
('yuding-37','蟬八韻','齊己','唐','御定全唐诗','yuding','','[]','咽咽複啾啾，多來自早秋。園林涼正好，風雨思相收。',96,'御定全唐詩/json/840.json','["咽咽複啾啾，多來自早秋。園林涼正好，風雨思相收。", "在處聲無別，何人淚欲流。冷憐天露滴，傷共野禽遊。", "靜息深依竹，驚移瞥過樓。分明晴渡口，淒切暮關頭。", "時節推應定，飛鳴即未休。年年聞爾苦，遠憶所居幽。"]'),
('yuding-38','鷺鷥二首','齊己','唐','御定全唐诗','yuding','','[]','日日滄江去，時時得意歸。自能終潔白，何處誤翻飛。',96,'御定全唐詩/json/840.json','["日日滄江去，時時得意歸。自能終潔白，何處誤翻飛。", "晚立銀塘闊，秋棲玉露微。殘陽葦花畔，雙下釣魚磯。", "雪裏曾迷我，籠中舊養君。忽從紅蓼岸，飛出白鷗群。", "影照翹灘浪，翎濡宿島雲。鴛鴻解相憶，天上列紛紛。"]'),
('yuding-39','送僧歸南嶽','齊己','唐','御定全唐诗','yuding','','[]','濁世住終難，孤峰念永安。逆風眉磔磔，沖雪錫珊珊。',48,'御定全唐詩/json/840.json','["濁世住終難，孤峰念永安。逆風眉磔磔，沖雪錫珊珊。", "石室關霞嫩，松枝拂蘚幹。岩猿應認得，連臂下句欄。"]'),
('yuding-40','夏日林下作','齊己','唐','御定全唐诗','yuding','','[]','煩暑莫相煎，森森在眼前。暫來還盡日，獨坐只聞蟬。',48,'御定全唐詩/json/840.json','["煩暑莫相煎，森森在眼前。暫來還盡日，獨坐只聞蟬。", "草媚終難死，花飛卒未蔫。秋風舍此去，滿篋貯新篇。"]'),
('yuding-41','村居寄懷','齊己','唐','御定全唐诗','yuding','','[]','風雨如堯代，何心欲退藏。諸侯行教化，下國自耕桑。',48,'御定全唐詩/json/840.json','["風雨如堯代，何心欲退藏。諸侯行教化，下國自耕桑。", "道挫時機盡，禪留話路長。前溪久不過，忽覺早禾香。"]'),
('yuding-42','酬王秀才','齊己','唐','御定全唐诗','yuding','','[]','相於分倍親，靜論到吟真。王澤曾無外，風騷甚少人。',48,'御定全唐詩/json/840.json','["相於分倍親，靜論到吟真。王澤曾無外，風騷甚少人。", "鴻隨秋過盡，雪向臘飛頻。何處多幽勝，期君作近鄰。"]'),
('yuding-43','贈無本上人','齊己','唐','御定全唐诗','yuding','','[]','往年吟月社，因亂散揚州。未免無端事，何妨出世流。',48,'御定全唐詩/json/840.json','["往年吟月社，因亂散揚州。未免無端事，何妨出世流。", "洞庭禪過臘，衡嶽坐經秋。終說將衣缽，天臺老去休。"]'),
('yuding-44','寄華山司空圖','齊己','唐','御定全唐诗','yuding','','[]','天下艱難際，全家入華山。幾勞丹詔問，空見使臣還。',48,'御定全唐詩/json/840.json','["天下艱難際，全家入華山。幾勞丹詔問，空見使臣還。", "瀑布寒吹夢，蓮峰翠濕關。兵戈阻相訪，身老瘴雲間。"]'),
('yuding-45','題真州精舍','齊己','唐','御定全唐诗','yuding','','[]','波心精舍好，那岸是繁華。礙目無高樹，當門即遠沙。',48,'御定全唐詩/json/840.json','["波心精舍好，那岸是繁華。礙目無高樹，當門即遠沙。", "晨齋來海客，夜磬到漁家。石鼎秋濤靜，禪回有嶽茶。"]'),
('yuding-46','懷道林寺因寄仁用二上人','齊己','唐','御定全唐诗','yuding','','[]','名山知不遠，長憶寺門松。昨晚登樓見，前年過夏峰。',48,'御定全唐詩/json/840.json','["名山知不遠，長憶寺門松。昨晚登樓見，前年過夏峰。", "雨餘雲腳樹，風外日西鐘。莫更來東岸，紅塵沒馬蹤。"]'),
('yuding-47','尋陽道中作','齊己','唐','御定全唐诗','yuding','','[]','秋聲連嶽樹，草色遍汀洲。多事時為客，無人處上樓。',48,'御定全唐詩/json/840.json','["秋聲連嶽樹，草色遍汀洲。多事時為客，無人處上樓。", "雲疏片雨歇，野闊九江流。欲向南朝去，詩僧有惠休。"]'),
('yuding-48','東林雨後望香爐峰','齊己','唐','御定全唐诗','yuding','','[]','翠濕僧窗裏，寒堆鳥道邊。靜思尋去路，急繞落來泉。',48,'御定全唐詩/json/840.json','["翠濕僧窗裏，寒堆鳥道邊。靜思尋去路，急繞落來泉。", "暮雨開青壁，朝陽照紫煙。二林多長老，誰憶上頭禪。"]'),
('yuding-49','寄雙泉大師師兄','齊己','唐','御定全唐诗','yuding','','[]','清泉流眼底，白道倚岩棱。後夜禪初入，前溪樹折冰。',48,'御定全唐詩/json/840.json','["清泉流眼底，白道倚岩棱。後夜禪初入，前溪樹折冰。", "南涼來的的，北魏去騰騰。敢把吾師意，密傳門外僧。"]'),
('yuding-50','送人潤州尋兄弟','齊己','唐','御定全唐诗','yuding','','[]','君話南徐去，迢迢過建康。弟兄新得信，鴻雁久離行。',48,'御定全唐詩/json/840.json','["君話南徐去，迢迢過建康。弟兄新得信，鴻雁久離行。", "木落空林浪，秋殘漸雪霜。閒遊登北固，東望海蒼蒼。"]'),
('yuding-51','貽張生','齊己','唐','御定全唐诗','yuding','','[]','日日見入寺，未曾含酒容。閑聽老僧語，坐到夕陽鐘。',48,'御定全唐詩/json/840.json','["日日見入寺，未曾含酒容。閑聽老僧語，坐到夕陽鐘。", "竹裏行多影，花邊偶過蹤。猶言謝生計，隨我去孤峰。"]'),
('yuding-52','送人遊雍京','齊己','唐','御定全唐诗','yuding','','[]','君來乞詩別，聊與愴前程。九野未無事，少年何遠行。',48,'御定全唐詩/json/840.json','["君來乞詩別，聊與愴前程。九野未無事，少年何遠行。", "商雲盤翠險，秦甸下煙平。應見周南化，如今在雍京。"]'),
('yuding-53','春草','齊己','唐','御定全唐诗','yuding','','[]','處處碧萋萋，平原帶日西。堪隨遊子路，遠入鷓鴣啼。',48,'御定全唐詩/json/840.json','["處處碧萋萋，平原帶日西。堪隨遊子路，遠入鷓鴣啼。", "金谷園應沒，夫差國已迷。欲尋蘭蕙徑，荒穢滿汀畦。"]'),
('yuding-54','懷華頂道人','齊己','唐','御定全唐诗','yuding','','[]','華頂星邊出，真宜上士家。無人觸床榻，滿屋貯煙霞。',48,'御定全唐詩/json/840.json','["華頂星邊出，真宜上士家。無人觸床榻，滿屋貯煙霞。", "坐臥臨天井，晴明見海涯。禪餘石橋去，屐齒印松花。"]'),
('yuding-55','寄自牧上人','齊己','唐','御定全唐诗','yuding','','[]','五老回無計，三峰去不成。何言謝雲鳥，此地識公卿。',48,'御定全唐詩/json/840.json','["五老回無計，三峰去不成。何言謝雲鳥，此地識公卿。", "夢愧將僧說，心嫌觸類生。南朝古山寺，曾憶共尋行。"]'),
('yuding-56','靜坐','齊己','唐','御定全唐诗','yuding','','[]','日日只騰騰，心機何以興。詩魔苦不利，禪寂頗相應。',48,'御定全唐詩/json/840.json','["日日只騰騰，心機何以興。詩魔苦不利，禪寂頗相應。", "硯滿塵埃點，衣多坐臥棱。如斯自消息，合是個閑僧。"]'),
('yuding-57','送人游衡岳','齊己','唐','御定全唐诗','yuding','','[]','荊楚臘將殘，江湖蒼莽間。孤舟載高興，千里向名山。',48,'御定全唐詩/json/840.json','["荊楚臘將殘，江湖蒼莽間。孤舟載高興，千里向名山。", "雪浪來無定，風帆去是閑。石橋僧問我，應寄嶽茶還。"]'),
('yuding-58','答知己自闕下寄書','齊己','唐','御定全唐诗','yuding','','[]','故人勞劄翰，千里寄荊台。知戀文明在，來尋江漢來。',48,'御定全唐詩/json/840.json','["故人勞劄翰，千里寄荊台。知戀文明在，來尋江漢來。", "群機喧白晝，陸海漲黃埃。得路應相笑，無成守死灰。"]'),
('yuding-59','新筍','齊己','唐','御定全唐诗','yuding','','[]','亂迸苔錢破，參差出小欄。層層離錦籜，節節露琅玕。',48,'御定全唐詩/json/840.json','["亂迸苔錢破，參差出小欄。層層離錦籜，節節露琅玕。", "直上心終勁，四垂煙漸寬。欲知含古律，試剪鳳簫看。"]'),
('yuding-60','寄唐洙處士','齊己','唐','御定全唐诗','yuding','','[]','行僧去湘水，歸雁度荊門。彼此亡家國，東西役夢魂。',48,'御定全唐詩/json/840.json','["行僧去湘水，歸雁度荊門。彼此亡家國，東西役夢魂。", "多慵如長傲，久住不生根。曾問興亡事，丁寧寄勿言。"]'),
('yuding-61','謝人惠竹蠅拂','齊己','唐','御定全唐诗','yuding','','[]','妙刮筠篁制，纖柔玉柄同。拂蠅聲滿室，指月影搖空。',48,'御定全唐詩/json/840.json','["妙刮筠篁制，纖柔玉柄同。拂蠅聲滿室，指月影搖空。", "敢舍經行外，常將宴坐中。揮談一無取，千萬愧生公。"]'),
('yuding-62','新燕','齊己','唐','御定全唐诗','yuding','','[]','燕燕知何事，年年應候來。卻緣華屋在，長得好時催。',48,'御定全唐詩/json/840.json','["燕燕知何事，年年應候來。卻緣華屋在，長得好時催。", "花外銜泥去，空中接食回。不同黃雀意，迷逐網羅媒。"]'),
('yuding-63','謝王先輩寄氈','齊己','唐','御定全唐诗','yuding','','[]','深謝高科客，名氈寄惠重。靜思生朔漠，和雪長蒙茸。',48,'御定全唐詩/json/840.json','["深謝高科客，名氈寄惠重。靜思生朔漠，和雪長蒙茸。", "折坐資禪悅，鋪眠減病容。他年從破碎，擔去臥孤峰。"]'),
('yuding-64','寄還闕下高輦先輩卷','齊己','唐','御定全唐诗','yuding','','[]','去歲逢京使，因還所寄詩。難留天上作，曾換月中枝。',48,'御定全唐詩/json/840.json','["去歲逢京使，因還所寄詩。難留天上作，曾換月中枝。", "趣極僧迷旨，功深鬼不知。仍聞得名後，特地更忘疲。"]'),
('yuding-65','和孫支使惠示院中庭竹之什','齊己','唐','御定全唐诗','yuding','','[]','憶就江僧乞，和煙得一莖。剪黃憎舊本，科綠惜新生。',48,'御定全唐詩/json/840.json','["憶就江僧乞，和煙得一莖。剪黃憎舊本，科綠惜新生。", "護噪蟬身穩，資吟客眼明。星郎有佳詠，雅合此君聲。"]'),
('yuding-66','苦熱中江上，懷爐峰舊居','齊己','唐','御定全唐诗','yuding','','[]','舊寄爐峰下，杉松繞石房。年年五六月，江上憶清涼。',48,'御定全唐詩/json/840.json','["舊寄爐峰下，杉松繞石房。年年五六月，江上憶清涼。", "久別應荒廢，終歸隔渺茫。何當便搖落，披衲玩秋光。"]'),
('yuding-67','送僧游龍門香山寺','齊己','唐','御定全唐诗','yuding','','[]','君到香山寺，探幽莫損神。且尋風雅主，細看樂天真。',24,'御定全唐詩/json/840.json','["君到香山寺，探幽莫損神。且尋風雅主，細看樂天真。"]'),
('yuding-68','江上值春雨','齊己','唐','御定全唐诗','yuding','','[]','江皋正月雨，平陸亦波瀾。半是峨嵋雪，重為澤國寒。',48,'御定全唐詩/json/840.json','["江皋正月雨，平陸亦波瀾。半是峨嵋雪，重為澤國寒。", "農田淹浸盡，客棹往來難。愁殺騷人路，滄浪正渺漫。"]'),
('yuding-69','七十作','齊己','唐','御定全唐诗','yuding','','[]','七十去百歲，都來三十春。縱饒生得到，終免死無因。',48,'御定全唐詩/json/840.json','["七十去百歲，都來三十春。縱饒生得到，終免死無因。", "密理方通理，棲真始見真。沃洲匡阜客，幾劫不迷人。"]'),
('yuding-70','謝虛中寄新詩','齊己','唐','御定全唐诗','yuding','','[]','舊友一千里，新詩五十篇。此文經大匠，不見已多年。',48,'御定全唐詩/json/840.json','["舊友一千里，新詩五十篇。此文經大匠，不見已多年。", "趣極同無跡，精深合自然。相思把行坐，南望隔塵煙。"]'),
('yuding-71','送彬座主赴龍安請講','齊己','唐','御定全唐诗','yuding','','[]','兩論久研精，龍安受請行。春城雨雪霽，古寺殿堂明。',48,'御定全唐詩/json/840.json','["兩論久研精，龍安受請行。春城雨雪霽，古寺殿堂明。", "白髮老僧聽，金毛師子聲。同流有誰共，別著國風清。"]'),
('yuding-72','夏日荊渚書懷','齊己','唐','御定全唐诗','yuding','','[]','嵩嶽去值亂，匡廬回阻兵。中途息瓶錫，十載依公卿。',48,'御定全唐詩/json/840.json','["嵩嶽去值亂，匡廬回阻兵。中途息瓶錫，十載依公卿。", "不那猿鳥性，但懷林泉聲。何時遂情興，吟繞杉松行。"]'),
('yuding-73','春日西湖作','齊己','唐','御定全唐诗','yuding','','[]','一水繞孤島，閑門掩春草。曾無長者轍，枉此問衰老。',24,'御定全唐詩/json/840.json','["一水繞孤島，閑門掩春草。曾無長者轍，枉此問衰老。"]'),
('yuding-74','謝中上人寄茶','齊己','唐','御定全唐诗','yuding','','[]','春山谷雨前，並手摘芳煙。綠嫩難盈籠，清和易晚天。',48,'御定全唐詩/json/840.json','["春山谷雨前，並手摘芳煙。綠嫩難盈籠，清和易晚天。", "且招鄰院客，試煮落花泉。地遠勞相寄，無來又來年。"]'),
('yuding-75','送節大德歸闕','齊己','唐','御定全唐诗','yuding','','[]','西京曾入內，東洛又朝天。聖上方虛席，僧中正乏賢。',48,'御定全唐詩/json/840.json','["西京曾入內，東洛又朝天。聖上方虛席，僧中正乏賢。", "晨光金殿裏，紫氣玉簾前。知祝唐堯化，新恩異往年。"]'),
('yuding-76','覽清尚卷','齊己','唐','御定全唐诗','yuding','','[]','李洞僻相似，得詩先示師。鬼神迷去處，風日背吟時。',48,'御定全唐詩/json/840.json','["李洞僻相似，得詩先示師。鬼神迷去處，風日背吟時。", "格已搜清竭，名還著紫卑。從容味高作，翻為古人疑。"]'),
('yuding-77','荊門送晝公歸彭澤舊居','齊己','唐','御定全唐诗','yuding','','[]','彭澤舊居在，匡廬翠疊前。因思從楚寺，便附入吳船。',48,'御定全唐詩/json/840.json','["彭澤舊居在，匡廬翠疊前。因思從楚寺，便附入吳船。", "岸繞春殘樹，江浮曉霽天。應過虎溪社，佇立想諸賢。"]'),
('yuding-0','登祝融峰','齊己','唐','御定全唐诗','yuding','','[]','猿鳥共不到，我來身欲浮。四邊空碧落，絕頂正清秋。',48,'御定全唐詩/json/841.json','["猿鳥共不到，我來身欲浮。四邊空碧落，絕頂正清秋。", "宇宙知何極，華夷見細流。壇西獨立久，白日轉神州。"]'),
('yuding-1','寄貫休','齊己','唐','御定全唐诗','yuding','','[]','子美曾吟處，吾師複去吟。是何多勝地，銷得二公心。',48,'御定全唐詩/json/841.json','["子美曾吟處，吾師複去吟。是何多勝地，銷得二公心。", "錦水流春闊，峨嵋疊雪深。時逢蜀僧說，或道近遊黔。"]'),
('yuding-2','送唐稟正字歸萍川','齊己','唐','御定全唐诗','yuding','','[]','霜須芸閣吏，久掩白雲扉。來謁元戎後，還騎病馬歸。',48,'御定全唐詩/json/841.json','["霜須芸閣吏，久掩白雲扉。來謁元戎後，還騎病馬歸。", "煙村蔬飲淡，江驛雪泥肥。知到中林日，春風長澗薇。"]'),
('yuding-3','寄懷江西棲公','齊己','唐','御定全唐诗','yuding','','[]','龍沙為別日，廬阜得書年。不見來香社，相思繞白蓮。',48,'御定全唐詩/json/841.json','["龍沙為別日，廬阜得書年。不見來香社，相思繞白蓮。", "江僧歸海寺，楚路接吳煙。老病何堪說，扶羸寄此篇。"]'),
('yuding-4','山中喜得友生書','齊己','唐','御定全唐诗','yuding','','[]','柴門關樹石，未省夢塵埃。落日啼猿裏，同人有信來。',48,'御定全唐詩/json/841.json','["柴門關樹石，未省夢塵埃。落日啼猿裏，同人有信來。", "自成為拙隱，難以謝多才。見說相思處，前峰對古台。"]'),
('yuding-5','謝人惠扇子及茶','齊己','唐','御定全唐诗','yuding','','[]','槍旗封蜀茗，圓潔制鮫綃。好客分烹煮，青蠅避動搖。',48,'御定全唐詩/json/841.json','["槍旗封蜀茗，圓潔制鮫綃。好客分烹煮，青蠅避動搖。", "陸生誇妙法，班女恨涼飆。多謝崔居士，相思寄寂寥。"]'),
('yuding-6','寄監利司空學士','齊己','唐','御定全唐诗','yuding','','[]','詩家為政別，清苦日聞新。亂後無荒地，歸來盡遠人。',48,'御定全唐詩/json/841.json','["詩家為政別，清苦日聞新。亂後無荒地，歸來盡遠人。", "寬容民賦稅，憔悴吏精神。何必河陽縣，空傳桃李春。"]'),
('yuding-7','答陳秀才','齊己','唐','御定全唐诗','yuding','','[]','萬事皆可了，有詩門最深。古人難得志，吾子苦留心。',48,'御定全唐詩/json/841.json','["萬事皆可了，有詩門最深。古人難得志，吾子苦留心。", "野疊涼雲朵，苔重怪木陰。他年立名字，笑我老雙林。"]'),
('yuding-8','遊橘洲','齊己','唐','御定全唐诗','yuding','','[]','春日上芳洲，經春蘭杜幽。此時尋橘岸，昨日在城樓。',48,'御定全唐詩/json/841.json','["春日上芳洲，經春蘭杜幽。此時尋橘岸，昨日在城樓。", "鷺立青楓杪，沙沈白浪頭。漁家好生計，簷底系扁舟。"]'),
('yuding-9','寄武陵道友','齊己','唐','御定全唐诗','yuding','','[]','阮肇迷仙處，禪門接紫霞。不知尋鶴路，幾裏入桃花。',48,'御定全唐詩/json/841.json','["阮肇迷仙處，禪門接紫霞。不知尋鶴路，幾裏入桃花。", "晚樹陰搖蘚，春潭影弄砂。何當見招我，乞與片生涯。"]'),
('yuding-10','謝人惠藥','齊己','唐','御定全唐诗','yuding','','[]','五金元造化，九煉更精新。敢謂長生客，將遺必死人。',48,'御定全唐詩/json/841.json','["五金元造化，九煉更精新。敢謂長生客，將遺必死人。", "久餐應換骨，一服已通神。終逐淮王去，永拋浮世塵。"]'),
('yuding-11','還族弟卷','齊己','唐','御定全唐诗','yuding','','[]','豈要私相許，君詩自入神。風騷何句出，瀑布一聯新。',48,'御定全唐詩/json/841.json','["豈要私相許，君詩自入神。風騷何句出，瀑布一聯新。", "□若長如此，名須遠逐身。閑齋舒複卷，留滯忽經旬。"]'),
('yuding-12','送周秀游峽','齊己','唐','御定全唐诗','yuding','','[]','又向夔城去，知難動旅魂。自非亡國客，何慮斷腸猿。',48,'御定全唐詩/json/841.json','["又向夔城去，知難動旅魂。自非亡國客，何慮斷腸猿。", "灩澦分高仞，瞿塘露淺痕。明年期此約，平穩到荊門。"]'),
('yuding-13','荊門夏日寄洞山節公','齊己','唐','御定全唐诗','yuding','','[]','湖光搖翠木，靈洞疊雲深。五月經行處，千秋檜柏陰。',48,'御定全唐詩/json/841.json','["湖光搖翠木，靈洞疊雲深。五月經行處，千秋檜柏陰。", "山形臨北渚，僧格繼東林。莫惜相招信，餘心是此心。"]'),
('yuding-14','再經蔣山與諸長老夜話','齊己','唐','御定全唐诗','yuding','','[]','遠跡都如雁，南行又北回。老僧猶記得，往歲已曾來。',48,'御定全唐詩/json/841.json','["遠跡都如雁，南行又北回。老僧猶記得，往歲已曾來。", "話遍名山境，燒殘黑櫟灰。無因伴師往，歸思在天臺。"]'),
('yuding-15','寄當陽張明府','齊己','唐','御定全唐诗','yuding','','[]','玉泉神運寺，寒磬徹琴堂。有境靈如此，為官興亦長。',48,'御定全唐詩/json/841.json','["玉泉神運寺，寒磬徹琴堂。有境靈如此，為官興亦長。", "吏愁清白甚，民樂賦輸忘。聞說巴山縣，今來尚憶張。"]'),
('yuding-16','遊三覺山','齊己','唐','御定全唐诗','yuding','','[]','白石路重重，縈紆勢忽窮。孤峰擎像閣，萬木蔽星空。',48,'御定全唐詩/json/841.json','["白石路重重，縈紆勢忽窮。孤峰擎像閣，萬木蔽星空。", "世論隨時變，禪懷曆劫同。良宵正冥目，海日上窗紅。"]'),
('yuding-17','庭際晚菊上主人','齊己','唐','御定全唐诗','yuding','','[]','九月將欲盡，幽叢始綻芳。都緣含正氣，不是背重陽。',48,'御定全唐詩/json/841.json','["九月將欲盡，幽叢始綻芳。都緣含正氣，不是背重陽。", "采去蜂聲遠，尋來蝶路長。王孫歸未晚，猶得泛金觴。"]'),
('yuding-18','送趙長史歸閩川','齊己','唐','御定全唐诗','yuding','','[]','荊門與閩越，關戍隔三千。風雪揚帆去，台隍指海邊。',48,'御定全唐詩/json/841.json','["荊門與閩越，關戍隔三千。風雪揚帆去，台隍指海邊。", "客情消旅火，王化似堯年。莫失春回約，江城穀雨前。"]'),
('yuding-19','擬嵇康絕交寄湘中貫微','齊己','唐','御定全唐诗','yuding','','[]','何處同嵇懶，吾徒道異諸。本無文字學，何有往來書。',48,'御定全唐詩/json/841.json','["何處同嵇懶，吾徒道異諸。本無文字學，何有往來書。", "岳寺逍遙夢，侯門勉強居。相知在玄契，莫訝八行疏。"]'),
('yuding-20','寄許州清古','齊己','唐','御定全唐诗','yuding','','[]','北來儒士說，許下有吟僧。白日身長倚，清秋塔上層。',48,'御定全唐詩/json/841.json','["北來儒士說，許下有吟僧。白日身長倚，清秋塔上層。", "言雖依景得，理要入無征。敢望多相示，孱微老不勝。"]'),
('yuding-21','謝丁秀才見示賦卷','齊己','唐','御定全唐诗','yuding','','[]','五首新裁翦，搜羅盡指歸。誰曾師古律，君自負天機。',48,'御定全唐詩/json/841.json','["五首新裁翦，搜羅盡指歸。誰曾師古律，君自負天機。", "聖後求賢久，明公得雋稀。乘秋好攜去，直望九霄飛。"]'),
('yuding-22','驚秋','齊己','唐','御定全唐诗','yuding','','[]','褰簾聽秋信，晚傍竹聲歸。多故堪傷骨，孤峰好拂衣。',48,'御定全唐詩/json/841.json','["褰簾聽秋信，晚傍竹聲歸。多故堪傷骨，孤峰好拂衣。", "梧桐凋綠盡，菡萏墮紅稀。卻恐吾形影，嫌心與口違。"]'),
('yuding-23','夏日雨中寄幕中知己','齊己','唐','御定全唐诗','yuding','','[]','北風吹夏雨，和竹亞南軒。豆枕欹涼冷，蓮峰入夢魂。',48,'御定全唐詩/json/841.json','["北風吹夏雨，和竹亞南軒。豆枕欹涼冷，蓮峰入夢魂。", "窗多斜迸濕，庭遍瀑流痕。清興知無限，晴來示一言。"]'),
('yuding-24','夜次湘陰','齊己','唐','御定全唐诗','yuding','','[]','風濤出洞庭，帆影入澄清。何處驚鴻起，孤舟趁月行。',48,'御定全唐詩/json/841.json','["風濤出洞庭，帆影入澄清。何處驚鴻起，孤舟趁月行。", "時難多戰地，野闊絕春耕。骨肉知存否，林園近郡城。"]'),
('yuding-25','寄唐稟正字','齊己','唐','御定全唐诗','yuding','','[]','疏野還如舊，何曾稱在城。水邊無伴立，天際有山橫。',48,'御定全唐詩/json/841.json','["疏野還如舊，何曾稱在城。水邊無伴立，天際有山橫。", "落日雲霞赤，高窗筆硯明。鮑昭多所得，時憶寄湯生。"]'),
('yuding-26','宿舒湖希上人房','齊己','唐','御定全唐诗','yuding','','[]','入寺先來此，經窗半在湖。秋風新菡萏，暮雨老菰蒲。',48,'御定全唐詩/json/841.json','["入寺先來此，經窗半在湖。秋風新菡萏，暮雨老菰蒲。", "任聽浮生速，能消默坐無。語來燈焰短，嘒唳發高梧。"]'),
('yuding-27','戊辰歲江南感懷','齊己','唐','御定全唐诗','yuding','','[]','忽忽動中私，人間何所之。老過離亂世，生在太平時。',48,'御定全唐詩/json/841.json','["忽忽動中私，人間何所之。老過離亂世，生在太平時。", "桃李春無主，杉松寺有期。曾吟子山賦，何啻舊淩遲。"]'),
('yuding-28','送林上人歸永嘉舊居','齊己','唐','御定全唐诗','yuding','','[]','東越常懸思，山門在永嘉。秋光浮楚水，帆影背長沙。',48,'御定全唐詩/json/841.json','["東越常懸思，山門在永嘉。秋光浮楚水，帆影背長沙。", "城黑天台雨，村明海嶠霞。時尋謝公跡，春草有瑤花。"]'),
('yuding-29','答友生山居寄示','齊己','唐','御定全唐诗','yuding','','[]','嘉遁有新吟，因僧寄竹林。靜思來鳥外，閑味繞松陰。',48,'御定全唐詩/json/841.json','["嘉遁有新吟，因僧寄竹林。靜思來鳥外，閑味繞松陰。", "兵寇憑淩甚，溪山幾許深。休為反招隱，攜取一相尋。"]'),
('yuding-30','新秋霽後晚眺懷先公','齊己','唐','御定全唐诗','yuding','','[]','雨霽湘楚晚，水涼天亦澄。山中應解夏，渡口有行僧。',48,'御定全唐詩/json/841.json','["雨霽湘楚晚，水涼天亦澄。山中應解夏，渡口有行僧。", "鳥列滄洲隊，雲排碧落層。孤峰磬聲絕，一點石龕燈。"]'),
('yuding-31','池上感興','齊己','唐','御定全唐诗','yuding','','[]','所向似無端，風前吟憑欄。旁人應悶見，片水自閑看。',48,'御定全唐詩/json/841.json','["所向似無端，風前吟憑欄。旁人應悶見，片水自閑看。", "碧底紅鱗鬣，澄邊白羽翰。南山眾木葉，飄著竹聲幹。"]'),
('yuding-32','和曇域上人寄贈之什','齊己','唐','御定全唐诗','yuding','','[]','百病煎衰朽，棲遲戰國中。思量青壁寺，行坐赤松風。',48,'御定全唐詩/json/841.json','["百病煎衰朽，棲遲戰國中。思量青壁寺，行坐赤松風。", "道寄虛無合，書傳往復空。可憐禪月子，香火國門東。"]'),
('yuding-33','吊雙泉大師真塔','齊己','唐','御定全唐诗','yuding','','[]','塔聳層峰後，碑鐫巨石新。不知將一句，分付與何人。',48,'御定全唐詩/json/841.json','["塔聳層峰後，碑鐫巨石新。不知將一句，分付與何人。", "靜坐雲生衲，空山月照真。後徒遊禮者，猶認指迷津。"]'),
('yuding-34','暮冬送璘上人歸華容','齊己','唐','御定全唐诗','yuding','','[]','故園雖不遠，那免愴行思。莽蒼平湖路，霏微過雪時。',48,'御定全唐詩/json/841.json','["故園雖不遠，那免愴行思。莽蒼平湖路，霏微過雪時。", "全無山阻隔，或有客相隨。得見交親後，春風動柳絲。"]'),
('yuding-35','秋夜聽業上人彈琴','齊己','唐','御定全唐诗','yuding','','[]','萬物都寂寂，堪聞彈正聲。人心盡如此，天下自和平。',48,'御定全唐詩/json/841.json','["萬物都寂寂，堪聞彈正聲。人心盡如此，天下自和平。", "湘水瀉秋碧，古風吹太清。往年廬嶽奏，今夕更分明。"]'),
('yuding-36','謝人惠丹藥','齊己','唐','御定全唐诗','yuding','','[]','別後聞餐餌，相逢訝道情。肌膚紅色透，髭發黑光生。',48,'御定全唐詩/json/841.json','["別後聞餐餌，相逢訝道情。肌膚紅色透，髭發黑光生。", "仙洞誰傳與，松房自煉成。常蒙遠分惠，亦覺骨毛輕。"]'),
('yuding-37','荊門病中寄懷貫微上人','齊己','唐','御定全唐诗','yuding','','[]','我衰君亦老，相憶更何言。除泥安禪力，難醫必死根。',48,'御定全唐詩/json/841.json','["我衰君亦老，相憶更何言。除泥安禪力，難醫必死根。", "梅寒爭雪彩，日冷讓冰痕。早晚東歸去，同尋入石門。"]'),
('yuding-38','答孔秀才','齊己','唐','御定全唐诗','yuding','','[]','早向文章裏，能降少壯心。不愁人不愛，閑處自閑吟。',48,'御定全唐詩/json/841.json','["早向文章裏，能降少壯心。不愁人不愛，閑處自閑吟。", "水國雲雷闊，僧園竹樹深。無嫌我衰颯，時此一相尋。"]'),
('yuding-39','秋江','齊己','唐','御定全唐诗','yuding','','[]','兩岸山青映，中流一棹聲。遠無風浪動，正向夕陽橫。',48,'御定全唐詩/json/841.json','["兩岸山青映，中流一棹聲。遠無風浪動，正向夕陽橫。", "島嶼蟬分宿，沙洲客獨行。浩然心自合，何必濯吾纓。"]'),
('yuding-40','船窗','齊己','唐','御定全唐诗','yuding','','[]','孤舸憑幽窗，清波逼面涼。舉頭還有礙，低眼即無妨。',48,'御定全唐詩/json/841.json','["孤舸憑幽窗，清波逼面涼。舉頭還有礙，低眼即無妨。", "瞥過沙禽翠，斜分夕照光。何時到山寺，上閣看江鄉。"]'),
('yuding-41','永夜','齊己','唐','御定全唐诗','yuding','','[]','永日還欹枕，良宵亦曲肱。神閑無萬慮，壁冷有殘燈。',48,'御定全唐詩/json/841.json','["永日還欹枕，良宵亦曲肱。神閑無萬慮，壁冷有殘燈。", "香影浮龕象，瓶聲著井冰。尋思到何處，海上斷崖僧。"]'),
('yuding-42','中春愴懷寄二三知己','齊己','唐','御定全唐诗','yuding','','[]','眼暗心還白，逢春強憑欄。因聞積雨夜，卻憶舊山寒。',48,'御定全唐詩/json/841.json','["眼暗心還白，逢春強憑欄。因聞積雨夜，卻憶舊山寒。", "竹撼煙叢滑，花燒露朵幹。故人相會處，應話此衰殘。"]'),
('yuding-43','自遣','齊己','唐','御定全唐诗','yuding','','[]','了然知是夢，既覺更何求。死入孤峰去，灰飛一燼休。',48,'御定全唐詩/json/841.json','["了然知是夢，既覺更何求。死入孤峰去，灰飛一燼休。", "雲無空碧在，天靜月華流。免有諸徒弟，時來吊石頭。"]'),
('yuding-44','送陳霸歸閩','齊己','唐','御定全唐诗','yuding','','[]','涼風動行興，含笑話臨途。已得身名了，全忘客道孤。',48,'御定全唐詩/json/841.json','["涼風動行興，含笑話臨途。已得身名了，全忘客道孤。", "鄉程過百越，帆影繞重湖。家在飛鴻外，音書可寄無。"]'),
('yuding-45','寄孫辟呈鄭谷郎中','齊己','唐','御定全唐诗','yuding','','[]','衡嶽去都忘，清吟戀省郎。淹留才半月，酬唱頗盈箱。',48,'御定全唐詩/json/841.json','["衡嶽去都忘，清吟戀省郎。淹留才半月，酬唱頗盈箱。", "雪長松檉格，茶添語話香。因論樂安子，年少老篇章。"]'),
('yuding-46','荊門送人自峨嵋游南嶽','齊己','唐','御定全唐诗','yuding','','[]','峨嵋來已遠，衡嶽去猶賒。南浦懸帆影，西風亂荻花。',48,'御定全唐詩/json/841.json','["峨嵋來已遠，衡嶽去猶賒。南浦懸帆影，西風亂荻花。", "天涯遙夢澤，山眾近長沙。有興多新作，攜將大府誇。"]'),
('yuding-47','謝主人石筍','齊己','唐','御定全唐诗','yuding','','[]','西園罷宴遊，東閣念林丘。特減花邊峭，來添竹裏幽。',48,'御定全唐詩/json/841.json','["西園罷宴遊，東閣念林丘。特減花邊峭，來添竹裏幽。", "憶過陽朔見，曾記大湖求。從此頻吟繞，歸山意亦休。"]'),
('yuding-48','經安公寺','齊己','唐','御定全唐诗','yuding','','[]','大聖威靈地，安公宴坐蹤。未知長寂默，不見久從容。',48,'御定全唐詩/json/841.json','["大聖威靈地，安公宴坐蹤。未知長寂默，不見久從容。", "塔影高群木，江聲壓暮鐘。此遊幽勝後，來夢亦應重。"]'),
('yuding-49','秋夕寄諸侄','齊己','唐','御定全唐诗','yuding','','[]','每到秋殘夜，燈前憶故鄉。園林紅橘柚，窗戶碧瀟湘。',48,'御定全唐詩/json/841.json','["每到秋殘夜，燈前憶故鄉。園林紅橘柚，窗戶碧瀟湘。", "離別身垂老，艱難路去長。弟兄應健在，兵火裏耕桑。"]'),
('yuding-50','謝炭','齊己','唐','御定全唐诗','yuding','','[]','正擁寒灰次，何當惠寂寥。且留連夜向，未敢滿爐燒。',48,'御定全唐詩/json/841.json','["正擁寒灰次，何當惠寂寥。且留連夜向，未敢滿爐燒。", "必恐吞難盡，唯愁撥易消。豪家捏為獸，紅迸錦茵焦。"]'),
('yuding-51','夏滿日偶作寄孫支使','齊己','唐','御定全唐诗','yuding','','[]','一百二十日，煎熬幾不勝。憶歸滄海寺，冷倚翠崖棱。',48,'御定全唐詩/json/841.json','["一百二十日，煎熬幾不勝。憶歸滄海寺，冷倚翠崖棱。", "舊扇猶操執，新秋更鬱蒸。何當見涼月，擁衲訪詩朋。"]'),
('yuding-52','寄清溪道友','齊己','唐','御定全唐诗','yuding','','[]','山門搖落空，霜霰滿杉松。明月行禪處，青苔繞石重。',48,'御定全唐詩/json/841.json','["山門搖落空，霜霰滿杉松。明月行禪處，青苔繞石重。", "泉聲喧萬壑，鐘韻遍千峰。終去焚香老，同師大士蹤。"]'),
('yuding-53','謝重緣舊山水障子','齊己','唐','御定全唐诗','yuding','','[]','敢望重緣飾，微茫洞壑春。坐看終未是，歸臥始應真。',48,'御定全唐詩/json/841.json','["敢望重緣飾，微茫洞壑春。坐看終未是，歸臥始應真。", "已覺心中朽，猶憐四面新。不因公子鑒，零落幾成塵。"]'),
('yuding-54','寺居','齊己','唐','御定全唐诗','yuding','','[]','鄰井雙梧上，一蟬鳴隔牆。依稀舊林日，撩亂繞山堂。',48,'御定全唐詩/json/841.json','["鄰井雙梧上，一蟬鳴隔牆。依稀舊林日，撩亂繞山堂。", "難嘿吟風口，終清飲露腸。老僧加護物，應任噪殘陽。"]'),
('yuding-55','剃發','齊己','唐','御定全唐诗','yuding','','[]','金刀閃冷光，一剃一清涼。未免隨朝夕，依前長雪霜。',48,'御定全唐詩/json/841.json','["金刀閃冷光，一剃一清涼。未免隨朝夕，依前長雪霜。", "夏林欹石膩，春澗水泉香。向老凋疏盡，寒天不出房。"]'),
('yuding-56','謝高輦先輩寄新唱和集','齊己','唐','御定全唐诗','yuding','','[]','敢謂神仙手，多懷老比丘。編聯來鹿野，酬唱在龍樓。',48,'御定全唐詩/json/841.json','["敢謂神仙手，多懷老比丘。編聯來鹿野，酬唱在龍樓。", "洛浦精靈懾，邙山鬼魅愁。二南風雅道，從此化東周。"]'),
('yuding-57','送徐秀才游吳國','齊己','唐','御定全唐诗','yuding','','[]','西江東注急，孤棹若流星。風浪相隨白，雲中獨過青。',48,'御定全唐詩/json/841.json','["西江東注急，孤棹若流星。風浪相隨白，雲中獨過青。", "他時誰共說，此路我曾經。好向吳朝看，衣冠盡漢庭。"]'),
('yuding-58','憶在匡廬日','齊己','唐','御定全唐诗','yuding','','[]','憶在匡廬日，秋風八月時。松聲虎溪寺，塔影雁門師。',48,'御定全唐詩/json/841.json','["憶在匡廬日，秋風八月時。松聲虎溪寺，塔影雁門師。", "步碧葳蕤徑，吟香菡萏池。何當舊泉石，歸去洗心脾。"]'),
('yuding-59','寄三覺山從益上人','齊己','唐','御定全唐诗','yuding','','[]','山下人來說，多時不下山。是應終未是，閑得且須閑。',48,'御定全唐詩/json/841.json','["山下人來說，多時不下山。是應終未是，閑得且須閑。", "海面雲歸竇，猿邊月上關。尋思亂峰頂，空送衲僧還。"]'),
('yuding-60','殘秋感愴','齊己','唐','御定全唐诗','yuding','','[]','日日加衰病，心心趣寂寥。殘陽起閑望，萬木聳寒條。',48,'御定全唐詩/json/841.json','["日日加衰病，心心趣寂寥。殘陽起閑望，萬木聳寒條。", "楚寺新為客，吳江舊看潮。此懷何以寄，風雨暮蕭蕭。"]'),
('yuding-61','寄南徐劉員外二首','齊己','唐','御定全唐诗','yuding','','[]','竟陵兵革際，歸復舊園林。早歲為官苦，常聞說此心。',96,'御定全唐詩/json/841.json','["竟陵兵革際，歸復舊園林。早歲為官苦，常聞說此心。", "海邊山夜上，城外寺秋尋。應訝嵩峰約，蹉跎直到今。", "晝公評眾制，姚監選諸文。風雅誰收我，編聯獨有君。", "餘生終此道，萬事盡浮雲。爭得重攜手，探幽楚水濆。"]'),
('yuding-62','貽王秀才','齊己','唐','御定全唐诗','yuding','','[]','功到難搜處，知難始是詩。自能探虎子，何慮屈男兒。',48,'御定全唐詩/json/841.json','["功到難搜處，知難始是詩。自能探虎子，何慮屈男兒。", "此道真清氣，前賢早白髭。須教至公手，不惜付舟枝。"]'),
('yuding-63','贈孫生','齊己','唐','御定全唐诗','yuding','','[]','見君詩自別，君是繼詩人。道出千途外，功爭一字新。',48,'御定全唐詩/json/841.json','["見君詩自別，君是繼詩人。道出千途外，功爭一字新。", "寂寥中影跡，霜雪裏精神。待折東堂桂，歸來更苦辛。"]'),
('yuding-64','酬元員外','齊己','唐','御定全唐诗','yuding','','[]','清洛碧嵩根，寒流白照門。園林經難別，桃李幾株存。',48,'御定全唐詩/json/841.json','["清洛碧嵩根，寒流白照門。園林經難別，桃李幾株存。", "衰老江南日，淒涼海上村。閑來曬朱紱，淚滴舊朝恩。"]'),
('yuding-65','與楊秀才話別','齊己','唐','御定全唐诗','yuding','','[]','庾信哀何極，仲宣悲苦多。因思學文賦，不勝弄干戈。',48,'御定全唐詩/json/841.json','["庾信哀何極，仲宣悲苦多。因思學文賦，不勝弄干戈。", "自古有如此，於今終若何。到頭重策蹇，歸去舊煙蘿。"]'),
('yuding-66','寄何崇丘員外','齊己','唐','御定全唐诗','yuding','','[]','門底桃源水，涵空複映山。高吟煙雨霽，殘日郡樓間。',48,'御定全唐詩/json/841.json','["門底桃源水，涵空複映山。高吟煙雨霽，殘日郡樓間。", "變俗真無事，分題是不閑。尋思章岸見，全未有年顏。"]'),
('yuding-67','贈劉五經','齊己','唐','御定全唐诗','yuding','','[]','往年長白山，發憤忍饑寒。掃葉雪霜濕，讀書唇齒幹。',48,'御定全唐詩/json/841.json','["往年長白山，發憤忍饑寒。掃葉雪霜濕，讀書唇齒幹。", "群經通講解，八十尚輕安。今日江南寺，相逢話世難。"]'),
('yuding-68','送遊山道者','齊己','唐','御定全唐诗','yuding','','[]','我亦遊山者，常經舊所經。雪消天外碧，春曉海中青。',48,'御定全唐詩/json/841.json','["我亦遊山者，常經舊所經。雪消天外碧，春曉海中青。", "可見亂離世，況臨衰病形。憐君此行興，獨入白雲屏。"]'),
('yuding-69','舟中江上望玉梁山懷李尊師','齊己','唐','御定全唐诗','yuding','','[]','殘照玉梁巔，峨峨遠棹前。古來傳勝異，人去學神仙。',48,'御定全唐詩/json/841.json','["殘照玉梁巔，峨峨遠棹前。古來傳勝異，人去學神仙。", "白鹿老碧壑，黃猿啼紫煙。誰心共無事，局上度流年。"]'),
('yuding-70','角','齊己','唐','御定全唐诗','yuding','','[]','聞說征人說，嗚嗚何處邊。孤城沙塞地，殘月雪霜天。',48,'御定全唐詩/json/841.json','["聞說征人說，嗚嗚何處邊。孤城沙塞地，殘月雪霜天。", "會轉胡風急，吹長磧雁連。應傷漢車騎，名未勒燕然。"]'),
('yuding-71','言詩','齊己','唐','御定全唐诗','yuding','','[]','畢竟將何狀，根元在正思。達人皆一貫，迷者自多岐。',48,'御定全唐詩/json/841.json','["畢竟將何狀，根元在正思。達人皆一貫，迷者自多岐。", "觸類風騷遠，懷賢肺腑衰。河橋送別者，二子好相知。"]'),
('yuding-72','酬王秀才','齊己','唐','御定全唐诗','yuding','','[]','離亂幾時休，儒生厄遠遊。亡家非漢代，何處覓荊州。',48,'御定全唐詩/json/841.json','["離亂幾時休，儒生厄遠遊。亡家非漢代，何處覓荊州。", "旅夢寒燈屋，鄉懷晝雨樓。相逢話相殺，誰複念風流。"]'),
('yuding-73','春居寄友生','齊己','唐','御定全唐诗','yuding','','[]','莎徑荒蕪甚，君應共此情。江村雷雨發，竹屋夢魂驚。',48,'御定全唐詩/json/841.json','["莎徑荒蕪甚，君應共此情。江村雷雨發，竹屋夢魂驚。", "社過多來燕，花繁漸老鶯。相思意何切，新作未曾評。"]'),
('yuding-74','寄答武陵幕中何支使二首','齊己','唐','御定全唐诗','yuding','','[]','十萬雄軍幕，三千上客才。何當談笑外，遠慰寂寥來。',96,'御定全唐詩/json/841.json','["十萬雄軍幕，三千上客才。何當談笑外，遠慰寂寥來。", "騷雅鏘金擲，風流醉玉頹。爭知江雪寺，老病向寒灰。", "南州無百戰，北地有長征。閑殺何從事，傷哉蘇子卿。", "江樓聯雪句，野寺看春耕。門外滄浪水，風波雜雨聲。"]'),
('yuding-75','浙江晚渡','齊己','唐','御定全唐诗','yuding','','[]','去年曾到此，久立滯前程。岐路時難處，風濤晚未平。',48,'御定全唐詩/json/841.json','["去年曾到此，久立滯前程。岐路時難處，風濤晚未平。", "汀蟬含老韻，岸荻簇枯聲。莫泥關河險，多游自遠行。"]'),
('yuding-76','送人下第東歸，再謁舊主人','齊己','唐','御定全唐诗','yuding','','[]','一戰偶不捷，東歸計未空。還攜故書劍，去謁舊英雄。',48,'御定全唐詩/json/841.json','["一戰偶不捷，東歸計未空。還攜故書劍，去謁舊英雄。", "楚雪連吳樹，西江正北風。男兒藝若是，會合值明公。"]'),
('yuding-77','寄謝高先輩見寄二首','齊己','唐','御定全唐诗','yuding','','[]','穿鑿堪傷骨，風騷久痛心。永言無絕唱，忽此惠希音。',96,'御定全唐詩/json/841.json','["穿鑿堪傷骨，風騷久痛心。永言無絕唱，忽此惠希音。", "楊柳江湖晚，芙蓉島嶼深。何因會仙手，臨水一披襟。", "詩在混茫前，難搜到極玄。有時還積思，度歲未終篇。", "片月雙松際，高樓闊水邊。前賢多此得，風味若為傳。"]'),
('yuding-0','寄仰山光味長者','齊己','唐','御定全唐诗','yuding','','[]','大仰禪棲處，杉松到頂陰。下來雖有路，歸去每無心。',48,'御定全唐詩/json/842.json','["大仰禪棲處，杉松到頂陰。下來雖有路，歸去每無心。", "鳥道峰形直，龍湫石影深。徑行誰得見，半夜老猿吟。"]'),
('yuding-1','貽廬岳陳沆秀才','齊己','唐','御定全唐诗','yuding','','[]','為儒老雙鬢，勤苦竟何如。四海方磨劍，空山自讀書。',48,'御定全唐詩/json/842.json','["為儒老雙鬢，勤苦竟何如。四海方磨劍，空山自讀書。", "石圍泉眼碧，秋落洞門虛。莫慮搜賢僻，征君舊此居。"]'),
('yuding-2','邊上','齊己','唐','御定全唐诗','yuding','','[]','漢地從休馬，胡家自牧羊。都來銷帝道，渾不用兵防。',48,'御定全唐詩/json/842.json','["漢地從休馬，胡家自牧羊。都來銷帝道，渾不用兵防。", "草上孤城白，沙翻大漠黃。秋風起邊雁，一一向瀟湘。"]'),
('yuding-3','蟋蟀','齊己','唐','御定全唐诗','yuding','','[]','聲異蟪蛄聲，聽須是正聽。無風來竹院，有月在莎庭。',48,'御定全唐詩/json/842.json','["聲異蟪蛄聲，聽須是正聽。無風來竹院，有月在莎庭。", "雖不妨調瑟，多堪伴誦經。誰人向秋夕，為爾欲忘形。"]'),
('yuding-4','寄西山鄭谷神','齊己','唐','御定全唐诗','yuding','','[]','西望鄭先生，焚修在杳冥。幾番松骨朽，未換鬢根青。',48,'御定全唐詩/json/842.json','["西望鄭先生，焚修在杳冥。幾番松骨朽，未換鬢根青。", "石闕涼調瑟，秋壇夜拜星。俗人應撫掌，閑處誦黃庭。"]'),
('yuding-5','讀參同契','齊己','唐','御定全唐诗','yuding','','[]','堪笑修仙侶，燒金覓大還。不知消息火，只在寂寥關。',48,'御定全唐詩/json/842.json','["堪笑修仙侶，燒金覓大還。不知消息火，只在寂寥關。", "鬢白爐中術，魂飛海上山。悲哉五千字，無用在人間。"]'),
('yuding-6','聞落葉','齊己','唐','御定全唐诗','yuding','','[]','楚樹雪晴後，蕭蕭落晚風。因思故國夜，臨水幾株空。',48,'御定全唐詩/json/842.json','["楚樹雪晴後，蕭蕭落晚風。因思故國夜，臨水幾株空。", "煮茗燒乾脆，行苔踏爛紅。來年未離此，還見碧叢叢。"]'),
('yuding-7','謝王先輩昆弟游湘中回各見示新詩','齊己','唐','御定全唐诗','yuding','','[]','瀟湘多勝異，宗社久裴回。兄弟同游去，幽奇盡采來。',48,'御定全唐詩/json/842.json','["瀟湘多勝異，宗社久裴回。兄弟同游去，幽奇盡采來。", "只應求妙唱，何以示寒灰。上國攜歸後，唯呈不世才。"]'),
('yuding-8','寄酬高輦推官','齊己','唐','御定全唐诗','yuding','','[]','道自閑機長，詩從靜境生。不知春豔盡，但覺雅風清。',48,'御定全唐詩/json/842.json','["道自閑機長，詩從靜境生。不知春豔盡，但覺雅風清。", "竹膩題幽碧，蕉乾裂脆聲。何當九霄客，重疊記無名。"]'),
('yuding-9','逢詩僧','齊己','唐','御定全唐诗','yuding','','[]','禪玄無可並，詩妙有何評。五七字中苦，百千年後清。',48,'御定全唐詩/json/842.json','["禪玄無可並，詩妙有何評。五七字中苦，百千年後清。", "難求方至理，不朽始為名。珍重重相見，忘機話此情。"]'),
('yuding-10','話道','齊己','唐','御定全唐诗','yuding','','[]','大道多大笑，寂寥何以論。霜楓翻落葉，水鳥啄閑門。',48,'御定全唐詩/json/842.json','["大道多大笑，寂寥何以論。霜楓翻落葉，水鳥啄閑門。", "服藥還傷性，求珠亦損魂。無端鑿混沌，一死不還源。"]'),
('yuding-11','謝歐陽侍郎寄示新集','齊己','唐','御定全唐诗','yuding','','[]','宮錦三十段，金梭新織來。殷勤謝君子，迢遞寄寒灰。',48,'御定全唐詩/json/842.json','["宮錦三十段，金梭新織來。殷勤謝君子，迢遞寄寒灰。", "鸑鷟對鼓舞，神仙雙裴回。誰當巧裁制，披去升瑤台。"]'),
('yuding-12','西墅新居','齊己','唐','御定全唐诗','yuding','','[]','漸漸見苔青，疏疏遍地生。閑穿藤屐起，亂踏石階行。',48,'御定全唐詩/json/842.json','["漸漸見苔青，疏疏遍地生。閑穿藤屐起，亂踏石階行。", "野鳥啼幽樹，名僧笑此情。殘陽竹陰裏，老圃打門聲。"]'),
('yuding-13','酬孫魴','齊己','唐','御定全唐诗','yuding','','[]','幽人還愛雲，才子已從軍。可信鴛鴻侶，更思麋鹿群。',48,'御定全唐詩/json/842.json','["幽人還愛雲，才子已從軍。可信鴛鴻侶，更思麋鹿群。", "新題雖有寄，舊論竟難聞。知己今如此，編聯悉欲焚。"]'),
('yuding-14','掃地','齊己','唐','御定全唐诗','yuding','','[]','日日掃複灑，不容纖物侵。敢望來客口，道似主人心。',48,'御定全唐詩/json/842.json','["日日掃複灑，不容纖物侵。敢望來客口，道似主人心。", "蟻過光中少，苔依潤處深。門前亦如此，一徑入疏林。"]'),
('yuding-15','書匡山隱者壁','齊己','唐','御定全唐诗','yuding','','[]','紅霞青壁底，石室薜蘿垂。應有迷仙者，曾逢采藥時。',48,'御定全唐詩/json/842.json','["紅霞青壁底，石室薜蘿垂。應有迷仙者，曾逢采藥時。", "桃花饒兩頰，松葉淺長髭。直是來城市，何人識得伊。"]'),
('yuding-16','送幹康禪師入山過夏','齊己','唐','御定全唐诗','yuding','','[]','由來喧滑境，難駐寂寥蹤。逼夏搖孤錫，離城入亂峰。',48,'御定全唐詩/json/842.json','["由來喧滑境，難駐寂寥蹤。逼夏搖孤錫，離城入亂峰。", "雲門應近寺，石路或穿松。知在棲禪外，題詩寄北宗。"]'),
('yuding-17','野鴨','齊己','唐','御定全唐诗','yuding','','[]','野鴨殊家鴨，離群忽遠飛。長生緣甚瘦，近死為傷肥。',48,'御定全唐詩/json/842.json','["野鴨殊家鴨，離群忽遠飛。長生緣甚瘦，近死為傷肥。", "江海遊空闊，池塘啄細微。紅蘭白蘋渚，春暖刷毛衣。"]'),
('yuding-18','傷秋','齊己','唐','御定全唐诗','yuding','','[]','旦暮餘生在，肌膚十分無。眠寒半榻朽，立月一株枯。',48,'御定全唐詩/json/842.json','["旦暮餘生在，肌膚十分無。眠寒半榻朽，立月一株枯。", "夢已隨雙樹，詩猶卻萬夫。名山未歸得，可惜死江湖。"]'),
('yuding-19','懷東湖寺','齊己','唐','御定全唐诗','yuding','','[]','鐵柱東湖岸，寺高人亦閑。往年曾每日，來此看西山。',48,'御定全唐詩/json/842.json','["鐵柱東湖岸，寺高人亦閑。往年曾每日，來此看西山。", "竹徑青苔合，茶軒白鳥還。而今在天末，欲去已衰顏。"]'),
('yuding-20','寄峴山願公三首','齊己','唐','御定全唐诗','yuding','','[]','形影更誰親，應懷漆道人。片言酬鑿齒，半偈伏姚秦。',144,'御定全唐詩/json/842.json','["形影更誰親，應懷漆道人。片言酬鑿齒，半偈伏姚秦。", "榛莽池經燒，蒿萊寺過春。心期重西去，一共吊遺塵。", "相思恨相遠，至理那時何。道笑忘言甚，詩嫌背俗多。", "青苔閑閣閉，白日斷人過。獨上西樓望，荊門千萬坡。", "彼此無消息，所思江漢遙。轉聞多患難，甚說遠相招。", "老至何悲歎，生知便寂寥。終期踏松影，攜手虎溪橋。"]'),
('yuding-21','清夜作','齊己','唐','御定全唐诗','yuding','','[]','不惜白日短，乍容清夜長。坐聞風露滴，吟覺骨毛涼。',48,'御定全唐詩/json/842.json','["不惜白日短，乍容清夜長。坐聞風露滴，吟覺骨毛涼。", "興寢無諸病，空閒有一床。天明振衣起，苔砌落花香。"]'),
('yuding-22','贈白處士','齊己','唐','御定全唐诗','yuding','','[]','莘野居何定，浮生知是誰。衣衫同野叟，指趣似禪師。',48,'御定全唐詩/json/842.json','["莘野居何定，浮生知是誰。衣衫同野叟，指趣似禪師。", "白髮應無也，丹砂久服之。仍聞創行計，春暖向峨嵋。"]'),
('yuding-23','崔秀才宿話','齊己','唐','御定全唐诗','yuding','','[]','事轉聞多事，心休話苦心。相留明月寺，共憶白雲岑。',48,'御定全唐詩/json/842.json','["事轉聞多事，心休話苦心。相留明月寺，共憶白雲岑。", "蘚壁殘蟲韻，霜軒倒竹陰。開門又言別，誰竟慰塵襟。"]'),
('yuding-24','懷天臺華頂僧','齊己','唐','御定全唐诗','yuding','','[]','華頂危臨海，丹霞裏石橋。曾從國清寺，上看月明潮。',48,'御定全唐詩/json/842.json','["華頂危臨海，丹霞裏石橋。曾從國清寺，上看月明潮。", "好鳥親香火，狂泉噴泬寥。欲歸師智者，頭白路迢迢。"]'),
('yuding-25','送人赴官','齊己','唐','御定全唐诗','yuding','','[]','年少作初官，還如行路難。兵荒經邑裏，風俗久凋殘。',48,'御定全唐詩/json/842.json','["年少作初官，還如行路難。兵荒經邑裏，風俗久凋殘。", "照硯花光淡，漂書柳絮幹。聊應充侍膳，薄俸繼朝餐。"]'),
('yuding-26','水鶴','齊己','唐','御定全唐诗','yuding','','[]','鴛鴦與鸂鶒，相狎豈慚君。比雪還勝雪，同群亦出群。',48,'御定全唐詩/json/842.json','["鴛鴦與鸂鶒，相狎豈慚君。比雪還勝雪，同群亦出群。", "靜巢孤島月，寒夢九皋雲。歸路分明過，飛鳴即可聞。"]'),
('yuding-27','湘中感懷','齊己','唐','御定全唐诗','yuding','','[]','漁翁那會我，傲兀葦邊行。亂世難逸跡，乘流擬濯纓。',48,'御定全唐詩/json/842.json','["漁翁那會我，傲兀葦邊行。亂世難逸跡，乘流擬濯纓。", "江花紅細碎，沙鳥白分明。向夕題詩處，春風斑竹聲。"]'),
('yuding-28','九日逢虛中虛受','齊己','唐','御定全唐诗','yuding','','[]','楚後萍台下，相逢九日時。干戈人事地，荒廢菊花籬。',48,'御定全唐詩/json/842.json','["楚後萍台下，相逢九日時。干戈人事地，荒廢菊花籬。", "我已多衰病，君猶盡黑髭。皇天安罪得，解語便吟詩。"]'),
('yuding-29','贈李明府','齊己','唐','御定全唐诗','yuding','','[]','名家宰名邑，將謂屈鋒鋩。直是難蘇俗，能消不下堂。',48,'御定全唐詩/json/842.json','["名家宰名邑，將謂屈鋒鋩。直是難蘇俗，能消不下堂。", "冰痕生硯水，柳影透琴床。何必稱瀟灑，獨為詩酒狂。"]'),
('yuding-30','暮春久雨作','齊己','唐','御定全唐诗','yuding','','[]','積雨向春陰，冥冥獨院深。已無花落地，空有竹藏禽。',48,'御定全唐詩/json/842.json','["積雨向春陰，冥冥獨院深。已無花落地，空有竹藏禽。", "簷溜聲何暴，鄰僧影亦沈。誰知力耕者，桑麥最關心。"]'),
('yuding-31','渚宮莫問詩一十五首','齊己','唐','御定全唐诗','yuding','','[]','莫問疏人事，王侯已任伊。不妨隨野性，還似在山時。',576,'御定全唐詩/json/842.json','["莫問疏人事，王侯已任伊。不妨隨野性，還似在山時。", "靜入無聲樂，狂拋正律詩。自為仍自愛，清淨裏尋思。", "莫問伊嵇懶，流年已付他。話通時事少，詩著野題多。", "夢外春桃李，心中舊薜蘿。浮生此不悟，剃發竟如何。", "莫問休行腳，南方已遍尋。了應須自了，心不是他心。", "赤水珠何覓，寒山偈莫吟。誰同論此理，杜口少知音。", "莫問孱愚格，天應只與閑。合居長樹下，那稱眾人間。", "跡絕為真隱，機忘是大還。終當學支遁，買取個青山。", "莫問無求意，浮雲喻可知。滿盈如不戒，倚伏更何疑。", "樂矣賢顏子，窮乎聖仲尼。已過知命歲，休把運行推。", "莫問閑行趣，春風野水涯。千門無謝女，兩岸有楊花。", "好鶴曾為客，真龍或作蛇。躊躕自回首，日腳背樓斜。", "莫問真消息，中心只自知。清風含笑詠，明月混希夷。", "壞衲涼天擁，玄文靜夜披。善哉溫伯子，言望至公知。", "莫問休持缽，從貧乞已疏。侯門叨月俸，齋食剩年儲。", "簪履三千外，形骸六十餘。舊峰呵練若，松徑接匡廬。", "莫問依劉跡，金台又度秋。威儀非上客，譚笑愧諸侯。", "禮許無拘檢，詩推異輩流。東林未歸得，搖落楚江頭。", "莫問無機性，甘名百鈍人。一床鋪冷落，長日臥精神。", "分已疏知舊，詩還得意新。多才碧雲客，時或此相親。", "莫問關門意，從來寡往還。道應歸淡泊，身合在空閒。", "四面苔圍綠，孤窗雨灑斑。夢尋何處去，秋色水邊山。", "莫問□□□，□□逐性情。人間高此道，禪外剩他名。", "夏□松邊坐，秋光水畔行。更無時忌諱，容易得題成。"]'),
('yuding-32','荊州新秋病起雜題一十五首：病起見王化','齊己','唐','御定全唐诗','yuding','','[]','病起見王化，融融古帝鄉。曉煙凝氣紫，晚色作雲黃。',48,'御定全唐詩/json/842.json','["病起見王化，融融古帝鄉。曉煙凝氣紫，晚色作雲黃。", "四野歌豐稔，千門唱樂康。老身仍未死，猶詠好風光。"]'),
('yuding-33','荊州新秋病起雜題一十五首：病起見圖畫','齊己','唐','御定全唐诗','yuding','','[]','病起見圖畫，雲門興似饒。衲衣棕笠重，嵩岳華山遙。',48,'御定全唐詩/json/842.json','["病起見圖畫，雲門興似饒。衲衣棕笠重，嵩岳華山遙。", "命在齋猶赴，刀閑發盡凋。秋光漸輕健，欲去倚江橋。"]'),
('yuding-34','荊州新秋病起雜題一十五首：病起見苔錢','齊己','唐','御定全唐诗','yuding','','[]','病起見苔錢，規模遍地圓。兒童掃不破，子母自相連。',48,'御定全唐詩/json/842.json','["病起見苔錢，規模遍地圓。兒童掃不破，子母自相連。", "潤屋何曾有，緣牆謾可憐。虛教作銅臭，空使外人傳。"]'),
('yuding-35','荊州新秋病起雜題一十五首：病起見庭竹','齊己','唐','御定全唐诗','yuding','','[]','病起見庭竹，君應悲我情。何妨甚消瘦，卻稱苦修行。',48,'御定全唐詩/json/842.json','["病起見庭竹，君應悲我情。何妨甚消瘦，卻稱苦修行。", "每謝侵床影，時回傍枕聲。秋來漸平復，吟繞骨毛輕。"]'),
('yuding-36','荊州新秋病起雜題一十五首：病起見生涯','齊己','唐','御定全唐诗','yuding','','[]','病起見生涯，資緣覺甚奢。方袍嫌垢弊，律服變光華。',48,'御定全唐詩/json/842.json','["病起見生涯，資緣覺甚奢。方袍嫌垢弊，律服變光華。", "頗愧同諸俗，何嘗異出家。三衣如兩翼，珍重汝寒鴉。"]'),
('yuding-37','荊州新秋病起雜題一十五首：病起見秋扇','齊己','唐','御定全唐诗','yuding','','[]','病起見秋扇，風前悟感傷。念予當咽絕，得爾致清涼。',48,'御定全唐詩/json/842.json','["病起見秋扇，風前悟感傷。念予當咽絕，得爾致清涼。", "沙鷺如搖影，汀蓮似綻香。不同婕妤詠，托意怨君王。"]'),
('yuding-38','荊州新秋病起雜題一十五首：病起見衰葉','齊己','唐','御定全唐诗','yuding','','[]','病起見衰葉，飄然似我身。偶乘風有韻，初落地無塵。',48,'御定全唐詩/json/842.json','["病起見衰葉，飄然似我身。偶乘風有韻，初落地無塵。", "縱得紅沾露，爭如綠帶春。因傷此懷抱，聊寄一篇新。"]'),
('yuding-39','荊州新秋病起雜題一十五首：病起見庭柏','齊己','唐','御定全唐诗','yuding','','[]','病起見庭柏，青青我不任。力扶乾瘦骨，勉對歲寒心。',48,'御定全唐詩/json/842.json','["病起見庭柏，青青我不任。力扶乾瘦骨，勉對歲寒心。", "韻謝疏篁合，根容片石侵。衰殘想長壽，時倚就閑吟。"]'),
('yuding-40','荊州新秋病起雜題一十五首：病起見庭蓮','齊己','唐','御定全唐诗','yuding','','[]','病起見庭蓮，風荷已颯然。開時聞馥鬱，枕上正纏綿。',48,'御定全唐詩/json/842.json','["病起見庭蓮，風荷已颯然。開時聞馥鬱，枕上正纏綿。", "本在滄江闊，移來碧沼圓。卻思香社裏，葉葉漏聲連。"]'),
('yuding-41','荊州新秋病起雜題一十五首：病起見庭菊','齊己','唐','御定全唐诗','yuding','','[]','病起見庭菊，幾勞栽種工。可能經臥疾，相倚自成叢。',48,'御定全唐詩/json/842.json','["病起見庭菊，幾勞栽種工。可能經臥疾，相倚自成叢。", "翠萼低含露，金英盡亞風。那知予愛爾，不在酒杯中。"]'),
('yuding-42','荊州新秋病起雜題一十五首：病起見庭石','齊己','唐','御定全唐诗','yuding','','[]','病起見庭石，豈知經夏眠。不能資藥價，空自作苔錢。',48,'御定全唐詩/json/842.json','["病起見庭石，豈知經夏眠。不能資藥價，空自作苔錢。", "翠憶藍光底，青思瀑影邊。岩僧應笑我，細碎種階前。"]'),
('yuding-43','荊州新秋病起雜題一十五首：病起見庭莎','齊己','唐','御定全唐诗','yuding','','[]','病起見庭莎，綠階傍竹多。繞行猶未得，靜聽複如何。',48,'御定全唐詩/json/842.json','["病起見庭莎，綠階傍竹多。繞行猶未得，靜聽複如何。", "蟋蟀幽中響，蟪蛄深處歌。不緣田地窄，剩種任婆娑。"]'),
('yuding-44','荊州新秋病起雜題一十五首：病起見苔色','齊己','唐','御定全唐诗','yuding','','[]','病起見苔色，凝然陣未枯。淺深圍柱礎，詰曲繞廊廡。',48,'御定全唐詩/json/842.json','["病起見苔色，凝然陣未枯。淺深圍柱礎，詰曲繞廊廡。", "碧翠文相間，青黃勢自鋪。為錢虛玷染，畢竟不如無。"]'),
('yuding-45','荊州新秋病起雜題一十五首：病起見秋月','齊己','唐','御定全唐诗','yuding','','[]','病起見秋月，正當三五時。清光應鑒我，幽思更同誰。',48,'御定全唐詩/json/842.json','["病起見秋月，正當三五時。清光應鑒我，幽思更同誰。", "惜坐身猶倦，牽吟氣尚羸。明年七十六，約此健相期。"]'),
('yuding-46','荊州新秋病起雜題一十五首：病起見閑雲','齊己','唐','御定全唐诗','yuding','','[]','病起見閑雲，空中聚又分。滯留堪笑我，舒卷不如君。',48,'御定全唐詩/json/842.json','["病起見閑雲，空中聚又分。滯留堪笑我，舒卷不如君。", "觸石終無跡，從風或有聞。仙山足鸞鳳，歸去自同群。"]'),
('yuding-47','夜坐聞雪寄所知','齊己','唐','御定全唐诗','yuding','','[]','初宵飛霰急，竹樹灑幹輕。不是知音者，難教愛此聲。',48,'御定全唐詩/json/842.json','["初宵飛霰急，竹樹灑幹輕。不是知音者，難教愛此聲。", "漸淩孤燭白，偏激苦心清。堪笑同文友，忘眠坐到明。"]'),
('yuding-48','懷洞庭','齊己','唐','御定全唐诗','yuding','','[]','憶過巴陵歲，無人問去留。中宵滿湖月，獨自在僧樓。',48,'御定全唐詩/json/842.json','["憶過巴陵歲，無人問去留。中宵滿湖月，獨自在僧樓。", "漁父真閑唱，靈均是謾愁。今來欲長往，誰借木蘭舟。"]'),
('yuding-49','欲游龍山鹿苑有作','齊己','唐','御定全唐诗','yuding','','[]','龍山門不遠，鹿苑路非遙。合逐閑身去，何須待客招。',48,'御定全唐詩/json/842.json','["龍山門不遠，鹿苑路非遙。合逐閑身去，何須待客招。", "年華殘兩鬢，筋骨倦長宵。聞說峰前寺，新修白石橋。"]'),
('yuding-50','再逢晝公','齊己','唐','御定全唐诗','yuding','','[]','竟陵西別後，遍地起刀兵。彼此無緣著，雲山有處行。',48,'御定全唐詩/json/842.json','["竟陵西別後，遍地起刀兵。彼此無緣著，雲山有處行。", "久吟難敵句，終忍不求名。年鬢俱如雪，相看眼且明。"]'),
('yuding-51','送人游武陵湘中','齊己','唐','御定全唐诗','yuding','','[]','為子歌行樂，西南入武陵。風煙無戰士，賓榻有吟僧。',48,'御定全唐詩/json/842.json','["為子歌行樂，西南入武陵。風煙無戰士，賓榻有吟僧。", "山繞軍城疊，江臨寺閣層。遍尋幽勝了，湘水泛清澄。"]'),
('yuding-52','酬九經者','齊己','唐','御定全唐诗','yuding','','[]','九經三史學，窮妙又窮微。長白山初出，青雲路欲飛。',48,'御定全唐詩/json/842.json','["九經三史學，窮妙又窮微。長白山初出，青雲路欲飛。", "江僧酬雪句，沙鶴識麻衣。家在黃河北，南來偶未歸。"]'),
('yuding-53','寄贈集灘二公','齊己','唐','御定全唐诗','yuding','','[]','聞有難名境，因君住更名。軒窗中夜色，風月繞灘聲。',48,'御定全唐詩/json/842.json','["聞有難名境，因君住更名。軒窗中夜色，風月繞灘聲。", "客好過無厭，禽幽畫不成。終期一尋去，聊且寄吟情。"]'),
('yuding-54','夏日作','齊己','唐','御定全唐诗','yuding','','[]','燕雀語相和，風池滿芰荷。可驚成事晚，殊喜得閒多。',48,'御定全唐詩/json/842.json','["燕雀語相和，風池滿芰荷。可驚成事晚，殊喜得閒多。", "竹眾涼欺水，苔繁綠勝莎。無慚孤聖代，賦詠有詩歌。"]'),
('yuding-55','行路難','齊己','唐','御定全唐诗','yuding','','[]','下浸與高盤，不為行路難。是非真險惡，翻覆作峰巒。',48,'御定全唐詩/json/842.json','["下浸與高盤，不為行路難。是非真險惡，翻覆作峰巒。", "漆愧同時黑，朱慚巧處丹。令人畏相識，欲畫白雲看。"]'),
('yuding-56','送玉泉道者回山寺','齊己','唐','御定全唐诗','yuding','','[]','卻憶西峰頂，經行絕愛憎。別來心念念，歸去雪層層。',48,'御定全唐詩/json/842.json','["卻憶西峰頂，經行絕愛憎。別來心念念，歸去雪層層。", "石塢尋春筍，苔龕續夜燈。應悲塵土裏，追逐利名僧。"]'),
('yuding-57','謝王拾遺見訪兼寄篇什','齊己','唐','御定全唐诗','yuding','','[]','竹里安禪處，生涯一印灰。經年乞食過，昨日諫臣來。',48,'御定全唐詩/json/842.json','["竹里安禪處，生涯一印灰。經年乞食過，昨日諫臣來。", "愧把黃梅偈，曾酬白雪才。因令識鳥跡，重疊在蒼苔。"]'),
('yuding-58','題張氏池亭','齊己','唐','御定全唐诗','yuding','','[]','樹石叢叢別，詩家趣向幽。有時閑客散，始覺細泉流。',48,'御定全唐詩/json/842.json','["樹石叢叢別，詩家趣向幽。有時閑客散，始覺細泉流。", "蝶到琴棋畔，花過島嶼頭。月明紅藕上，應見白龜遊。"]'),
('yuding-59','送人南游','齊己','唐','御定全唐诗','yuding','','[]','且聽吟贈遠，君此去蒙州。瘴國頻聞說，邊鴻亦不遊。',48,'御定全唐詩/json/842.json','["且聽吟贈遠，君此去蒙州。瘴國頻聞說，邊鴻亦不遊。", "蠻花藏孔雀，野石亂犀牛。到彼誰相慰，知音有郡侯。"]'),
('yuding-60','題明公房','齊己','唐','御定全唐诗','yuding','','[]','寺北聞湘浪，窗南見嶽雲。自然高日用，何要出人群。',48,'御定全唐詩/json/842.json','["寺北聞湘浪，窗南見嶽雲。自然高日用，何要出人群。", "瓦滴殘松雨，香爐匝印文。近年精易道，疑者曉紛紛。"]'),
('yuding-61','寄顧處士','齊己','唐','御定全唐诗','yuding','','[]','半年離別夢，來往即湖邊。兩幅關山雪，尋常在眼前。',48,'御定全唐詩/json/842.json','["半年離別夢，來往即湖邊。兩幅關山雪，尋常在眼前。", "項容藏古翠，張藻卷寒煙。藍澱圖花鳥，時人不惜錢。"]'),
('yuding-62','貽徐生','齊己','唐','御定全唐诗','yuding','','[]','可能東海子，清苦在貧居。掃地無閑客，堆窗有古書。',48,'御定全唐詩/json/842.json','["可能東海子，清苦在貧居。掃地無閑客，堆窗有古書。", "少年猶若此，向老合何如。去歲頻相訪，今來見亦疏。"]'),
('yuding-63','謝虛中上人晚秋見寄','齊己','唐','御定全唐诗','yuding','','[]','楚外同文在，荊門得信時。幾重相別意，一首晚秋詩。',48,'御定全唐詩/json/842.json','["楚外同文在，荊門得信時。幾重相別意，一首晚秋詩。", "日暮山沈雨，蓮殘水滿池。登樓試南望，為子動歸思。"]'),
('yuding-0','寄東林言之禪子','齊己','唐','御定全唐诗','yuding','','[]','聞思相送後，幽院閉苔錢。使我吟還廢，聞君病未痊。',48,'御定全唐詩/json/843.json','["聞思相送後，幽院閉苔錢。使我吟還廢，聞君病未痊。", "聽秋唯困坐，怕客但佯眠。可惜東窗月，無寥過一年。"]'),
('yuding-1','寒節日寄鄉友','齊己','唐','御定全唐诗','yuding','','[]','歲歲逢寒食，寥寥古寺家。踏青思故里，垂白看楊花。',48,'御定全唐詩/json/843.json','["歲歲逢寒食，寥寥古寺家。踏青思故里，垂白看楊花。", "原野稀疏雨，江天冷澹霞。滄浪與湘水，歸恨共無涯。"]'),
('yuding-2','聞西蟾從弟卜岩居嶽西有寄','齊己','唐','御定全唐诗','yuding','','[]','瀑布見高低，岩開岩壁西。碧雲多舊作，紅葉幾新題。',48,'御定全唐詩/json/843.json','["瀑布見高低，岩開岩壁西。碧雲多舊作，紅葉幾新題。", "滴瀝中疏磬，嵌空半倚梯。仍聞樵子徑，□不到前溪。"]'),
('yuding-3','寄懷西蟾師弟','齊己','唐','御定全唐诗','yuding','','[]','萬里八九月，一身西北風。自從相示後，長記在吟中。',48,'御定全唐詩/json/843.json','["萬里八九月，一身西北風。自從相示後，長記在吟中。", "見說南遊遠，堪懷我姓同。江邊忽得信，回到嶽門東。"]'),
('yuding-4','撲滿子','齊己','唐','御定全唐诗','yuding','','[]','只愛滿我腹，爭如滿害身。到頭須撲破，卻散與他人。',24,'御定全唐詩/json/843.json','["只愛滿我腹，爭如滿害身。到頭須撲破，卻散與他人。"]'),
('yuding-5','寄西川惠光大師曇域','齊己','唐','御定全唐诗','yuding','','[]','禪月有名子，相知面未曾。筆精垂壁溜，詩澀滴杉冰。',48,'御定全唐詩/json/843.json','["禪月有名子，相知面未曾。筆精垂壁溜，詩澀滴杉冰。", "蜀國從棲泊，蕪城幾廢興。憶歸應寄夢，東北過金陵。"]'),
('yuding-6','憶別匡山寄彭澤幹晝上人','齊己','唐','御定全唐诗','yuding','','[]','憶別匡山日，無端是遠遊。卻回看五老，翻悔上孤舟。',48,'御定全唐詩/json/843.json','["憶別匡山日，無端是遠遊。卻回看五老，翻悔上孤舟。", "蹭蹬三千里，蹉跎二十秋。近來空寄夢，時到虎溪頭。"]'),
('yuding-7','又寄彭澤晝公','齊己','唐','御定全唐诗','yuding','','[]','聞君彭澤住，結構近陶公。種菊心相似，嘗茶味不同。',48,'御定全唐詩/json/843.json','["聞君彭澤住，結構近陶公。種菊心相似，嘗茶味不同。", "湖光秋枕上，岳翠夏窗中。八月東林去，吟香菡萏風。"]'),
('yuding-8','因覽支使孫中丞看可准大師詩序有寄','齊己','唐','御定全唐诗','yuding','','[]','一千篇裏選，三百首菁英。玉尺新量出，金刀舊剪成。',48,'御定全唐詩/json/843.json','["一千篇裏選，三百首菁英。玉尺新量出，金刀舊剪成。", "錦江增古翠，仙掌減元精。自此為風格，留傳諸後生。"]'),
('yuding-9','新秋病中枕上聞蟬','齊己','唐','御定全唐诗','yuding','','[]','枕上稍醒醒，忽聞蟬一聲。此時知不死，昨日即前生。',48,'御定全唐詩/json/843.json','["枕上稍醒醒，忽聞蟬一聲。此時知不死，昨日即前生。", "更欲臨窗聽，猶難策杖行。尋應同蛻殼，重飲露華清。"]'),
('yuding-10','寄雲蓋山先禪師','齊己','唐','御定全唐诗','yuding','','[]','曾尋湘水東，古翠積秋濃。長老禪棲處，半天雲蓋峰。',48,'御定全唐詩/json/843.json','["曾尋湘水東，古翠積秋濃。長老禪棲處，半天雲蓋峰。", "閑床饒得石，雜樹少於松。近有誰堪語，瀏陽妙指蹤。"]'),
('yuding-11','落葉','齊己','唐','御定全唐诗','yuding','','[]','落多秋亦晚，窗外見諸鄰。世上誰驚盡，林間獨掃頻。',48,'御定全唐詩/json/843.json','["落多秋亦晚，窗外見諸鄰。世上誰驚盡，林間獨掃頻。", "蕭騷微月夜，重疊早霜晨。昨日繁陰在，鶯聲樹樹春。"]'),
('yuding-12','次耒陽作','齊己','唐','御定全唐诗','yuding','','[]','繞嶽複沿湘，衡陽又耒陽。不堪思北客，從此入南荒。',48,'御定全唐詩/json/843.json','["繞嶽複沿湘，衡陽又耒陽。不堪思北客，從此入南荒。", "旦夕多猿狖，淹留少雪霜。因經杜公墓，惆悵學文章。"]'),
('yuding-13','舟中晚望祝融峰','齊己','唐','御定全唐诗','yuding','','[]','天際卓寒青，舟中望晚晴。十年關夢寐，此日向崢嶸。',48,'御定全唐詩/json/843.json','["天際卓寒青，舟中望晚晴。十年關夢寐，此日向崢嶸。", "巨石淩空黑，飛泉照夜明。終當躡孤頂，坐看白雲生。"]'),
('yuding-14','吊杜工部墳','齊己','唐','御定全唐诗','yuding','','[]','鵬翅蹋於斯，明君知不知。域中詩價大，荒外土墳卑。',48,'御定全唐詩/json/843.json','["鵬翅蹋於斯，明君知不知。域中詩價大，荒外土墳卑。", "瘴雨無時滴，蠻風有穴吹。唯應李太白，魂魄往來疲。"]'),
('yuding-15','岳中寄殷處士','齊己','唐','御定全唐诗','yuding','','[]','出岳與入嶽，前題繼後題。遍尋僧壁上，多在雁峰西。',48,'御定全唐詩/json/843.json','["出岳與入嶽，前題繼後題。遍尋僧壁上，多在雁峰西。", "近說游江寺，將誰話石梯。相思立高巘，山下草萋萋。"]'),
('yuding-16','送幽禪師','齊己','唐','御定全唐诗','yuding','','[]','霜繁野葉飛，長老卷行衣。浮世不知處，白雲相待歸。',48,'御定全唐詩/json/843.json','["霜繁野葉飛，長老卷行衣。浮世不知處，白雲相待歸。", "磬和天籟響，禪動岳神威。莫便言長往，勞生待發機。"]'),
('yuding-17','觀燒','齊己','唐','御定全唐诗','yuding','','[]','獵獵寒蕪引，承風勢不還。放來應有主，焚去到何山。',48,'御定全唐詩/json/843.json','["獵獵寒蕪引，承風勢不還。放來應有主，焚去到何山。", "焰入空蒙裏，煙飛蒼莽間。石中有良玉，惆悵但傷顏。"]'),
('yuding-18','詠茶十二韻','齊己','唐','御定全唐诗','yuding','','[]','百草讓為靈，功先百草成。甘傳天下口，貴占火前名。',144,'御定全唐詩/json/843.json','["百草讓為靈，功先百草成。甘傳天下口，貴占火前名。", "出處春無雁，收時穀有鶯。封題從澤國，貢獻入秦京。", "嗅覺精新極，嘗知骨自輕。研通天柱響，摘繞蜀山明。", "賦客秋吟起，禪師晝臥驚。角開香滿室，爐動綠凝鐺。", "晚憶涼泉對，閑思異果平。松黃幹旋泛，雲母滑隨傾。", "頗貴高人寄，尤宜別匱盛。曾尋修事法，妙盡陸先生。"]'),
('yuding-19','寄陽岐西峰僧','齊己','唐','御定全唐诗','yuding','','[]','西峰殘照東，瀑布灑冥鴻。閑憶高窗外，秋晴萬里空。',48,'御定全唐詩/json/843.json','["西峰殘照東，瀑布灑冥鴻。閑憶高窗外，秋晴萬里空。", "藤陰藏石磴，衣毳落杉風。日有誰來覓，層層鳥道中。"]'),
('yuding-20','回雁峰','齊己','唐','御定全唐诗','yuding','','[]','瘴雨過孱顏，危邊有徑盤。壯堪扶壽嶽，靈合置仙壇。',48,'御定全唐詩/json/843.json','["瘴雨過孱顏，危邊有徑盤。壯堪扶壽嶽，靈合置仙壇。", "影北鴻聲亂，青南客道難。他年思隱遁，何處憑闌幹。"]'),
('yuding-21','贈詢公上人','齊己','唐','御定全唐诗','yuding','','[]','威儀何貴重，一室貯水清。終日松杉徑，自多蟲蟻行。',48,'御定全唐詩/json/843.json','["威儀何貴重，一室貯水清。終日松杉徑，自多蟲蟻行。", "像前孤立影，鐘外數珠聲。知悟修來事，今為第幾生。"]'),
('yuding-22','秋興','齊己','唐','御定全唐诗','yuding','','[]','所見背時情，閑行亦獨行。晚涼思水石，危閣望崢嶸。',48,'御定全唐詩/json/843.json','["所見背時情，閑行亦獨行。晚涼思水石，危閣望崢嶸。", "雨外殘雲片，風中亂葉聲。舊山吟友在，相憶夢應清。"]'),
('yuding-23','古寺老松','齊己','唐','御定全唐诗','yuding','','[]','百歲禪師說，先師指此松。小年行道繞，早見偃枝重。',48,'御定全唐詩/json/843.json','["百歲禪師說，先師指此松。小年行道繞，早見偃枝重。", "月檻移孤影，秋亭卓一峰。終當因夜電，拏攫從雲龍。"]'),
('yuding-24','題無餘處士書齋','齊己','唐','御定全唐诗','yuding','','[]','閑地從莎蘚，誰人愛此心。琴棋懷客遠，風雪閉門深。',48,'御定全唐詩/json/843.json','["閑地從莎蘚，誰人愛此心。琴棋懷客遠，風雪閉門深。", "枕外江灘響，窗西樹石陰。他年衡嶽寺，為我一相尋。"]'),
('yuding-25','歲暮江寺住','齊己','唐','御定全唐诗','yuding','','[]','山依枯槁容，何處見年終。風雪軍城外，蒹葭古寺中。',48,'御定全唐詩/json/843.json','["山依枯槁容，何處見年終。風雪軍城外，蒹葭古寺中。", "孤村誰認磬，極浦夜鳴鴻。坐憶匡廬隱，泉聲滴半空。"]'),
('yuding-26','新燕','齊己','唐','御定全唐诗','yuding','','[]','棲托近佳人，應憐巧語新。風光華屋暖，弦管牡丹晨。',48,'御定全唐詩/json/843.json','["棲托近佳人，應憐巧語新。風光華屋暖，弦管牡丹晨。", "遠采江泥膩，雙飛麥雨勻。差池自有便，敢觸杏梁塵。"]'),
('yuding-27','喻吟','齊己','唐','御定全唐诗','yuding','','[]','日用是何專，吟疲即坐禪。此生還可喜，餘事不相便。',48,'御定全唐詩/json/843.json','["日用是何專，吟疲即坐禪。此生還可喜，餘事不相便。", "頭白無邪裏，魂清有象先。江花與芳草，莫染我情田。"]'),
('yuding-28','過湘江唐弘書齋','齊己','唐','御定全唐诗','yuding','','[]','四鄰無俗跡，終日大開門。水晚來邊雁，林秋下楚猿。',48,'御定全唐詩/json/843.json','["四鄰無俗跡，終日大開門。水晚來邊雁，林秋下楚猿。", "一家隨難在，雙眼向書昏。沈近騷人廟，吟應見古魂。"]'),
('yuding-29','讀賈島集','齊己','唐','御定全唐诗','yuding','','[]','遺篇三百首，首首是遺冤。知到千年外，更逢何者論。',48,'御定全唐詩/json/843.json','["遺篇三百首，首首是遺冤。知到千年外，更逢何者論。", "離秦空得罪，入蜀但聽猿。還似長沙祖，唯餘賦鵩言。"]'),
('yuding-30','寄山中諸友','齊己','唐','御定全唐诗','yuding','','[]','自歸城裏寺，長憶宿山門。終夜冥心客，諸峰叫月猿。',48,'御定全唐詩/json/843.json','["自歸城裏寺，長憶宿山門。終夜冥心客，諸峰叫月猿。", "嵐光生眼力，泉滴爽吟魂。只待游方遍，還來掃樹根。"]'),
('yuding-31','懷終南僧','齊己','唐','御定全唐诗','yuding','','[]','擾擾一京塵，何門是了因。萬重千疊嶂，一去不來人。',48,'御定全唐詩/json/843.json','["擾擾一京塵，何門是了因。萬重千疊嶂，一去不來人。", "鳥道春殘雪，蘿龕晝定身。寥寥石窗外，天籟動衣巾。"]'),
('yuding-32','送二友生歸宜陽','齊己','唐','御定全唐诗','yuding','','[]','二生俱我友，清苦輩流稀。舊國居相近，孤帆秋共歸。',48,'御定全唐詩/json/843.json','["二生俱我友，清苦輩流稀。舊國居相近，孤帆秋共歸。", "殘陽沙鳥亂，疏雨島楓飛。幾宿多山處，猿啼燭影微。"]'),
('yuding-33','懷從弟','齊己','唐','御定全唐诗','yuding','','[]','孤窗燭影微，何事阻吟思。兄弟斷消息，山川長路岐。',48,'御定全唐詩/json/843.json','["孤窗燭影微，何事阻吟思。兄弟斷消息，山川長路岐。", "日沈棲鶴塢，霜著叫猿枝。可想為懷抱，多愁多難時。"]'),
('yuding-34','岳陽道中作','齊己','唐','御定全唐诗','yuding','','[]','客思尋常動，未如今斷魂。路岐經亂後，風雪少人村。',48,'御定全唐詩/json/843.json','["客思尋常動，未如今斷魂。路岐經亂後，風雪少人村。", "大澤鳴寒雁，千峰啼晝猿。爭教此時白，不上鬢鬚根。"]'),
('yuding-35','赴鄭谷郎中招游龍興觀讀題詩板謁七真儀像因有十八韻','齊己','唐','御定全唐诗','yuding','','[]','何處陪游勝，龍興古觀時。詩懸大雅作，殿禮七真儀。',216,'御定全唐詩/json/843.json','["何處陪游勝，龍興古觀時。詩懸大雅作，殿禮七真儀。", "遠繼周南美，彌旌拱北思。雄方垂朴略，後輩仰箴規。", "對坐茵花暖，偕行蘚陣隳。僧絛初學結，朝服久慵披。", "到處琴棋傍，登樓筆硯隨。論禪忘視聽，譚老極希夷。", "照日江光遠，遮軒檜影欹。觸鞋松子響，窺立鶴雛癡。", "始貴茶巡爽，終憐酒散遲。放懷還把杖，憩石或支頤。", "眺遠凝清眄，吟高動白髭。風鵬心不小，蒿雀志徒卑。", "顧我專無作，于身忘有為。叨因五字解，每忝重言期。", "舍此應休也，何人更賞之。淹留仙境晚，回騎雪風吹。"]'),
('yuding-36','書李秀才壁','齊己','唐','御定全唐诗','yuding','','[]','干戈阻上日，南國寄貧居。舊裏荒應盡，新年病未除。',48,'御定全唐詩/json/843.json','["干戈阻上日，南國寄貧居。舊裏荒應盡，新年病未除。", "窗風連島樹，門徑接鄰蔬。我有閑來約，相看雪滿株。"]'),
('yuding-37','聞尚顏下世','齊己','唐','御定全唐诗','yuding','','[]','嶽僧傳的信，聞在麓山亡。郡有為詩客，誰來一影堂。',48,'御定全唐詩/json/843.json','["嶽僧傳的信，聞在麓山亡。郡有為詩客，誰來一影堂。", "夢休尋灞滻，跡已絕瀟湘。遠憶同吟石，新秋檜柏涼。"]'),
('yuding-38','薔薇','齊己','唐','御定全唐诗','yuding','','[]','根本似玫瑰，繁英刺外開。香高叢有架，紅落地多苔。',48,'御定全唐詩/json/843.json','["根本似玫瑰，繁英刺外開。香高叢有架，紅落地多苔。", "去住閒人看，晴明遠蝶來。牡丹先幾日，銷歇向塵埃。"]'),
('yuding-39','送隆公上人','齊己','唐','御定全唐诗','yuding','','[]','獨攜譚柄去，千里指人寰。未斷生徒望，難教白日閑。',48,'御定全唐詩/json/843.json','["獨攜譚柄去，千里指人寰。未斷生徒望，難教白日閑。", "空江橫落照，大府向西山。好騁陳那孔，誰雲劫石頑。"]'),
('yuding-40','宿簡寂觀','齊己','唐','御定全唐诗','yuding','','[]','萬壑雲霞影，千年松檜聲。如何教下士，容易信長生。',48,'御定全唐詩/json/843.json','["萬壑雲霞影，千年松檜聲。如何教下士，容易信長生。", "月共虛無白，香和沆瀣清。閑尋古廊畫，記得列仙名。"]'),
('yuding-41','遇元上人','齊己','唐','御定全唐诗','yuding','','[]','七澤過名山，相逢黃落殘。杉鬆開寺晚，泉月話心寒。',48,'御定全唐詩/json/843.json','["七澤過名山，相逢黃落殘。杉鬆開寺晚，泉月話心寒。", "祖遍諸方禮，經曾幾處看。應懷出家院，紫閣近長安。"]'),
('yuding-42','早梅','齊己','唐','御定全唐诗','yuding','','[]','萬木凍欲折，孤根暖獨回。前村深雪裏，昨夜一枝開。',48,'御定全唐詩/json/843.json','["萬木凍欲折，孤根暖獨回。前村深雪裏，昨夜一枝開。", "風遞幽香去，禽窺素豔來。明年如應律，先發映春台。"]'),
('yuding-43','聽泉','齊己','唐','御定全唐诗','yuding','','[]','落石幾萬仞，冷聲飄遠空。高秋初雨後，半夜亂山中。',48,'御定全唐詩/json/843.json','["落石幾萬仞，冷聲飄遠空。高秋初雨後，半夜亂山中。", "只有照壁月，更無吹葉風。幾曾廬嶽聽，到曉與僧同。"]'),
('yuding-44','送孫逸人歸廬山','齊己','唐','御定全唐诗','yuding','','[]','獨自擔琴鶴，還歸瀑布東。逍遙非俗趣，楊柳謾春風。',48,'御定全唐詩/json/843.json','["獨自擔琴鶴，還歸瀑布東。逍遙非俗趣，楊柳謾春風。", "草繞村程綠，花磐石磴紅。他時許相覓，五老亂雲中。"]'),
('yuding-45','聽李尊師彈琴','齊己','唐','御定全唐诗','yuding','','[]','仙子弄瑤琴，仙山松月深。此聲含太古，誰聽到無心。',48,'御定全唐詩/json/843.json','["仙子弄瑤琴，仙山松月深。此聲含太古，誰聽到無心。", "灑石霜千片，噴崖泉萬尋。何人傳指法，攜向海中岑。"]'),
('yuding-46','寄武陵微上人','齊己','唐','御定全唐诗','yuding','','[]','善卷台邊寺，松筠繞祖堂。秋聲度風雨，曉色遍滄浪。',48,'御定全唐詩/json/843.json','["善卷台邊寺，松筠繞祖堂。秋聲度風雨，曉色遍滄浪。", "白石同誰坐，清吟過我狂。近聞為古律，雅道更重光。"]'),
('yuding-47','匡山寓居棲公','齊己','唐','御定全唐诗','yuding','','[]','外物盡已外，閒遊且自由。好山逢過夏，無事住經秋。',48,'御定全唐詩/json/843.json','["外物盡已外，閒遊且自由。好山逢過夏，無事住經秋。", "樹影殘陽寺，茶香古石樓。何時定休講，歸漱虎溪流。"]'),
('yuding-48','湘西道林寺陶太尉井','齊己','唐','御定全唐诗','yuding','','[]','太尉遺孤井，寒澄七百年。未聞陵穀變，終與姓名傳。',48,'御定全唐詩/json/843.json','["太尉遺孤井，寒澄七百年。未聞陵穀變，終與姓名傳。", "影浸無風樹，光含有月天。林僧曉來此，滿汲灑金田。"]'),
('yuding-49','寄松江陸龜蒙處士','齊己','唐','御定全唐诗','yuding','','[]','萬卷功何用，徒稱處士休。閑欹太湖石，醉聽洞庭秋。',48,'御定全唐詩/json/843.json','["萬卷功何用，徒稱處士休。閑欹太湖石，醉聽洞庭秋。", "道在誰開口，詩成自點頭。中間欲相訪，尋便阻戈矛。"]'),
('yuding-50','閉門','齊己','唐','御定全唐诗','yuding','','[]','外事休關念，灰心獨閉門。無人來問我，白日又黃昏。',48,'御定全唐詩/json/843.json','["外事休關念，灰心獨閉門。無人來問我，白日又黃昏。", "燈集飛蛾影，窗銷迸雪痕。中心自明瞭，一句祖師言。"]'),
('yuding-51','看水','齊己','唐','御定全唐诗','yuding','','[]','範蠡東浮闊，靈均北泛長。誰知遠煙浪，別有好思量。',48,'御定全唐詩/json/843.json','["範蠡東浮闊，靈均北泛長。誰知遠煙浪，別有好思量。", "故國門前急，天涯照裏忙。難收上樓興，渺漫正斜陽。"]'),
('yuding-52','寄棲白上人','齊己','唐','御定全唐诗','yuding','','[]','萬國爭名地，吾師獨此閑。題詩招上相，看雪下南山。',48,'御定全唐詩/json/843.json','["萬國爭名地，吾師獨此閑。題詩招上相，看雪下南山。", "內殿承恩久，中條進表還。常因秋貢客，少得掩禪關。"]'),
('yuding-53','自題','齊己','唐','御定全唐诗','yuding','','[]','禪外求詩妙，年來鬢已秋。未嘗將一字，容易謁諸侯。',48,'御定全唐詩/json/843.json','["禪外求詩妙，年來鬢已秋。未嘗將一字，容易謁諸侯。", "掛夢山皆遠，題名石盡幽。敢言梁太子，傍采碧雲流。"]'),
('yuding-54','孫支使來借詩集，因有謝','齊己','唐','御定全唐诗','yuding','','[]','冥搜從少小，隨分得淳元。聞說吟僧口，多傳過蜀門。',48,'御定全唐詩/json/843.json','["冥搜從少小，隨分得淳元。聞說吟僧口，多傳過蜀門。", "相尋江島上，共看夏雲根。坐落遲遲日，新題互把論。"]'),
('yuding-55','夏日言懷','齊己','唐','御定全唐诗','yuding','','[]','苦被流年迫，衰羸老病情。得歸青嶂死，便共白雲生。',48,'御定全唐詩/json/843.json','["苦被流年迫，衰羸老病情。得歸青嶂死，便共白雲生。", "樹枿燒爐響，崖棱躡屐聲。此心人信否，魂夢自分明。"]'),
('yuding-56','早秋寄友生','齊己','唐','御定全唐诗','yuding','','[]','雨多殘暑歇，蟬急暮風清。誰有閒心去，江邊看水行。',48,'御定全唐詩/json/843.json','["雨多殘暑歇，蟬急暮風清。誰有閒心去，江邊看水行。", "河遙紅蓼簇，野闊白煙平。試折秋蓮葉，題詩寄竺卿。"]'),
('yuding-57','送王秀才往松滋夏課','齊己','唐','御定全唐诗','yuding','','[]','松滋聞古縣，明府是詩家。靜理餘無事，欹眠盡落花。',48,'御定全唐詩/json/843.json','["松滋聞古縣，明府是詩家。靜理餘無事，欹眠盡落花。", "江光搖夕照，柳影帶殘霞。君去應相與，乘船泛月華。"]'),
('yuding-58','喜z6公自武陵至','齊己','唐','御定全唐诗','yuding','','[]','已盡滄浪興，還思相楚行。鬢全無舊黑，詩別有新清。',48,'御定全唐詩/json/843.json','["已盡滄浪興，還思相楚行。鬢全無舊黑，詩別有新清。", "暫憩臨寒水，時來扣靜荊。囊中有靈藥，終不獻公卿。"]'),
('yuding-59','假山','齊己','唐','御定全唐诗','yuding','','[]','匡廬久別離，積翠杳天涯。靜室曾圖峭，幽亭複創奇。',216,'御定全唐詩/json/843.json','["匡廬久別離，積翠杳天涯。靜室曾圖峭，幽亭複創奇。", "典衣酬土價，擇日運工時。信手成重疊，隨心作蔽虧。", "根盤驚院窄，頂聳訝簷卑。鎮地那言重，當軒未厭危。", "巨靈何忍擘，秦政肯輕移。晚覺莎煙觸，寒聞竹籟吹。", "藍灰澄古色，泥水合凝滋。引看僧來數，牽吟客散遲。", "九華渾仿佛，五老頗參差。蛛網藤蘿掛，春霖瀑布垂。", "加添雙石筍，映帶小蓮池。舊說雷居士，曾聞遠大師。", "紅霞中結社，白壁上題詩。顧此誠徒爾，勞心是妄為。", "經營慚培塿，賞玩愧童兒。會入千峰去，閑蹤任屬誰。"]'),
('yuding-60','謝西川可准上人遠寄詩集','齊己','唐','御定全唐诗','yuding','','[]','匡社經行外，沃洲禪宴餘。吾師還繼此，後輩複何如。',48,'御定全唐詩/json/843.json','["匡社經行外，沃洲禪宴餘。吾師還繼此，後輩複何如。", "江上傳風雅，靜中時卷舒。堪隨樂天集，共伴白芙蕖。"]'),
('yuding-61','秋空','齊己','唐','御定全唐诗','yuding','','[]','已覺秋空極，更堪寥泬青。只應容好月，爭合有妖星。',48,'御定全唐詩/json/843.json','["已覺秋空極，更堪寥泬青。只應容好月，爭合有妖星。", "耿耿高河截，翛翛一雁經。曾於洞庭宿，上下徹心靈。"]'),
('yuding-62','與聶尊師話道','齊己','唐','御定全唐诗','yuding','','[]','伯陽遺妙旨，杳杳與冥冥。說即非難說，行還不易行。',48,'御定全唐詩/json/843.json','["伯陽遺妙旨，杳杳與冥冥。說即非難說，行還不易行。", "藥中迷九轉，心外覓長生。畢竟荒原上，一盤蒿隴平。"]'),
('yuding-63','送相裏秀才自京至卻回','齊己','唐','御定全唐诗','yuding','','[]','夷門詩客至，楚寺閉蕭騷。老病語言澀，少年風韻高。',48,'御定全唐詩/json/843.json','["夷門詩客至，楚寺閉蕭騷。老病語言澀，少年風韻高。", "難於尋閬島，險甚涉雲濤。珍重西歸去，無忘役思勞。"]'),
('yuding-64','謝人寄南榴卓子','齊己','唐','御定全唐诗','yuding','','[]','幸附全材長，良工劚器殊。千林文柏有，一尺錦榴無。',48,'御定全唐詩/json/843.json','["幸附全材長，良工劚器殊。千林文柏有，一尺錦榴無。", "品格宜仙果，精光稱玉壺。憐君遠相寄，多愧野蔬粗。"]'),
('yuding-65','寄舊居鄰友','齊己','唐','御定全唐诗','yuding','','[]','別後知何趣，搜奇少客同。幾層山影下，萬樹雪聲中。',48,'御定全唐詩/json/843.json','["別後知何趣，搜奇少客同。幾層山影下，萬樹雪聲中。", "晚鼎烹茶綠，晨廚爨粟紅。何時攜卷出，世代有名公。"]'),
('yuding-66','送朱秀才歸閩','齊己','唐','御定全唐诗','yuding','','[]','荊門來幾日，欲往又囊空。遠客歸南越，單衣背北風。',48,'御定全唐詩/json/843.json','["荊門來幾日，欲往又囊空。遠客歸南越，單衣背北風。", "近鄉微有雪，到海漸無鴻。努力成詩業，無謀謁至公。"]'),
('yuding-67','龍潭作','齊己','唐','御定全唐诗','yuding','','[]','乍臨毛髮豎，雙壁夾湍流。白日鳥影過，青苔龍氣浮。',48,'御定全唐詩/json/843.json','["乍臨毛髮豎，雙壁夾湍流。白日鳥影過，青苔龍氣浮。", "蔽空雲出石，應禱雨翻湫。四面耕桑者，先聞賀有秋。"]'),
('yuding-68','依韻酬謝尊師見贈二首','齊己','唐','御定全唐诗','yuding','','[]','南國搜奇久，偏傷杜甫墳。重來經漢浦，又去入嵩雲。',96,'御定全唐詩/json/843.json','["南國搜奇久，偏傷杜甫墳。重來經漢浦，又去入嵩雲。", "舊別人稀見，新朝事漸聞。莫將高尚跡，閑處傲明君。", "岳頂休高臥，荊門訪掩扉。新詩遺我別，舊約與誰歸。", "賢路曾無滯，良時肯自違。明年窺日窟，仙桂露霏微。"]'),
('yuding-69','送冰禪再往湖中','齊己','唐','御定全唐诗','yuding','','[]','行心寧肯住，南去與誰群。碧落高空處，清秋一片雲。',48,'御定全唐詩/json/843.json','["行心寧肯住，南去與誰群。碧落高空處，清秋一片雲。", "穿林瓶影滅，背雨錫聲分。應笑游方久，龍鍾楚水濆。"]'),
('yuding-70','喜表公往楚王城','齊己','唐','御定全唐诗','yuding','','[]','已聞人舍地，結構舊基平。一面湖光白，鄰家竹影清。',48,'御定全唐詩/json/843.json','["已聞人舍地，結構舊基平。一面湖光白，鄰家竹影清。", "應難尋輦道，空說是王城。誰信興亡跡，今來有磬聲。"]'),
('yuding-71','春雪初晴喜友生至','齊己','唐','御定全唐诗','yuding','','[]','數日不見日，飄飄勢忽開。雖無忙事出，還有故人來。',48,'御定全唐詩/json/843.json','["數日不見日，飄飄勢忽開。雖無忙事出，還有故人來。", "已盡南簷滴，仍殘北牖堆。明朝望平遠，相約在春台。"]'),
('yuding-72','殘春連雨中偶作懷故人','齊己','唐','御定全唐诗','yuding','','[]','南鄰阻杖藜，屐齒繞床泥。漠漠門長掩，遲遲日又西。',48,'御定全唐詩/json/843.json','["南鄰阻杖藜，屐齒繞床泥。漠漠門長掩，遲遲日又西。", "不知何興味，更有好詩題。還憶東林否，行苔傍虎溪。"]'),
('yuding-73','送崔判官赴歸倅','齊己','唐','御定全唐诗','yuding','','[]','白首從顏巷，青袍去佐官。只應微俸祿，聊補舊饑寒。',48,'御定全唐詩/json/843.json','["白首從顏巷，青袍去佐官。只應微俸祿，聊補舊饑寒。", "地說丘墟甚，民聞旱歉殘。春風吹綺席，賓主醉相歡。"]'),
('yuding-74','寒食日懷寄友人','齊己','唐','御定全唐诗','yuding','','[]','萬井追寒食，閑扉獨不開。梨花應折盡，柳絮自飛來。',48,'御定全唐詩/json/843.json','["萬井追寒食，閑扉獨不開。梨花應折盡，柳絮自飛來。", "夢覺懷仙島，吟行繞砌苔。浮生已悟了，時節任相催。"]'),
('yuding-75','懷巴陵舊游','齊己','唐','御定全唐诗','yuding','','[]','洞庭雲夢秋，空碧共悠悠。孟子狂題後，何人更倚樓。',48,'御定全唐詩/json/843.json','["洞庭雲夢秋，空碧共悠悠。孟子狂題後，何人更倚樓。", "日西來遠棹，風外見平流。終欲重尋去，僧窗古岸頭。"]'),
('yuding-76','招幹晝上人宿話','齊己','唐','御定全唐诗','yuding','','[]','連夜因風雪，相留在寂寥。禪心誰指示，詩卷自焚燒。',48,'御定全唐詩/json/843.json','["連夜因風雪，相留在寂寥。禪心誰指示，詩卷自焚燒。", "語默鄰寒漏，窗扉向早朝。天臺若長往，還渡海門潮。"]'),
('yuding-77','荊門秋日寄友人','齊己','唐','御定全唐诗','yuding','','[]','青溪知不遠，白首要難歸。空想煙雲裏，春風鸞鶴飛。',48,'御定全唐詩/json/843.json','["青溪知不遠，白首要難歸。空想煙雲裏，春風鸞鶴飛。", "誰論傳法偈，自補坐禪衣。未謝侯門去，尋常即掩扉。"]'),
('yuding-78','哭鄭谷郎中','齊己','唐','御定全唐诗','yuding','','[]','朝衣閑典盡，酒病覺難醫。下世無遺恨，傳家有大詩。',48,'御定全唐詩/json/843.json','["朝衣閑典盡，酒病覺難醫。下世無遺恨，傳家有大詩。", "新墳青嶂疊，寒食白雲垂。長憶招吟夜，前年風雪時。"]'),
('yuding-0','題東林十八賢真堂','齊己','唐','御定全唐诗','yuding','','[]','白藕花前舊影堂，劉雷風骨畫龍章。共輕天子諸侯貴，',40,'御定全唐詩/json/844.json','["白藕花前舊影堂，劉雷風骨畫龍章。共輕天子諸侯貴，", "何人到此思高躅，嵐點苔痕滿粉牆。"]'),
('yuding-1','題南嶽般若寺','齊己','唐','御定全唐诗','yuding','','[]','諸峰翠少中峰翠，五寺名高此寺名。石路險盤嵐靄滑，',40,'御定全唐詩/json/844.json','["諸峰翠少中峰翠，五寺名高此寺名。石路險盤嵐靄滑，", "更有上方難上處，紫苔紅蘚繞崢嶸。"]'),
('yuding-2','寄廬岳僧','齊己','唐','御定全唐诗','yuding','','[]','一聞飛錫別區中，深入西南瀑布峰。天際雪埋千片石，',40,'御定全唐詩/json/844.json','["一聞飛錫別區中，深入西南瀑布峰。天際雪埋千片石，", "莫問江邊舊居寺，火燒兵劫斷秋鐘。"]'),
('yuding-3','游穀山寺','齊己','唐','御定全唐诗','yuding','','[]','城裏尋常見碧棱，水邊朝暮送歸僧。數峰雲腳垂平地，',40,'御定全唐詩/json/844.json','["城裏尋常見碧棱，水邊朝暮送歸僧。數峰雲腳垂平地，", "此身有底難拋事，時複攜筇信步登。"]'),
('yuding-4','楚寺寒夜作','齊己','唐','御定全唐诗','yuding','','[]','寒爐局促坐成勞，暗淡燈光照二毛。水寺閑來僧寂寂，',40,'御定全唐詩/json/844.json','["寒爐局促坐成勞，暗淡燈光照二毛。水寺閑來僧寂寂，", "畢竟忘言是吾道，袈裟不稱揖蕭曹。"]'),
('yuding-5','送泰禪師歸南嶽','齊己','唐','御定全唐诗','yuding','','[]','石龕閑鎖白猿邊，歸去程途半在船。林簇曉霜離水寺，',40,'御定全唐詩/json/844.json','["石龕閑鎖白猿邊，歸去程途半在船。林簇曉霜離水寺，", "有興寄題紅葉上，不妨收拾別為編。"]'),
('yuding-6','山中寄凝密大師兄弟','齊己','唐','御定全唐诗','yuding','','[]','一爐薪盡室空然，萬象何妨在眼前。時有興來還覓句，',40,'御定全唐詩/json/844.json','["一爐薪盡室空然，萬象何妨在眼前。時有興來還覓句，", "借問荀家兄弟內，八龍頭角讓誰先。"]'),
('yuding-7','海棠花','齊己','唐','御定全唐诗','yuding','','[]','繁于桃李盛于梅，寒食旬前社後開。半月暄和留豔態，',40,'御定全唐詩/json/844.json','["繁于桃李盛于梅，寒食旬前社後開。半月暄和留豔態，", "猶得殘紅向春暮，牡丹相繼發池台。"]'),
('yuding-8','題贈湘西龍安寺利禪師','齊己','唐','御定全唐诗','yuding','','[]','頭白已無行腳念，自開荒寺住煙蘿。門前路到瀟湘盡，',40,'御定全唐詩/json/844.json','["頭白已無行腳念，自開荒寺住煙蘿。門前路到瀟湘盡，", "閑來松外看城郭，一片紅塵隔逝波。"]'),
('yuding-9','寄文浩百法','齊己','唐','御定全唐诗','yuding','','[]','當時六祖在黃梅，五百人中眼獨開。入室偈聞傳絕唱，',40,'御定全唐詩/json/844.json','["當時六祖在黃梅，五百人中眼獨開。入室偈聞傳絕唱，", "聞說欲拋經論去，莫教惆悵卻空回。"]'),
('yuding-10','謝人寄新詩集','齊己','唐','御定全唐诗','yuding','','[]','所聞新事即戈矛，欲去終疑是暗投。遠客寄言還有在，',40,'御定全唐詩/json/844.json','["所聞新事即戈矛，欲去終疑是暗投。遠客寄言還有在，", "時入思量向何處，月圓孤憑水邊樓。"]'),
('yuding-11','《謝元願上人遠寄檀溪集》','齊己','唐','御定全唐诗','yuding','','[]','白首蕭條居漢浦，清吟編集號檀溪。有人收拾應如玉，',40,'御定全唐詩/json/844.json','["白首蕭條居漢浦，清吟編集號檀溪。有人收拾應如玉，", "猶能為我相思在，千里封來夢澤西。"]'),
('yuding-12','寄道林寺諸友','齊己','唐','御定全唐诗','yuding','','[]','吟興終依異境長，舊游時入靜思量。江聲裏過東西寺，',40,'御定全唐詩/json/844.json','["吟興終依異境長，舊游時入靜思量。江聲裏過東西寺，", "老來何計重歸去，千里重湖浪渺茫。"]'),
('yuding-13','贈智滿三藏','齊己','唐','御定全唐诗','yuding','','[]','灌頂清涼一滴通，大毗盧藏遍虛空。欲飛薝蔔花無盡，',40,'御定全唐詩/json/844.json','["灌頂清涼一滴通，大毗盧藏遍虛空。欲飛薝蔔花無盡，", "可堪東獻明天子，命服新酬贊國風。"]'),
('yuding-14','謝王先輩湘中回惠示卷軸','齊己','唐','御定全唐诗','yuding','','[]','少小即懷風雅情，獨能遺象琢淳精。不教霜雪侵玄鬢，',40,'御定全唐詩/json/844.json','["少小即懷風雅情，獨能遺象琢淳精。不教霜雪侵玄鬢，", "多君百首貽衰颯，留把吟行訪竺卿。"]'),
('yuding-15','荊渚寄懷西蜀無染大師兄','齊己','唐','御定全唐诗','yuding','','[]','大溈心付白崖前，寶月分輝照蜀天。聖主降情延北內，',40,'御定全唐詩/json/844.json','["大溈心付白崖前，寶月分輝照蜀天。聖主降情延北內，", "欲聽吾宗舊山說，地邊身老楚江邊。"]'),
('yuding-16','謝武陵徐巡官遠寄五七字詩集','齊己','唐','御定全唐诗','yuding','','[]','五字才將七字爭，為君聊敢試懸衡。鼎湖菡萏搖金影，',40,'御定全唐詩/json/844.json','["五字才將七字爭，為君聊敢試懸衡。鼎湖菡萏搖金影，", "兩邊珍重遙相惠，何夕燈前盡此情。"]'),
('yuding-17','重宿舊房與愚上人靜話','齊己','唐','御定全唐诗','yuding','','[]','曾此棲心過十冬，今來瀟灑屬生公。檀欒舊植青添翠，',40,'御定全唐詩/json/844.json','["曾此棲心過十冬，今來瀟灑屬生公。檀欒舊植青添翠，", "不知門下趨筵士，何似當時石解空。"]'),
('yuding-18','謝南平王賜山雞','齊己','唐','御定全唐诗','yuding','','[]','五色文章類彩鸞，楚人羅得半摧殘。金籠莫恨傷冠幘，',40,'御定全唐詩/json/844.json','["五色文章類彩鸞，楚人羅得半摧殘。金籠莫恨傷冠幘，", "上臺愛育通幽細，卻放溪山去不難。"]'),
('yuding-19','荊門病中雨後書懷寄幕中知己','齊己','唐','御定全唐诗','yuding','','[]','病根翻作憶山勞，一雨聊堪浣郁陶。心白未能忘水月，',40,'御定全唐詩/json/844.json','["病根翻作憶山勞，一雨聊堪浣郁陶。心白未能忘水月，", "還憶赤松兄弟否，別來應見鶴衣毛。"]'),
('yuding-20','宿江寺','齊己','唐','御定全唐诗','yuding','','[]','島僧留宿慰衰顏，舊住何妨老未還。身共錫聲離鳥外，',40,'御定全唐詩/json/844.json','["島僧留宿慰衰顏，舊住何妨老未還。身共錫聲離鳥外，", "珍重來晨渡江去，九華青裏扣松關。"]'),
('yuding-21','謝貫微上人寄示古風今體四軸','齊己','唐','御定全唐诗','yuding','','[]','四軸騷詞書八行，捧吟肌骨遍清涼。謾求龍樹能醫眼，',40,'御定全唐詩/json/844.json','["四軸騷詞書八行，捧吟肌骨遍清涼。謾求龍樹能醫眼，", "不知誰肯降文陣，闇點旌旗敵子房。"]'),
('yuding-22','荊州貫休大師舊房','齊己','唐','御定全唐诗','yuding','','[]','疏篁抽筍柳垂陰，舊是休公種境吟。入貢文儒來請益，',40,'御定全唐詩/json/844.json','["疏篁抽筍柳垂陰，舊是休公種境吟。入貢文儒來請益，", "銷得青城千嶂下，白蓮標塔帝恩深。"]'),
('yuding-23','寄谷山長老','齊己','唐','御定全唐诗','yuding','','[]','游遍名山祖遍尋，卻來塵世渾光陰。肯將的的吾師意，',40,'御定全唐詩/json/844.json','["游遍名山祖遍尋，卻來塵世渾光陰。肯將的的吾師意，", "滄浪萬頃三更月，天上何如水底深。"]'),
('yuding-24','寄黃暉處士','齊己','唐','御定全唐诗','yuding','','[]','蒙氏藝傳黃氏子，獨聞相繼得名高。鋒鋩妙奪金雞距，',40,'御定全唐詩/json/844.json','["蒙氏藝傳黃氏子，獨聞相繼得名高。鋒鋩妙奪金雞距，", "何妨寄我臨池興，忍使江淹役夢勞。"]'),
('yuding-25','荊門勉懷寄道林寺諸友','齊己','唐','御定全唐诗','yuding','','[]','榮枯得失理昭然，誰斅離騷更問天。生下便知真夢幻，',40,'御定全唐詩/json/844.json','["榮枯得失理昭然，誰斅離騷更問天。生下便知真夢幻，", "珍重匡廬沃洲主，拂衣拋卻好林泉。"]'),
('yuding-26','答崔校書','齊己','唐','御定全唐诗','yuding','','[]','雪色衫衣絕點塵，明知富貴是浮雲。不隨喧滑迷真性，',40,'御定全唐詩/json/844.json','["雪色衫衣絕點塵，明知富貴是浮雲。不隨喧滑迷真性，", "清吟有興頻相示，欲得多慚蠹蝕文。"]'),
('yuding-27','乞櫻桃','齊己','唐','御定全唐诗','yuding','','[]','去年曾賦此花詩，幾聽南園爛熟時。嚼破紅香堪換骨，',40,'御定全唐詩/json/844.json','["去年曾賦此花詩，幾聽南園爛熟時。嚼破紅香堪換骨，", "聞說張筵就珠樹，任從攀折半離披。"]'),
('yuding-28','寄南雅上人','齊己','唐','御定全唐诗','yuding','','[]','曾得音書慰暮年，相思多故信難傳。清吟何處題紅葉，',40,'御定全唐詩/json/844.json','["曾得音書慰暮年，相思多故信難傳。清吟何處題紅葉，", "他時不得君招隱，會逐南歸楚客船。"]'),
('yuding-29','寄歐陽侍郎','齊己','唐','御定全唐诗','yuding','','[]','又聞繁總在嘉州，職重身閑倚寺樓。大象影和山面落，',40,'御定全唐詩/json/844.json','["又聞繁總在嘉州，職重身閑倚寺樓。大象影和山面落，", "畢竟男兒自高達，從來心不是悠悠。"]'),
('yuding-30','與崔校書靜話言懷','齊己','唐','御定全唐诗','yuding','','[]','同年生在咸通裏，事佛為儒趣盡高。我性已甘披祖衲，',40,'御定全唐詩/json/844.json','["同年生在咸通裏，事佛為儒趣盡高。我性已甘披祖衲，", "出世朝天俱未得，不妨還往有風騷。"]'),
('yuding-31','謝人惠拄杖','齊己','唐','御定全唐诗','yuding','','[]','邛州靈境產修篁，九節材應表九陽。造化已能分尺度，',40,'御定全唐詩/json/844.json','["邛州靈境產修篁，九節材應表九陽。造化已能分尺度，", "深謝魯儒憐潦倒，欲教撐拄繞禪床。"]'),
('yuding-32','《謝秦府推官寄丹台集》','齊己','唐','御定全唐诗','yuding','','[]','秦王手筆序丹台，不錯褒揚最上才。鳳闕幾傳為匠碩，',40,'御定全唐詩/json/844.json','["秦王手筆序丹台，不錯褒揚最上才。鳳闕幾傳為匠碩，", "兩軸蚌胎驪頷耀，枉臨禪室伴寒灰。"]'),
('yuding-33','題畫鷺鷥兼簡孫郎中','齊己','唐','御定全唐诗','yuding','','[]','曾向滄江看不真，卻因圖畫見精神。何妨金粉資高格，',40,'御定全唐詩/json/844.json','["曾向滄江看不真，卻因圖畫見精神。何妨金粉資高格，", "思量畫得勝籠得，野性由來不戀人。"]'),
('yuding-34','《賀行軍太傅得白氏東林集》','齊己','唐','御定全唐诗','yuding','','[]','樂天歌詠有遺編，留在東林伴白蓮。百尺典墳隨喪亂，',40,'御定全唐詩/json/844.json','["樂天歌詠有遺編，留在東林伴白蓮。百尺典墳隨喪亂，", "仰賀斯文歸朗鑒，永資聲政入熏弦。"]'),
('yuding-35','韶陽微公','齊己','唐','御定全唐诗','yuding','','[]','曲江晴影石千株，吾子思歸夢斷初。有信北來山疊疊，',40,'御定全唐詩/json/844.json','["曲江晴影石千株，吾子思歸夢斷初。有信北來山疊疊，", "閑野老身留得否，相招多是秀才書。"]'),
('yuding-36','將之匡岳過尋陽','齊己','唐','御定全唐诗','yuding','','[]','帆過尋陽晚霽開，西風北雁似相催。大都浪後青堆沒，',40,'御定全唐詩/json/844.json','["帆過尋陽晚霽開，西風北雁似相催。大都浪後青堆沒，", "遠公林下蓮池畔，個個高人盡有才。"]'),
('yuding-37','寄湘幕王重書記','齊己','唐','御定全唐诗','yuding','','[]','拋擲浟江舊釣磯，日參籌畫廢吟詩。可能有事關心後，',40,'御定全唐詩/json/844.json','["拋擲浟江舊釣磯，日參籌畫廢吟詩。可能有事關心後，", "高才直氣平生志，除卻徒知即不知。"]'),
('yuding-38','宿沈彬進士書院','齊己','唐','御定全唐诗','yuding','','[]','相期只為話篇章，踏雪曾來宿此房。喧滑盡消城漏滴，',40,'御定全唐詩/json/844.json','["相期只為話篇章，踏雪曾來宿此房。喧滑盡消城漏滴，", "應有太平時節在，寒宵未臥共思量。"]'),
('yuding-39','靜院','齊己','唐','御定全唐诗','yuding','','[]','花院相重點破苔，誰心肯此話心灰。好風時傍疏篁起，',40,'御定全唐詩/json/844.json','["花院相重點破苔，誰心肯此話心灰。好風時傍疏篁起，", "浮生已問空王了，箭急光陰一任催。"]'),
('yuding-40','送白處士游峨嵋','齊己','唐','御定全唐诗','yuding','','[]','閑身誰道是羈遊，西指峨嵋碧頂頭。琴鶴幾程隨客棹，',40,'御定全唐詩/json/844.json','["閑身誰道是羈遊，西指峨嵋碧頂頭。琴鶴幾程隨客棹，", "莫為寰瀛多事在，客星相逐不回休。"]'),
('yuding-41','寄顧蟾處士','齊己','唐','御定全唐诗','yuding','','[]','久聞為客過蒼梧，休說攜家歸鏡湖。山水顛狂應盡在，',40,'御定全唐詩/json/844.json','["久聞為客過蒼梧，休說攜家歸鏡湖。山水顛狂應盡在，", "春醉醒來有餘興，因人乞與武陵圖。"]'),
('yuding-42','懷金陵知舊','齊己','唐','御定全唐诗','yuding','','[]','海門相別住荊門，六度秋光兩鬢根。萬象倒心難蓋口，',40,'御定全唐詩/json/844.json','["海門相別住荊門，六度秋光兩鬢根。萬象倒心難蓋口，", "儘是共遊題版處，有誰惆悵拂苔痕。"]'),
('yuding-43','喜得自牧上人書','齊己','唐','御定全唐诗','yuding','','[]','吳都使者泛驚濤，靈一傳書慰毳袍。別興偶隨雲水遠，',40,'御定全唐詩/json/844.json','["吳都使者泛驚濤，靈一傳書慰毳袍。別興偶隨雲水遠，", "聞著括囊新集了，擬教誰與序離騷。"]'),
('yuding-44','驚秋','齊己','唐','御定全唐诗','yuding','','[]','曉窗驚覺向秋風，萬里心凝淡蕩中。池影碎翻紅菡萏，',40,'御定全唐詩/json/844.json','["曉窗驚覺向秋風，萬里心凝淡蕩中。池影碎翻紅菡萏，", "妖殺九原狐兔意，豈知丘隴是英雄。"]'),
('yuding-45','聞沈彬赴吳都請辟','齊己','唐','御定全唐诗','yuding','','[]','長訝高眠得穩無，果隨征辟起江湖。鴛鴦已列樽罍貴，',40,'御定全唐詩/json/844.json','["長訝高眠得穩無，果隨征辟起江湖。鴛鴦已列樽罍貴，", "可能更憶相尋夜，雪滿諸峰火一爐。"]'),
('yuding-46','寄江夏仁公','齊己','唐','御定全唐诗','yuding','','[]','寺閣高連黃鶴樓，簷前檻底大江流。幾因秋霽澄空外，',40,'御定全唐詩/json/844.json','["寺閣高連黃鶴樓，簷前檻底大江流。幾因秋霽澄空外，", "別來多少新吟也，不寄南宗老比丘。"]'),
('yuding-47','中春林下偶作','齊己','唐','御定全唐诗','yuding','','[]','淨境無人可共攜，閑眠未起日光低。浮生莫把還丹續，',40,'御定全唐詩/json/844.json','["淨境無人可共攜，閑眠未起日光低。浮生莫把還丹續，", "何能向外求攀折，岩桂枝條拂石梯。"]'),
('yuding-48','送劉秀才歸桑水甯覲','齊己','唐','御定全唐诗','yuding','','[]','歸和初喜戢戈矛，乍捧鄉書感去留。雁序分飛離漢口，',40,'御定全唐詩/json/844.json','["歸和初喜戢戈矛，乍捧鄉書感去留。雁序分飛離漢口，", "應到高堂問安後，卻攜文入帝京遊。"]'),
('yuding-49','寄曹松','齊己','唐','御定全唐诗','yuding','','[]','舊制新題削復刊，工夫過甚琢琅玕。藥中求見黃芽易，',40,'御定全唐詩/json/844.json','["舊制新題削復刊，工夫過甚琢琅玕。藥中求見黃芽易，", "夜來月苦懷高論，數樹霜邊獨傍欄。"]'),
('yuding-50','酬蜀國歐陽學士','齊己','唐','御定全唐诗','yuding','','[]','因緣劉表駐經行，又聽西風墮葉聲。鶴發不堪言此世，',40,'御定全唐詩/json/844.json','["因緣劉表駐經行，又聽西風墮葉聲。鶴發不堪言此世，", "深愧故人憐潦倒，每傳仙語下南荊。"]'),
('yuding-51','寄荊幕孫郎中','齊己','唐','御定全唐诗','yuding','','[]','珠履風流憶富春，三千鵷鷺讓精神。詩工鑿破清求妙，',40,'御定全唐詩/json/844.json','["珠履風流憶富春，三千鵷鷺讓精神。詩工鑿破清求妙，", "別來鄉國魂應斷，劍閣東西盡戰塵。"]'),
('yuding-52','謝王詹事垂訪','齊己','唐','御定全唐诗','yuding','','[]','鳥外孤峰未得歸，人間觸類是無機。方悲鹿軫棲江寺，',40,'御定全唐詩/json/844.json','["鳥外孤峰未得歸，人間觸類是無機。方悲鹿軫棲江寺，", "應驚老病炎天裏，枯骨肩橫一衲衣。"]'),
('yuding-53','題南平後園牡丹','齊己','唐','御定全唐诗','yuding','','[]','暖披煙豔照西園，翠幄朱欄護列仙。玉帳笙歌留盡日，',40,'御定全唐詩/json/844.json','["暖披煙豔照西園，翠幄朱欄護列仙。玉帳笙歌留盡日，", "上客分明記開處，明年開更勝今年。"]'),
('yuding-54','和李書記','齊己','唐','御定全唐诗','yuding','','[]','繁極全分青帝功，開時獨佔上春風。吳姬舞雪非真豔，',40,'御定全唐詩/json/844.json','["繁極全分青帝功，開時獨佔上春風。吳姬舞雪非真豔，", "君看萬態當筵處，羞殺薔薇點碎叢。"]'),
('yuding-55','謝孫郎中寄示','齊己','唐','御定全唐诗','yuding','','[]','一念禪餘味國風，早因持論偶名公。久傷琴喪人亡後，',40,'御定全唐詩/json/844.json','["一念禪餘味國風，早因持論偶名公。久傷琴喪人亡後，", "時來日往緣真趣，不覺秋江度塞鴻。"]'),
('yuding-56','愛吟','齊己','唐','御定全唐诗','yuding','','[]','正堪凝思掩禪扃，又被詩魔惱竺卿。偶憑窗扉從落照，',40,'御定全唐詩/json/844.json','["正堪凝思掩禪扃，又被詩魔惱竺卿。偶憑窗扉從落照，", "傳寫會逢精鑒者，也應知是詠閒情。"]'),
('yuding-57','寄懷東林寺匡白監寺','齊己','唐','御定全唐诗','yuding','','[]','南嶽別來無約後，東林歸住有前緣。閑搜好句題紅葉，',40,'御定全唐詩/json/844.json','["南嶽別來無約後，東林歸住有前緣。閑搜好句題紅葉，", "修心若似伊耶舍，傳記須添十九賢。"]'),
('yuding-58','謝人惠十色花箋並棋子','齊己','唐','御定全唐诗','yuding','','[]','陵州棋子浣花箋，深愧攜來自錦川。海蚌琢成星落落，',40,'御定全唐詩/json/844.json','["陵州棋子浣花箋，深愧攜來自錦川。海蚌琢成星落落，", "捧受不堪思出處，七千餘裏劍門前。"]'),
('yuding-59','夏日寓居寄友人','齊己','唐','御定全唐诗','yuding','','[]','北遊兵阻複南還，因寄荊州病掩關。日月坐銷江上寺，',40,'御定全唐詩/json/844.json','["北遊兵阻複南還，因寄荊州病掩關。日月坐銷江上寺，", "多謝扶風大君子，相思時到寂寥間。"]'),
('yuding-60','中秋十四日夜對月上南平主人','齊己','唐','御定全唐诗','yuding','','[]','今宵前夕皆堪玩，何必圓時始竭才。空說輪中有天子，',40,'御定全唐詩/json/844.json','["今宵前夕皆堪玩，何必圓時始竭才。空說輪中有天子，", "玉兔銀蟾似多意，乍臨棠樹影裴回。"]'),
('yuding-61','《謝人惠十才子圖》','齊己','唐','御定全唐诗','yuding','','[]','丹青妙寫十才人，玉峭冰棱姑射神。醉舞離披真鸑鷟，',40,'御定全唐詩/json/844.json','["丹青妙寫十才人，玉峭冰棱姑射神。醉舞離披真鸑鷟，", "猶得知音與圖畫，草堂閑掛似相親。"]'),
('yuding-62','荊門病中寄懷鄉人歐陽侍郎彬','齊己','唐','御定全唐诗','yuding','','[]','誰會荊州一老夫，夢勞神役憶匡廬。碧雲雁影紛紛去，',40,'御定全唐詩/json/844.json','["誰會荊州一老夫，夢勞神役憶匡廬。碧雲雁影紛紛去，", "可憐饌玉燒蘭者，肯慰寒偎雪夜爐。"]'),
('yuding-63','送譚三藏入京','齊己','唐','御定全唐诗','yuding','','[]','阿闍梨與佛身同，灌頂難施利濟功。持咒力須資運祚，',40,'御定全唐詩/json/844.json','["阿闍梨與佛身同，灌頂難施利濟功。持咒力須資運祚，", "好進梵文沾帝澤，卻歸天策繼真風。"]'),
('yuding-64','寄酬秦府高推官輦','齊己','唐','御定全唐诗','yuding','','[]','天臺衡岳舊曾尋，閑憶留題白石林。歲月已殘衰颯鬢，',40,'御定全唐詩/json/844.json','["天臺衡岳舊曾尋，閑憶留題白石林。歲月已殘衰颯鬢，", "爭得相逢一攜手，拂衣同去聽玄音。"]'),
('yuding-65','敘懷寄高推官','齊己','唐','御定全唐诗','yuding','','[]','搜新編舊與誰評，自向無聲認有聲。已覺愛來多廢道，',40,'御定全唐詩/json/844.json','["搜新編舊與誰評，自向無聲認有聲。已覺愛來多廢道，", "還勝禦溝寒夜水，狂吟沖尹甚傷情。"]'),
('yuding-66','送朱侍禦自洛陽歸閬州甯覲','齊己','唐','御定全唐诗','yuding','','[]','尋常西望故園時，幾處魂隨落照飛。客路舊縈秦甸出，',40,'御定全唐詩/json/844.json','["尋常西望故園時，幾處魂隨落照飛。客路舊縈秦甸出，", "從此倚門休望斷，交親喜換老萊衣。"]'),
('yuding-67','貽惠暹上人','齊己','唐','御定全唐诗','yuding','','[]','經論功餘更業詩，又於難裏縱天機。吳朝客見投文去，',40,'御定全唐詩/json/844.json','["經論功餘更業詩，又於難裏縱天機。吳朝客見投文去，", "金陵高憶恩門在，終掛雲帆重一飛。"]'),
('yuding-68','酬西蜀廣濟大師見寄','齊己','唐','御定全唐诗','yuding','','[]','猶得吾師繼頌聲，百篇相愛寄南荊。卷開錦水霞光爛，',40,'御定全唐詩/json/844.json','["猶得吾師繼頌聲，百篇相愛寄南荊。卷開錦水霞光爛，", "應憐無可同無本，終向風騷作弟兄。"]'),
('yuding-69','江寺春殘寄幕中知己二首','齊己','唐','御定全唐诗','yuding','','[]','誰遣西來負岳雲，自由歸去竟何因。山龕薜荔應殘雪，',80,'御定全唐詩/json/844.json','["誰遣西來負岳雲，自由歸去竟何因。山龕薜荔應殘雪，", "何妨夜醮時相憶，伴醉佯狂笑老身。", "社蓮慚與幕蓮同，嶽寺蕭條儉府雄。冷淡獨開香火裏，", "閑憶遺民此心地，一般無染喻真空。"]'),
('yuding-70','寄玉泉實仁上人','齊己','唐','御定全唐诗','yuding','','[]','往歲曾尋聖跡時，樹邊三繞禮吾師。敢望護法將軍記，',40,'御定全唐詩/json/844.json','["往歲曾尋聖跡時，樹邊三繞禮吾師。敢望護法將軍記，", "今來老劣難行甚，空寂無緣但寄詩。"]'),
('yuding-71','荊渚感懷寄僧達禪弟三首','齊己','唐','御定全唐诗','yuding','','[]','電擊流年七十三，齒衰氣沮竟何堪。誰雲有句傳天下，',120,'御定全唐詩/json/844.json','["電擊流年七十三，齒衰氣沮竟何堪。誰雲有句傳天下，", "鄰峰道者應彈指，蘚剝藤纏舊石龕。", "十五年前會虎溪，白蓮齋後便來西。干戈時變信雖絕，", "春殘相憶荊江岸，一隻杜鵑頭上啼。", "鶴嶺僧來細話君，依前高尚跡難群。自拋南嶽三生石，", "莫將離別為相隔，心似虛空幾處分。"]'),
('yuding-72','寄孫魴秀才','齊己','唐','御定全唐诗','yuding','','[]','郡樓東面寺牆西，顏子生涯竹屋低。書案飛颺風落絮，',40,'御定全唐詩/json/844.json','["郡樓東面寺牆西，顏子生涯竹屋低。書案飛颺風落絮，", "別後相思頻夢到，二年同此賦閑題。"]'),
('yuding-73','送李評事往宜春','齊己','唐','御定全唐诗','yuding','','[]','蘭舟西去是通津，名郡賢侯下禮頻。山遍寺樓看仰岫，',40,'御定全唐詩/json/844.json','["蘭舟西去是通津，名郡賢侯下禮頻。山遍寺樓看仰岫，", "別有官榮身外趣，月江松徑訪禪人。"]'),
('yuding-74','中春感興','齊己','唐','御定全唐诗','yuding','','[]','春風日日雨時時，寒力潛從暖勢衰。一氣不言含有象，',40,'御定全唐詩/json/844.json','["春風日日雨時時，寒力潛從暖勢衰。一氣不言含有象，", "應是正人持造化，盡驅幽細入壚錘。"]'),
('yuding-75','早鶯','齊己','唐','御定全唐诗','yuding','','[]','何處經年閟好音，暖風催出囀喬林。羽毛新刷陶潛菊，',40,'御定全唐詩/json/844.json','["何處經年閟好音，暖風催出囀喬林。羽毛新刷陶潛菊，", "曉來枝上千般語，應共桃花說舊心。"]'),
('yuding-76','酬尚顏上人','齊己','唐','御定全唐诗','yuding','','[]','紫綬蒼髭百歲侵，綠苔芳草繞階深。不妨好鳥喧高臥，',40,'御定全唐詩/json/844.json','["紫綬蒼髭百歲侵，綠苔芳草繞階深。不妨好鳥喧高臥，", "還憐我有冥搜癖，時把新詩過竹尋。"]'),
('yuding-77','寄倪署郎中','齊己','唐','御定全唐诗','yuding','','[]','風雨冥冥春闇移，紅殘綠滿海棠枝。帝鄉久別江鄉住，',40,'御定全唐詩/json/844.json','["風雨冥冥春闇移，紅殘綠滿海棠枝。帝鄉久別江鄉住，", "近聞南國升南省，應笑無機老病師。"]'),
('yuding-78','題鄭郎中谷仰山居','齊己','唐','御定全唐诗','yuding','','[]','簷壁層層映水天，半乘岡壟半民田。王維愛甚難拋畫，',40,'御定全唐詩/json/844.json','["簷壁層層映水天，半乘岡壟半民田。王維愛甚難拋畫，", "秦爭漢奪虛勞力，卻是巢由得穩眠。"]'),
('yuding-0','湘中寓居春日感懷','齊己','唐','御定全唐诗','yuding','','[]','江禽野獸兩堪傷，避射驚彈各自忙。頭角任多無獬豸，',40,'御定全唐詩/json/845.json','["江禽野獸兩堪傷，避射驚彈各自忙。頭角任多無獬豸，", "吟把離騷憶前事，汨羅春浪撼殘陽。"]'),
('yuding-1','瀟湘','齊己','唐','御定全唐诗','yuding','','[]','寒清健碧遠相含，珠媚根源在極南。流古遞今空作島，',40,'御定全唐詩/json/845.json','["寒清健碧遠相含，珠媚根源在極南。流古遞今空作島，", "畢竟輸他老漁叟，綠蓑青竹釣濃藍。"]'),
('yuding-2','寄友生','齊己','唐','御定全唐诗','yuding','','[]','風騷情味近如何，門底寒流屋裏莎。曾摘園蔬留我宿，',40,'御定全唐詩/json/845.json','["風騷情味近如何，門底寒流屋裏莎。曾摘園蔬留我宿，", "涼夜欹眠應得夢，平生心肺似君多。"]'),
('yuding-3','酬答退上人','齊己','唐','御定全唐诗','yuding','','[]','須鬢三分白二分，一生蹤跡出人群。嵩丘夢憶諸峰雪，',40,'御定全唐詩/json/845.json','["須鬢三分白二分，一生蹤跡出人群。嵩丘夢憶諸峰雪，", "荒村殘臘相逢夜，月滿鴻多楚水濆。"]'),
('yuding-4','山中春懷','齊己','唐','御定全唐诗','yuding','','[]','心魂役役不曾歸，萬象相牽向極微。所得或憂逢郢刃，',40,'御定全唐詩/json/845.json','["心魂役役不曾歸，萬象相牽向極微。所得或憂逢郢刃，", "何物不為狼藉境，桃花和雨更霏霏。"]'),
('yuding-5','寄鄭谷郎中','齊己','唐','御定全唐诗','yuding','','[]','上國誰傳消息過，醉眠醒坐對嵯峨。身離道士衣裳少，',40,'御定全唐詩/json/845.json','["上國誰傳消息過，醉眠醒坐對嵯峨。身離道士衣裳少，", "還應笑我降心外，惹得詩魔助佛魔。"]'),
('yuding-6','寄萍鄉唐稟正字','齊己','唐','御定全唐诗','yuding','','[]','新書聲價滿皇都，高臥林中更起無。春興酒香熏肺腑，',40,'御定全唐詩/json/845.json','["新書聲價滿皇都，高臥林中更起無。春興酒香熏肺腑，", "長憶前年送行處，洞門殘日照菖蒲。"]'),
('yuding-7','秋夕書懷','齊己','唐','御定全唐诗','yuding','','[]','涼多夜永擁山袍，片石閑欹不覺勞。蟋蟀繞床無夢寐，',40,'御定全唐詩/json/845.json','["涼多夜永擁山袍，片石閑欹不覺勞。蟋蟀繞床無夢寐，", "破落西窗向殘月，露聲如雨滴蓬蒿。"]'),
('yuding-8','亂後經西山寺','齊己','唐','御定全唐诗','yuding','','[]','松燒寺破是刀兵，穀變陵遷事可驚。雲裏乍逢新住主，',40,'御定全唐詩/json/845.json','["松燒寺破是刀兵，穀變陵遷事可驚。雲裏乍逢新住主，", "欲伴高僧重結社，此身無計舍前程。"]'),
('yuding-9','題梁賢巽公房','齊己','唐','御定全唐诗','yuding','','[]','吳王廟側有高房，簾影南軒日正長。吹苑野風桃葉碧，',40,'御定全唐詩/json/845.json','["吳王廟側有高房，簾影南軒日正長。吹苑野風桃葉碧，", "知有虎溪歸夢切，寺門松折社僧亡。"]'),
('yuding-10','塘上閑作','齊己','唐','御定全唐诗','yuding','','[]','閑行閑坐藉莎煙，此興堪思二古賢。陶靖節居彭澤畔，',40,'御定全唐詩/json/845.json','["閑行閑坐藉莎煙，此興堪思二古賢。陶靖節居彭澤畔，", "形影騰騰夕陽裏，數峰危翠滴漁船。"]'),
('yuding-11','江上望遠山寄鄭谷郎中','齊己','唐','御定全唐诗','yuding','','[]','危碧層層映水天，半垂岡隴下民田。王維愛甚難拋畫，',40,'御定全唐詩/json/845.json','["危碧層層映水天，半垂岡隴下民田。王維愛甚難拋畫，", "秦爭漢奪空勞力，卻是巢由得穩眠。"]'),
('yuding-12','送人自蜀回南游','齊己','唐','御定全唐诗','yuding','','[]','錦水東浮情尚鬱，湘波南泛思何長。蜀魂巴狖悲殘夜，',40,'御定全唐詩/json/845.json','["錦水東浮情尚鬱，湘波南泛思何長。蜀魂巴狖悲殘夜，", "尋幽必有僧相指，宋杜題詩近舊房。"]'),
('yuding-13','寄無願上人','齊己','唐','御定全唐诗','yuding','','[]','六十八去七十歲，與師年鬢不爭多。誰言生死無消處，',40,'御定全唐詩/json/845.json','["六十八去七十歲，與師年鬢不爭多。誰言生死無消處，", "會歸原上焚身後，一陣灰飛也任他。"]'),
('yuding-14','懷瀟湘即事寄友人','齊己','唐','御定全唐诗','yuding','','[]','浸野淫空澹蕩和，十年鄰住聽漁歌。城臨遠棹浮煙泊，',40,'御定全唐詩/json/845.json','["浸野淫空澹蕩和，十年鄰住聽漁歌。城臨遠棹浮煙泊，", "可憐千古懷沙處，還有魚龍弄白波。"]'),
('yuding-15','謝橘洲人寄橘','齊己','唐','御定全唐诗','yuding','','[]','洞庭栽種似瀟湘，綠繞人家帶夕陽。霜裛露蒸千樹熟，',40,'御定全唐詩/json/845.json','["洞庭栽種似瀟湘，綠繞人家帶夕陽。霜裛露蒸千樹熟，", "藏貯待供賓客好，石榴宜稱映舟光。"]'),
('yuding-16','自貽','齊己','唐','御定全唐诗','yuding','','[]','心中身外更何猜，坐石看雲養聖胎。名在好詩誰逐去，',40,'御定全唐詩/json/845.json','["心中身外更何猜，坐石看雲養聖胎。名在好詩誰逐去，", "晴出寺門驚往事，古松千尺半蒼苔。"]'),
('yuding-17','寄益上人','齊己','唐','御定全唐诗','yuding','','[]','長想尋君道路遙，亂山霜後火新燒。近聞移住鄰衡嶽，',40,'御定全唐詩/json/845.json','["長想尋君道路遙，亂山霜後火新燒。近聞移住鄰衡嶽，", "風騷味薄誰相愛，欹枕常多夢鮑昭。"]'),
('yuding-18','行次宜春寄湘西諸友','齊己','唐','御定全唐诗','yuding','','[]','幸無名利路相迷，雙履尋山上柏梯。衣缽祖辭梅嶺外，',40,'御定全唐詩/json/845.json','["幸無名利路相迷，雙履尋山上柏梯。衣缽祖辭梅嶺外，", "我愛遠遊君愛住，此心他約與誰攜。"]'),
('yuding-19','送略禪者歸南嶽','齊己','唐','御定全唐诗','yuding','','[]','林下鐘殘又拂衣，錫聲還獨向南飛。千峰冷截冥鴻處，',40,'御定全唐詩/json/845.json','["林下鐘殘又拂衣，錫聲還獨向南飛。千峰冷截冥鴻處，", "勞生有願應回首，忍著無心與物違。"]'),
('yuding-20','詠懷寄知己','齊己','唐','御定全唐诗','yuding','','[]','已得浮生到老閑，且將新句擬玄關。自知清興來無盡，',40,'御定全唐詩/json/845.json','["已得浮生到老閑，且將新句擬玄關。自知清興來無盡，", "此心終待相逢說，時複登樓看暮山。"]'),
('yuding-21','寄吳拾遺','齊己','唐','御定全唐诗','yuding','','[]','新竹將誰榷重輕，皎然評裏見權衡。非無苦到難搜處，',40,'御定全唐詩/json/845.json','["新竹將誰榷重輕，皎然評裏見權衡。非無苦到難搜處，", "野橋閑背殘陽立，翻憶蘇卿送子卿。"]'),
('yuding-22','春晴感興','齊己','唐','御定全唐诗','yuding','','[]','連旬陰翳曉來晴，水滿圓塘照日明。岸草短長邊過客，',40,'御定全唐詩/json/845.json','["連旬陰翳曉來晴，水滿圓塘照日明。岸草短長邊過客，", "桑柘依依禾黍綠，可憐歸去是張衡。"]'),
('yuding-23','謝道友拄杖','齊己','唐','御定全唐诗','yuding','','[]','翦自南岩瀑布邊，寒光七尺乳珠連。持來未入塵埃路，',40,'御定全唐詩/json/845.json','["翦自南岩瀑布邊，寒光七尺乳珠連。持來未入塵埃路，", "他時攜上嵩峰頂，把倚長松看洛川。"]'),
('yuding-24','東林寄別修睦上人','齊己','唐','御定全唐诗','yuding','','[]','行心乞得見秋風，雙履難留去住蹤。紅葉正多離社客，',40,'御定全唐詩/json/845.json','["行心乞得見秋風，雙履難留去住蹤。紅葉正多離社客，", "此別不能為後約，年華相似逼衰容。"]'),
('yuding-25','夏日原西避暑寄吟友','齊己','唐','御定全唐诗','yuding','','[]','熱煙疏竹古原西，日日乘涼此杖藜。閑處雨聲隨霹靂，',40,'御定全唐詩/json/845.json','["熱煙疏竹古原西，日日乘涼此杖藜。閑處雨聲隨霹靂，", "別有相招好泉石，瑞花瑤草盡堪攜。"]'),
('yuding-26','懷匡阜','齊己','唐','御定全唐诗','yuding','','[]','荊州連歲滯游方，拄杖塵封六尺光。洗面有香思石溜，',40,'御定全唐詩/json/845.json','["荊州連歲滯游方，拄杖塵封六尺光。洗面有香思石溜，", "昨夜分明夢歸去，薜蘿幽徑繞禪房。"]'),
('yuding-27','靜坐','齊己','唐','御定全唐诗','yuding','','[]','繩床欹坐任崩頹，雙眼醒醒閉複開。日月更無閑裏過，',40,'御定全唐詩/json/845.json','["繩床欹坐任崩頹，雙眼醒醒閉複開。日月更無閑裏過，", "何處堪投此蹤跡，水邊晴去上高臺。"]'),
('yuding-28','寄湘中諸友','齊己','唐','御定全唐诗','yuding','','[]','碧雲諸友盡黃眸，石點花飛更說無。嵐翠濕衣松接院，',40,'御定全唐詩/json/845.json','["碧雲諸友盡黃眸，石點花飛更說無。嵐翠濕衣松接院，", "爭似楚王文物國，金鑣紫綬讓前途。"]'),
('yuding-29','答無願上人書','齊己','唐','御定全唐诗','yuding','','[]','鄭生驅蹇峴山回，傳得安公好信來。千里阻修俱老骨，',40,'御定全唐詩/json/845.json','["鄭生驅蹇峴山回，傳得安公好信來。千里阻修俱老骨，", "必有南遊山水興，漢江平穩好浮杯。"]'),
('yuding-30','送胤公歸闕','齊己','唐','御定全唐诗','yuding','','[]','西朝歸去見高情，應戀香燈近聖明。關令莫疑非馬辯，',40,'御定全唐詩/json/845.json','["西朝歸去見高情，應戀香燈近聖明。關令莫疑非馬辯，", "忍惜文章便閑得，看他趨競取時名。"]'),
('yuding-31','感時','齊己','唐','御定全唐诗','yuding','','[]','忽忽枕前蝴蝶夢，悠悠覺後利名塵。無窮今日明朝事，',40,'御定全唐詩/json/845.json','["忽忽枕前蝴蝶夢，悠悠覺後利名塵。無窮今日明朝事，", "可憐顏子能消息，虛室坐忘心最真。"]'),
('yuding-32','湖上逸人','齊己','唐','御定全唐诗','yuding','','[]','澹蕩光中翡翠飛，田田初出柳絲絲。吟沿綠島時逢鶴，',40,'御定全唐詩/json/845.json','["澹蕩光中翡翠飛，田田初出柳絲絲。吟沿綠島時逢鶴，", "秋風水寺僧相近，一徑蘆花到竹籬。"]'),
('yuding-33','懷巴陵','齊己','唐','御定全唐诗','yuding','','[]','垂白堪思大亂前，薄游曾駐洞庭邊。尋僧古寺沿沙岸，',40,'御定全唐詩/json/845.json','["垂白堪思大亂前，薄游曾駐洞庭邊。尋僧古寺沿沙岸，", "此時欲買君山住，懶就商人乞個錢。"]'),
('yuding-34','渚宮謝楊秀才自嵩山相訪','齊己','唐','御定全唐诗','yuding','','[]','嵩峰有客遠相尋，塵滿麻衣袖苦吟。花盡草長方閉戶，',40,'御定全唐詩/json/845.json','["嵩峰有客遠相尋，塵滿麻衣袖苦吟。花盡草長方閉戶，", "惆悵雅聲消歇去，喜君聊此暫披襟。"]'),
('yuding-35','荊門寄沈彬','齊己','唐','御定全唐诗','yuding','','[]','罷趨明聖懶從知，鶴氅褵褷遂性披。道有靜君堪托跡，',40,'御定全唐詩/json/845.json','["罷趨明聖懶從知，鶴氅褵褷遂性披。道有靜君堪托跡，", "珍重兩篇千里達，去年江上雪飛時。"]'),
('yuding-36','《讀陰符經》','齊己','唐','御定全唐诗','yuding','','[]','繞窗風竹骨輕安，閑借陰符仰臥看。絕利一源真有謂，',40,'御定全唐詩/json/845.json','["繞窗風竹骨輕安，閑借陰符仰臥看。絕利一源真有謂，", "三要洞開何用閉，高臺時去憑欄幹。"]'),
('yuding-37','寄吳國知舊','齊己','唐','御定全唐诗','yuding','','[]','淮甸當年憶旅遊，衲衣棕笠外何求。城中古巷尋詩客，',40,'御定全唐詩/json/845.json','["淮甸當年憶旅遊，衲衣棕笠外何求。城中古巷尋詩客，", "可憐王化融融裏，惆悵無僧似惠休。"]'),
('yuding-38','移居','齊己','唐','御定全唐诗','yuding','','[]','上臺言任養疏愚，乞與西城水滿湖。吹榻好風終日有，',40,'御定全唐詩/json/845.json','["上臺言任養疏愚，乞與西城水滿湖。吹榻好風終日有，", "欲問存思搜抉妙，幾聯詩許敵三都。"]'),
('yuding-39','喜彬上人見訪','齊己','唐','御定全唐诗','yuding','','[]','高吟欲繼沃州師，千里相尋問課虛。殘臘江山行盡處，',40,'御定全唐詩/json/845.json','["高吟欲繼沃州師，千里相尋問課虛。殘臘江山行盡處，", "莫惜天機細捶琢，他時終可擬芙蕖。"]'),
('yuding-40','荊州新秋寺居寫懷詩五首上南平王','齊己','唐','御定全唐诗','yuding','','[]','竹如翡翠侵簾影，苔學琉璃布地紋。高臥更無如此樂，',200,'御定全唐詩/json/845.json','["竹如翡翠侵簾影，苔學琉璃布地紋。高臥更無如此樂，", "只恐老身衰朽速，他年不得頌鴻勳。", "井梧黃落暮蟬清，久駐金台但暗驚。事佛未憐諸弟子，", "滿印白檀燈一盞，可能酬謝得聰明。", "金湯裏面境何求，寶殿東邊院最幽。栽種已添新竹影，", "虛負岷峨老僧約，年年雪水下汀洲。", "漢江西岸蜀江東，六稔安禪教化中。托跡幸將王粲別，", "又見去年三五夕，一輪寒魄破煙空。", "石龕閑鎖舊居峰，何事膺門歲月重。五七詩中叨見遇，", "會待英雄啟金口，卻教擔錫入雲松。"]'),
('yuding-41','送李秀才歸湘中','齊己','唐','御定全唐诗','yuding','','[]','詞客攜文訪病夫，因吟送別憶湘湖。寒消浦漵催鴻雁，',40,'御定全唐詩/json/845.json','["詞客攜文訪病夫，因吟送別憶湘湖。寒消浦漵催鴻雁，", "君歸為問峰前寺，舊住僧房鎖在無。"]'),
('yuding-42','寄吳國西供奉','齊己','唐','御定全唐诗','yuding','','[]','別來相憶夢多迷，君住東朝我楚西。瑤闕合陪龍象位，',40,'御定全唐詩/json/845.json','["別來相憶夢多迷，君住東朝我楚西。瑤闕合陪龍象位，", "幾笑遠公慵送客，殷勤只到寺前溪。"]'),
('yuding-43','謝人惠端溪硯','齊己','唐','御定全唐诗','yuding','','[]','端人鑿斷碧溪潯，善價爭教惜萬金。礱琢已曾經敏手，',40,'御定全唐詩/json/845.json','["端人鑿斷碧溪潯，善價爭教惜萬金。礱琢已曾經敏手，", "保重更求裝鈿匣，閑將濡染寄知音。"]'),
('yuding-44','送吳先輩赴京','齊己','唐','御定全唐诗','yuding','','[]','煙霄已遂明經第，江漢重來問苦吟。托興偶憑風月遠，',40,'御定全唐詩/json/845.json','["煙霄已遂明經第，江漢重來問苦吟。托興偶憑風月遠，", "此日與君聊話別，老身難約更相尋。"]'),
('yuding-45','和西蜀可准大師遠寄之什','齊己','唐','御定全唐诗','yuding','','[]','莫知何路去追攀，空想人間出世間。杜口已同居士室，',40,'御定全唐詩/json/845.json','["莫知何路去追攀，空想人間出世間。杜口已同居士室，", "珍重希音遠相寄，亂峰西望疊孱顏。"]'),
('yuding-46','荊門暮冬與節公話別','齊己','唐','御定全唐诗','yuding','','[]','漳河湘岸柳關頭，離別相逢四十秋。我憶黃梅夢南國，',40,'御定全唐詩/json/845.json','["漳河湘岸柳關頭，離別相逢四十秋。我憶黃梅夢南國，", "好及春風承帝澤，莫忘衰朽臥林丘。"]'),
('yuding-47','賀孫支使郎中遷居','齊己','唐','御定全唐诗','yuding','','[]','別認公侯禮上才，築金何啻舊燕台。地連東閣橫頭買，',40,'御定全唐詩/json/845.json','["別認公侯禮上才，築金何啻舊燕台。地連東閣橫頭買，", "應逢明月清霜夜，閑領笙歌宴此來。"]'),
('yuding-48','庭際新移松竹','齊己','唐','御定全唐诗','yuding','','[]','三莖瘦竹兩株松，瑟瑟翛翛韻且同。抱節乍離新澗雪，',40,'御定全唐詩/json/845.json','["三莖瘦竹兩株松，瑟瑟翛翛韻且同。抱節乍離新澗雪，", "更待陽和信催促，碧梢青杪看淩空。"]'),
('yuding-49','荊門寄題禪月大師影堂','齊己','唐','御定全唐诗','yuding','','[]','澤國聞師泥日後，蜀王全禮葬餘灰。白蓮塔向清泉鎖，',40,'御定全唐詩/json/845.json','["澤國聞師泥日後，蜀王全禮葬餘灰。白蓮塔向清泉鎖，", "不堪只履還西去，蔥嶺如今無使回。"]'),
('yuding-50','賀雪','齊己','唐','御定全唐诗','yuding','','[]','上清凝結下乾坤，為瑞為祥表致君。日月影從光外過，',40,'御定全唐詩/json/845.json','["上清凝結下乾坤，為瑞為祥表致君。日月影從光外過，", "堪想畫堂簾卷次，輕隨舞袖正紛紛。"]'),
('yuding-51','荊州寄貫微上人','齊己','唐','御定全唐诗','yuding','','[]','舊齋休憶對松關，各在王侯顧遇間。命服已沾天渥澤，',40,'御定全唐詩/json/845.json','["舊齋休憶對松關，各在王侯顧遇間。命服已沾天渥澤，", "得失兩途俱不是，笑他高臥碧孱顏。"]'),
('yuding-52','送休師歸長沙甯覲','齊己','唐','御定全唐诗','yuding','','[]','高堂親老本師存，多難長懸兩處魂。已說戰塵消漢口，',40,'御定全唐詩/json/845.json','["高堂親老本師存，多難長懸兩處魂。已說戰塵消漢口，", "他日更思衰老否，七年相伴琢詩言。"]'),
('yuding-53','江上夏日','齊己','唐','御定全唐诗','yuding','','[]','無處清陰似剡溪，火雲奇崛倚空齊。千山冷疊湖光外，',40,'御定全唐詩/json/845.json','["無處清陰似剡溪，火雲奇崛倚空齊。千山冷疊湖光外，", "故園舊寺臨湘水，斑竹煙深越鳥啼。"]'),
('yuding-54','渚宮春日因懷有作','齊己','唐','御定全唐诗','yuding','','[]','舊業樹連湘樹遠，家山雲與岳雲平。僧來已說無耕釣，',40,'御定全唐詩/json/845.json','["舊業樹連湘樹遠，家山雲與岳雲平。僧來已說無耕釣，", "沙頭南望堪腸斷，誰把歸舟載我行。"]'),
('yuding-55','松化為石','齊己','唐','御定全唐诗','yuding','','[]','盤根幾聳翠崖前，卻偃淩雲化至堅。乍結精華齊永劫，',40,'御定全唐詩/json/845.json','["盤根幾聳翠崖前，卻偃淩雲化至堅。乍結精華齊永劫，", "肯似荊山鑿餘者，蘚封頑滯臥嵐煙。"]'),
('yuding-56','寄澧陽吳使君','齊己','唐','御定全唐诗','yuding','','[]','南客西來話使君，涔陽風雨變行春。四鄰耕釣趨仁政，',40,'御定全唐詩/json/845.json','["南客西來話使君，涔陽風雨變行春。四鄰耕釣趨仁政，", "紅蘭浦暖攜才子，爛醉連題賦白蘋。"]'),
('yuding-57','湘江送客','齊己','唐','御定全唐诗','yuding','','[]','湘江秋色湛如冰，楚客離懷暮不勝。千里碧雲聞塞雁，',40,'御定全唐詩/json/845.json','["湘江秋色湛如冰，楚客離懷暮不勝。千里碧雲聞塞雁，", "鸚鵡洲邊若回首，為思前事一捫膺。"]'),
('yuding-58','暮游嶽麓寺','齊己','唐','御定全唐诗','yuding','','[]','寺樓高出碧崖棱，城裏誰知在上層。初雪灑來喬木暝，',40,'御定全唐詩/json/845.json','["寺樓高出碧崖棱，城裏誰知在上層。初雪灑來喬木暝，", "回首何邊是空地，四村桑麥遍丘陵。"]'),
('yuding-59','林下留別道友','齊己','唐','御定全唐诗','yuding','','[]','住亦無依去是閑，何心終戀此林間。片雲孤鶴東西路，',40,'御定全唐詩/json/845.json','["住亦無依去是閑，何心終戀此林間。片雲孤鶴東西路，", "秋來洗浣行衣了，還爾鄰僧舊竹關。"]'),
('yuding-60','道林寺居寄岳麓禪師二首','齊己','唐','御定全唐诗','yuding','','[]','門前石路徹中峰，樹影泉聲在半空。尋去未應勞上下，',80,'御定全唐詩/json/845.json','["門前石路徹中峰，樹影泉聲在半空。尋去未應勞上下，", "長憶高窗夏天裏，古松青檜午時風。", "山袍不稱下紅塵，各是閒居島外身。兩處煙霞門寂寂，", "月照經行更誰見，露華松粉點衣巾。"]'),
('yuding-61','亂後江西過孫魴舊居因寄','齊己','唐','御定全唐诗','yuding','','[]','舊遊重到倍悲涼，吟憶同人倚寺牆。何處暮蟬喧逆旅，',40,'御定全唐詩/json/845.json','["舊遊重到倍悲涼，吟憶同人倚寺牆。何處暮蟬喧逆旅，", "欲寄此心空北望，塞鴻天末失歸行。"]'),
('yuding-62','宜春江上寄仰山長老二首','齊己','唐','御定全唐诗','yuding','','[]','水隔孤城城隔山，水邊時望憶師閑。清泉白日中峰上，',80,'御定全唐詩/json/845.json','["水隔孤城城隔山，水邊時望憶師閑。清泉白日中峰上，", "傳心莫學羅浮去，後輩思量待扣關。", "雨晴天半碧光流，影倒殘陽濕郡樓。絕頂有人經劫在，", "欲為吾師拂衣去，白雲紅葉又新秋。"]'),
('yuding-63','螢','齊己','唐','御定全唐诗','yuding','','[]','透窗穿竹住還移，萬類俱閑始見伊。難把寸光藏暗室，',40,'御定全唐詩/json/845.json','["透窗穿竹住還移，萬類俱閑始見伊。難把寸光藏暗室，", "後代儒生懶收拾，夜深飛過讀書帷。"]'),
('yuding-64','湘中送翁員外歸閩','齊己','唐','御定全唐诗','yuding','','[]','船滿琴書與酒杯，清湘影裏片帆開。人歸南國鄉園去，',40,'御定全唐詩/json/845.json','["船滿琴書與酒杯，清湘影裏片帆開。人歸南國鄉園去，", "此身未別江邊寺，猶看星郎奉詔回。"]'),
('yuding-65','寄居道林寺作','齊己','唐','御定全唐诗','yuding','','[]','嵐濕南朝殿塔寒，此中因得謝塵寰。已同庭樹千株老，',40,'御定全唐詩/json/845.json','["嵐濕南朝殿塔寒，此中因得謝塵寰。已同庭樹千株老，", "如今衰颯成多病，黃葉風前晝掩關。"]'),
('yuding-66','沙鷗','齊己','唐','御定全唐诗','yuding','','[]','暖傍漁船睡不驚，可憐孤潔似華亭。晚來灣浦沖平碧，',40,'御定全唐詩/json/845.json','["暖傍漁船睡不驚，可憐孤潔似華亭。晚來灣浦沖平碧，", "何如飛入漢宮裏，留與興亡作典經。"]'),
('yuding-67','和翁員外題馬太傅宅賈相公井','齊己','唐','御定全唐诗','yuding','','[]','飛塵不敢下相干，闇脈傍應潤牡丹。心任短長投玉綆，',40,'御定全唐詩/json/845.json','["飛塵不敢下相干，闇脈傍應潤牡丹。心任短長投玉綆，", "太傅欲旌前古事，星郎屬思久憑欄。"]'),
('yuding-68','看雲','齊己','唐','御定全唐诗','yuding','','[]','何峰觸石濕苔錢，便逐高風離瀑泉。深處臥來真隱逸，',40,'御定全唐詩/json/845.json','["何峰觸石濕苔錢，便逐高風離瀑泉。深處臥來真隱逸，", "長憶舊山青壁裏，繞庵閑伴老僧禪。"]');
